-- Poems batch 281
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2afa3b3b-6b2f-407e-acee-432339529221','古意四首寄張可與孫晉卿  其三','陸文圭','宋','宋诗','song-poetry','','[]','老翁持鏡向市賣，銅光的皪秋水清。',32,'全唐诗/poet.song.248000.json','["老翁持鏡向市賣，銅光的皪秋水清。", "醜婦鑑容驚墮地，想渠嫌殺太分明。"]'),
('e3453a7a-0965-4ca0-9a97-285713d37459','古意四首寄張可與孫晉卿  其四','陸文圭','宋','宋诗','song-poetry','','[]','牧兒狹逕礙樵枝，樵兒格鬬暮不歸。',32,'全唐诗/poet.song.248000.json','["牧兒狹逕礙樵枝，樵兒格鬬暮不歸。", "於菟一聲嘯篁谷，兩兒驚散走如飛。"]'),
('00c72f05-6ffc-4e52-88b7-0c7bd621ac65','夜得二絕寄子華  其一','陸文圭','宋','宋诗','song-poetry','','[]','送客征衫秋八月，懷人病枕夜三更。',32,'全唐诗/poet.song.248000.json','["送客征衫秋八月，懷人病枕夜三更。", "牀頭稚子呼不覺，窗外瀟瀟風雨聲。"]'),
('7b0dca1a-270c-4b98-b64f-68594e4cc750','夜得二絕寄子華  其二','陸文圭','宋','宋诗','song-poetry','','[]','雞鳴風雨思君子，雁過瀟湘憶故人。',32,'全唐诗/poet.song.248000.json','["雞鳴風雨思君子，雁過瀟湘憶故人。", "別去情懷渾欲醉，夢回詩筆已如神。"]'),
('4bd9746b-ccf8-4b48-8b39-46f5a03cc90a','絕句二首寄紹堂求巧石  其一','陸文圭','宋','宋诗','song-poetry','','[]','籬根怪石起層雲，淺带春泥碧蘚紋。',32,'全唐诗/poet.song.248000.json','["籬根怪石起層雲，淺带春泥碧蘚紋。", "乞與詩人時醒酒，也勝豪奪任監軍。"]'),
('19b0c788-2dcf-4508-9392-8b8ca3c9f04e','絕句二首寄紹堂求巧石  其二','陸文圭','宋','宋诗','song-poetry','','[]','幾年石友卧蒼苔，曾受南宮雅拜來。',32,'全唐诗/poet.song.248000.json','["幾年石友卧蒼苔，曾受南宮雅拜來。", "老子暮年行脚倦，只宜窗裏看崔嵬。"]'),
('9fc2f3c8-7952-4094-9c23-4c1d65856208','送唐孟方教授三首  其一','陸文圭','宋','宋诗','song-poetry','','[]','泮水三年惟飲水，不知芹藻味何如。',32,'全唐诗/poet.song.248000.json','["泮水三年惟飲水，不知芹藻味何如。", "群鴞無故爭桑葚，挾彈何人莫問渠。"]'),
('4c8231d2-36c8-41f7-ac89-11f2aea1e4b2','送唐孟方教授三首  其二','陸文圭','宋','宋诗','song-poetry','','[]','禦兒溪北浣征衣，重拂蒼苔舊釣磯。',32,'全唐诗/poet.song.248000.json','["禦兒溪北浣征衣，重拂蒼苔舊釣磯。", "有弟對牀思久別，呼兒置酒話遲歸。"]'),
('0722831b-d35e-4af6-bbfb-494dba58eeae','送唐孟方教授三首  其三','陸文圭','宋','宋诗','song-poetry','','[]','城東老圃舊書生，緊閉柴門懶送迎。',32,'全唐诗/poet.song.248000.json','["城東老圃舊書生，緊閉柴門懶送迎。", "獨袖篇詩與君別，相看白首不勝情。"]'),
('6913cce6-d1b9-4a97-955d-e2a96e545503','送李義夫出遊二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','梅花卸玉春寒淺，柳色描金雪意消。',32,'全唐诗/poet.song.248000.json','["梅花卸玉春寒淺，柳色描金雪意消。", "老子偶然詩興動，又挑行李過溪橋。"]'),
('aeed6fb0-42aa-4fdc-8740-46a92a416dc1','送李義夫出遊二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','三千丈髪從渠脫，九十日春須我遊。',32,'全唐诗/poet.song.248000.json','["三千丈髪從渠脫，九十日春須我遊。", "出却草堂三五里，囊中無得一錢留。"]'),
('9a5b740d-8241-4bed-ad37-94cb4f9b14f5','送吳仲魯回烏江二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','老人白帽子青衿，二水相滋兌澤深。',32,'全唐诗/poet.song.248000.json','["老人白帽子青衿，二水相滋兌澤深。", "易學已隨丁氏去，金蘭何日慰同心。"]'),
('ac8235cf-9a9e-42ae-b188-1ab53977dc67','送吳仲魯回烏江二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','黄田西望歷陽城，風水蕭蕭數日程。',32,'全唐诗/poet.song.248000.json','["黄田西望歷陽城，風水蕭蕭數日程。", "紙上陳言刊落盡，滄浪時聽棹歌聲。"]'),
('e5658e60-01b8-4db9-be92-eb3ba67aaddd','送留君玉高雲卿自江陰遷松江四絕  其一','陸文圭','宋','宋诗','song-poetry','','[]','二君才斡俱優裕，數載相從意未休。',32,'全唐诗/poet.song.248000.json','["二君才斡俱優裕，數載相從意未休。", "短棹西風吹過泖，相思霜月落南州。"]'),
('10b73935-eade-4de7-8756-6a624cbda27f','送留君玉高雲卿自江陰遷松江四絕  其二','陸文圭','宋','宋诗','song-poetry','','[]','江浦買鱸秋正美，山亭聞鶴夜尤清。',32,'全唐诗/poet.song.248000.json','["江浦買鱸秋正美，山亭聞鶴夜尤清。", "送君此去因懷古，海水東來意未平。"]'),
('86b25518-bf94-4bb4-8f94-a332b727b677','送留君玉高雲卿自江陰遷松江四絕  其三','陸文圭','宋','宋诗','song-poetry','','[]','老我卑枝甘伏鷃，羨君喬木又遷鶑。',32,'全唐诗/poet.song.248000.json','["老我卑枝甘伏鷃，羨君喬木又遷鶑。", "清平官府無公事，分我絲蓴一箸羹。"]'),
('58fbb4ac-2597-4892-b2ad-1c8d16bcdab6','送留君玉高雲卿自江陰遷松江四絕  其四','陸文圭','宋','宋诗','song-poetry','','[]','暨州風土今非昔，安得珠犀賈客船。',32,'全唐诗/poet.song.248000.json','["暨州風土今非昔，安得珠犀賈客船。", "莫笑歸裝無一物，江頭魚蟹亦論錢。"]'),
('58267f11-94af-422b-b380-1731762412be','鑒止堂','陸文圭','宋','宋诗','song-poetry','','[]','流水涓涓止水停，要令漱玉結層冰。',32,'全唐诗/poet.song.248000.json','["流水涓涓止水停，要令漱玉結層冰。", "深溪不泛桃花出，誰識仙源在武陵。"]'),
('31dd40a6-b8bf-482d-a7c5-eddf73c710b8','西苑','陸文圭','宋','宋诗','song-poetry','','[]','雪花剪白忘安蒂，霜葉雕紅不戀枝。',32,'全唐诗/poet.song.248000.json','["雪花剪白忘安蒂，霜葉雕紅不戀枝。", "爭似隋家宮樹上，四時錦綵不曾離。"]'),
('c7665753-401c-430e-86ed-a8c6c20436c2','丘莊多稼樓二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','樓上西風野望時，冥冥禾黍沒高低。',32,'全唐诗/poet.song.248000.json','["樓上西風野望時，冥冥禾黍沒高低。", "勸農使者來行水，還凭朱欄憶舊題。"]'),
('7d43e582-741a-4f17-ad86-23d2d406b700','丘莊多稼樓二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','萬畝耕耘卒歲勤，可曾一飽慰農人。',32,'全唐诗/poet.song.248000.json','["萬畝耕耘卒歲勤，可曾一飽慰農人。", "催租令急如風火，輸入官倉化腐塵。"]'),
('59ebd879-0ef7-46b4-995c-e73b6e9c388d','喜客泉二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','幽篁夾道少人居，山骨清寒草木疏。',32,'全唐诗/poet.song.248000.json','["幽篁夾道少人居，山骨清寒草木疏。", "泉見客來空自喜，春懷渺渺正愁余。"]'),
('912d66ea-0fdf-4f7f-9a09-02707b0aa833','喜客泉二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','一飲懷金出嶺南，蓮花峰下絕清甘。',32,'全唐诗/poet.song.248000.json','["一飲懷金出嶺南，蓮花峰下絕清甘。", "我來欲與流泉約，獨喜廉人莫喜貪。"]'),
('b8d5b085-9f5e-454e-bbdf-a9024952b8d0','四時佳興題徐景陽園堂五首  其一','陸文圭','宋','宋诗','song-poetry','','[]','溶溶川上花光午，冉冉窗前草色春。',32,'全唐诗/poet.song.248000.json','["溶溶川上花光午，冉冉窗前草色春。", "能識此中真樂處，聖門只有兩三人。"]'),
('66489589-3579-4a95-8d8f-dd50029d0f11','四時佳興題徐景陽園堂五首  其二','陸文圭','宋','宋诗','song-poetry','','[]','門前車馬客方散，堂下樽罍酒半醒。',32,'全唐诗/poet.song.248000.json','["門前車馬客方散，堂下樽罍酒半醒。", "不信鏡中添白髪，君山依舊去年青。"]'),
('bb7380e0-d93f-46b9-9c9b-64793a01cc5e','四時佳興題徐景陽園堂五首  其三','陸文圭','宋','宋诗','song-poetry','','[]','窮秋破屋簷頭雨，殘臘征夫陌上霜。',32,'全唐诗/poet.song.248000.json','["窮秋破屋簷頭雨，殘臘征夫陌上霜。", "公子閒居無一事，可能憂樂兩相忘。"]'),
('5744b6be-c2b8-443e-883d-46506cb4e18e','四時佳興題徐景陽園堂五首  其四','陸文圭','宋','宋诗','song-poetry','','[]','華陽洞口金泉水，流入宮牆作小渠。',32,'全唐诗/poet.song.248000.json','["華陽洞口金泉水，流入宮牆作小渠。", "任轉秦淮出江去，不應久住化龍魚。"]'),
('c7e19bce-3b69-4b78-a659-85f9677e56c1','四時佳興題徐景陽園堂五首  其五','陸文圭','宋','宋诗','song-poetry','','[]','半奩玉鏡照鬚眉，長笑東坡與水嬉。',32,'全唐诗/poet.song.248000.json','["半奩玉鏡照鬚眉，長笑東坡與水嬉。", "直下琤然投小石，一波先動萬波隨。"]'),
('18d5f199-c01f-4f83-bda8-7e28a50ad6d0','題園亭','陸文圭','宋','宋诗','song-poetry','','[]','把酒看花貧亦樂，携琴對竹靜相宜。',32,'全唐诗/poet.song.248000.json','["把酒看花貧亦樂，携琴對竹靜相宜。", "客來若問朝家事，回首東風謝不知。"]'),
('4f0b8ad7-8e37-4c6d-a3cc-ec2efe8e4ed2','同善之仲實無逸共賦雪中香亭','陸文圭','宋','宋诗','song-poetry','','[]','冷雲低壓翠禽巢，碎玉玲瓏不耐敲。',32,'全唐诗/poet.song.248000.json','["冷雲低壓翠禽巢，碎玉玲瓏不耐敲。", "蜂蝶遲來探芳信，暖風已逼杏花稍。"]'),
('fa229be3-7254-423c-9a2c-cb6fee0448c8','鶴皋詩爲振之作','陸文圭','宋','宋诗','song-poetry','','[]','鸛鳴于垤婦長歎，鴻漸于陸夫遠征。',32,'全唐诗/poet.song.248000.json','["鸛鳴于垤婦長歎，鴻漸于陸夫遠征。", "何似山亭聞鶴唳，無人靜坐月三更。"]'),
('da8ef8f7-e299-4eb4-a035-600653ccbfdd','劉澹齋求米船謾賦二絕  其一','陸文圭','宋','宋诗','song-poetry','','[]','文士清高數米顛，蔡公門下詎能賢。',32,'全唐诗/poet.song.248000.json','["文士清高數米顛，蔡公門下詎能賢。", "探囊萬一逢江盜，錯認真州發運船。"]'),
('cb57ed30-7957-425e-97fd-23fc6a8924e7','劉澹齋求米船謾賦二絕  其二','陸文圭','宋','宋诗','song-poetry','','[]','靈寶生平愛虎頭，每傍戰艦繫輕舟。',32,'全唐诗/poet.song.248000.json','["靈寶生平愛虎頭，每傍戰艦繫輕舟。", "晚無書畫真無益，洗手莫嫌寒具油。"]'),
('8c205b4f-0927-43df-9831-015fca2a172d','臨山谷帖不似','陸文圭','宋','宋诗','song-poetry','','[]','曾草華清妙入神，涪翁以後更無人。',32,'全唐诗/poet.song.248000.json','["曾草華清妙入神，涪翁以後更無人。", "捧心終是西施好，里婦何緣輒效顰。"]'),
('455cf4cb-555a-4d28-a156-f05f7107d02a','危金仙示容齋清暉堂詩求跋洪景盧乃危驪塘之座主也因成二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','卷中人物想乾淳，老筆題詩意轉新。',32,'全唐诗/poet.song.248000.json','["卷中人物想乾淳，老筆題詩意轉新。", "却怪洪楊交不合，誠齋亦自是詩人。"]'),
('6366acb6-9352-4e0d-b3b0-e84d76e04f8c','危金仙示容齋清暉堂詩求跋洪景盧乃危驪塘之座主也因成二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','清暉何處有園堂，消得先生句發揚。',32,'全唐诗/poet.song.248000.json','["清暉何處有園堂，消得先生句發揚。", "百世空留遺墨在，後生併不識驪塘。"]'),
('5fe225dd-7c18-4304-ba79-7b7ca6ae7cbb','題敬威卿參政贈許正卿針詩卷末敬公之章許卿之藝諸君發揮盡矣終以二絕貂續尾蛇添足乎  其一','陸文圭','宋','宋诗','song-poetry','','[]','江左知名許叔微，公來示之衡氣機。',32,'全唐诗/poet.song.248000.json','["江左知名許叔微，公來示之衡氣機。", "天下呻吟尚未息，公持肘後將安歸。"]'),
('679febc8-0bb2-4c16-a3b5-861b29d1ea9b','題敬威卿參政贈許正卿針詩卷末敬公之章許卿之藝諸君發揮盡矣終以二絕貂續尾蛇添足乎  其二','陸文圭','宋','宋诗','song-poetry','','[]','正人一脈係安危，溫公身事亦付醫。',32,'全唐诗/poet.song.248000.json','["正人一脈係安危，溫公身事亦付醫。", "此身强健無著處，不如枕卧看兒嬉。"]'),
('d327d349-ab63-4e14-b248-704f449a091f','題李兄課卷','陸文圭','宋','宋诗','song-poetry','','[]','集中有句儘堪傳，一夢科名十二年。',32,'全唐诗/poet.song.248000.json','["集中有句儘堪傳，一夢科名十二年。", "音好空聞永嘉末，命乖不遇竟陵前。"]'),
('3d547d81-6dc1-4a16-8c6e-692816838fbd','題趙子德修屋疏二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','公子王孫逞富豪，連雲甲第競相高。',32,'全唐诗/poet.song.248000.json','["公子王孫逞富豪，連雲甲第競相高。", "誰是錦里秋風客，不辦三重屋上茅。"]'),
('be6f7674-c87c-4595-af67-80e0659bc456','題趙子德修屋疏二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','神有青囊號救貧，如何無術自謀身。',32,'全唐诗/poet.song.248000.json','["神有青囊號救貧，如何無術自謀身。", "道南大宅今安在，欲向龍舒覓主人。"]'),
('839de5e9-7de3-4c0b-8825-d6debcf9f5de','戲題聽琴手卷','陸文圭','宋','宋诗','song-poetry','','[]','流水高山不用彈，巴人下里衆皆歡。',32,'全唐诗/poet.song.248000.json','["流水高山不用彈，巴人下里衆皆歡。", "只今何處求鍾子，多向文闈作考官。"]'),
('d0f2ac2c-0759-4a80-b470-1d8b5f40c2f8','題昭君畫卷五絕  其一','陸文圭','宋','宋诗','song-poetry','','[]','當時隨例與黄金，不遣君王有悔心。',32,'全唐诗/poet.song.248000.json','["當時隨例與黄金，不遣君王有悔心。", "近使來傳延壽死，回思終是漢恩深。"]'),
('c31cb107-4774-4dc1-9e3b-d4f60f06726c','題昭君畫卷五絕  其二','陸文圭','宋','宋诗','song-poetry','','[]','妍醜何須問畫工，美人終日侍宮中。',32,'全唐诗/poet.song.248000.json','["妍醜何須問畫工，美人終日侍宮中。", "奉春初計真堪恨，欲望單于敬外翁。"]'),
