('a4323860-c60c-4e6f-8f75-889afab26019','海棠','繆鑑','宋','宋诗','song-poetry','','[]','滴滴妖嬈睡未醒，碎花猶带馬嵬塵。',32,'全唐诗/poet.song.248000.json','["滴滴妖嬈睡未醒，碎花猶带馬嵬塵。", "少年正抱憂時恨，更有因花比太真。"]'),
('5f590ed0-8806-4796-9fed-36634be3547d','寄劉澹齋','繆鑑','宋','宋诗','song-poetry','','[]','聞說商山有隠仙，劉郎引入洞中天。',32,'全唐诗/poet.song.248000.json','["聞說商山有隠仙，劉郎引入洞中天。", "誰知白石蒼苔客，獨守孤燈夜不眠。"]'),
('3bd8f3e3-d27b-49a8-ae44-d0b1fd1ad662','詠鶴','繆鑑','宋','宋诗','song-poetry','','[]','青山修竹矮籬笆，彷彿林泉隠者家。',32,'全唐诗/poet.song.248000.json','["青山修竹矮籬笆，彷彿林泉隠者家。", "酷愛綠窗風日美，鶴梳輕毳亂楊花。"]'),
('aae46b59-0a81-4586-a868-e78cdd1dcf6b','詠菊','繆鑑','宋','宋诗','song-poetry','','[]','誰去東籬號菊莊，饑來三嗅飽詩腸。',32,'全唐诗/poet.song.248000.json','["誰去東籬號菊莊，饑來三嗅飽詩腸。", "何如陶令歸南圃，天賜西風萬斛香。"]'),
('fb5c7a53-a63a-44c4-a00a-e5117201b406','詠圍棋','繆鑑','宋','宋诗','song-poetry','','[]','午香簾影靜浮華，對面機心萬里賒。',64,'全唐诗/poet.song.248000.json','["午香簾影靜浮華，對面機心萬里賒。", "夾騎倒戈窺虎穴，亂烏橫陣占鷗沙。", "當人不讓爭先著，袖手須饒老作家。", "欲訪爛柯山下客，洞深春染碧桃花。"]'),
('05391cbf-ebd4-4ae9-9372-6a76d047725e','解嘲','繆鑑','宋','宋诗','song-poetry','','[]','莫笑詩翁懶出門，詩翁樂事在山村。',64,'全唐诗/poet.song.248000.json','["莫笑詩翁懶出門，詩翁樂事在山村。", "鶑啼楊柳金歌舞，蝶宿梨花雪夢魂。", "罨畫丹青分曙色，壓醅醽醁漲溪痕。", "燕簾風裏茶煙外，自選唐詩教子孫。"]'),
('0e3e0949-3d91-4817-a2e2-517428091a64','端居','繆鑑','宋','宋诗','song-poetry','','[]','修竹垂楊映戶栽，清風長送午陰來。',64,'全唐诗/poet.song.248000.json','["修竹垂楊映戶栽，清風長送午陰來。", "門因好客時時掃，窗爲看山面面開。", "此樂恐於兒輩覺，長貧能免俗情猜。", "儒衣不似牛衣好，叮囑糠妻放窄裁。"]'),
('97ac993e-6628-4a12-bde4-1d2778de7617','白髪','繆鑑','宋','宋诗','song-poetry','','[]','老矣無心競寸陰，不知公道爲何人。',64,'全唐诗/poet.song.248000.json','["老矣無心競寸陰，不知公道爲何人。", "晴梳櫛齒千絲雪，靜掩梨花一鏡春。", "鑷處癡兒愁是種，染來因藥怪無嗔。", "兒曹共日誇頭角，笑說非熊有渭濱。"]'),
('5719b9f8-afcd-4d17-8af2-ac687150d3c4','題悟空寺','繆鑑','宋','宋诗','song-poetry','','[]','不到招提二十霜，眼明猶識魯靈光。',64,'全唐诗/poet.song.248000.json','["不到招提二十霜，眼明猶識魯靈光。", "雲餐已供伊蒲塞，風鐸猶傳替戾岡。", "新寺金湯龍化遠，舊家王謝燕飛忙。", "行人指點簪犀地，十里春風土尚香。"]'),
('7cd831ee-dd5a-4c18-8575-587db22f2128','得女','繆鑑','宋','宋诗','song-poetry','','[]','得駒未必真權奇，中雀未必有淑姿。',64,'全唐诗/poet.song.248000.json','["得駒未必真權奇，中雀未必有淑姿。", "男兒未必勳鼎彝，女子未必光門楣。", "吾今素髪紛如絲，得此一笑春生眉。", "蒼蒼天道不我遺，猶勝伯道全無兒。"]'),
('5f760548-8fcf-44ed-91cc-6877936cde77','春題','繆鑑','宋','宋诗','song-poetry','','[]','江雲漠漠水悠悠，望斷春風燕子樓。',64,'全唐诗/poet.song.248000.json','["江雲漠漠水悠悠，望斷春風燕子樓。", "書寄碧雲千里雁，鏡分明月半奩秋。", "來時楊柳陰連陌，歸路蘋花雪滿洲。", "遥想瑣窗挑錦字，淚珠如粉冷銀鉤。"]'),
('473efa9c-5a41-4620-8516-43eb6168f4da','梅花','繆鑑','宋','宋诗','song-poetry','','[]','鐵石槎牙玉粒姿，詩中圖畫畫中詩。',64,'全唐诗/poet.song.248000.json','["鐵石槎牙玉粒姿，詩中圖畫畫中詩。", "半稜山色初晴後，一截谿煙欲暝時。", "流水带雲棲瘦影，小窗和月上橫枝。", "老來自覺吟情拙，莫遣孤山怨鶴知。"]'),
('e36af9f0-468e-4e93-ae94-ca8411f9f99a','月屋','繆鑑','宋','宋诗','song-poetry','','[]','一室虛明萬境寬，水晶簾映玉闌干。',64,'全唐诗/poet.song.248000.json','["一室虛明萬境寬，水晶簾映玉闌干。", "不從此處逢仙子，爭信人間有廣寒。", "梅影夜窺霜鏡滿，桂香秋吸酒壺乾。", "客來試問推敲字，笑指湖光上下看。"]'),
('bdaa113f-604d-43f5-992e-9b1b582491b6','咏妓','繆鑑','宋','宋诗','song-poetry','','[]','誰去江雲問牧之，玉樓人醉半離披。',64,'全唐诗/poet.song.248000.json','["誰去江雲問牧之，玉樓人醉半離披。", "燭摇窗影三更月，人醉花陰十二時。", "訪杜秋娘惟我老，夢揚州鶴有誰知。", "臨風笑却垂楊下，重解連環寄所思。"]'),
('b61688ea-7552-497d-97cd-9a929cbfb460','春雪','繆鑑','宋','宋诗','song-poetry','','[]','撩亂春風作陣飛，曉來餘片尚離披。',64,'全唐诗/poet.song.248000.json','["撩亂春風作陣飛，曉來餘片尚離披。", "細看山色空明處，應似乾坤混沌時。", "一轉陽和回土脈，十分清氣入詩脾。", "芒鞋蹋碎瓊瑶窟，問著梅花總不知。"]'),
('368e60f1-f4f0-483a-8c2c-5604a15492a1','贈僧','繆鑑','宋','宋诗','song-poetry','','[]','兩脚行來鐵石堅，相逢去住總隨緣。',64,'全唐诗/poet.song.248000.json','["兩脚行來鐵石堅，相逢去住總隨緣。", "談空舌本原無語，打破機關不用拳。", "山檻看雲齋鼓後，竹窗聽雨夜燈前。", "客來瀹茗煨寒柮，味勝廬峰第一泉。"]'),
('019e69a4-69e8-4c4f-9f64-8f348cd35a62','句  其一','繆鑑','宋','宋诗','song-poetry','','[]','雁沈秋驛雨，鷄送曉窗燈。',12,'全唐诗/poet.song.248000.json','["雁沈秋驛雨，鷄送曉窗燈。"]'),
('3e8a7d78-e3f2-404f-89de-559c25fa8d3d','句  其二','繆鑑','宋','宋诗','song-poetry','','[]','門當車馬道，簾隔利名塵。',12,'全唐诗/poet.song.248000.json','["門當車馬道，簾隔利名塵。"]'),
('bbef3583-2740-4727-9c09-09e83402a192','句  其三','繆鑑','宋','宋诗','song-poetry','','[]','病猶有药扶持老，貧爲無心俯仰人。',16,'全唐诗/poet.song.248000.json','["病猶有药扶持老，貧爲無心俯仰人。"]'),
('245882c1-d720-41f3-8f9f-cf188dd67fd7','句  其四','繆鑑','宋','宋诗','song-poetry','','[]','門因好客時時掃，窗爲看山面面開。',16,'全唐诗/poet.song.248000.json','["門因好客時時掃，窗爲看山面面開。"]'),
('6be82fee-294c-4d02-93bb-6c624050169f','句  其五','繆鑑','宋','宋诗','song-poetry','','[]','既能事漢識真主，何必下齊求假王。',16,'全唐诗/poet.song.248000.json','["既能事漢識真主，何必下齊求假王。"]'),
('336612e1-26cf-416d-a289-44c9e74c1053','川上女','張玉孃','宋','宋诗','song-poetry','','[]','川上女，行踽踽。',68,'全唐诗/poet.song.248000.json','["川上女，行踽踽。", "翠鬢濕輕雲，冰肌清溽暑。", "霞裾瓊佩動春風，蘭操蘋心常似縷。", "却恨征途輕薄兒，笑隔山花問妾期。", "妾情清澈川中水，朝暮風波無改時。"]'),
('f05575f2-2abc-475f-bec7-8a5e2dd38a96','古別離','張玉孃','宋','宋诗','song-poetry','','[]','把酒上河梁，送君灞陵道。',84,'全唐诗/poet.song.248000.json','["把酒上河梁，送君灞陵道。", "去去不復返，古道生秋草。", "迢遞山河長，縹緲音書杳。", "愁結雨冥冥，情深天浩浩。", "人云松菊荒，不言桃李好。", "澹泊羅衣裳，容顔萎枯槁。", "不見鏡中人，愁向鏡中老。"]'),
('f417975d-d268-4836-8de6-8cf9f3d67b30','結襪子','張玉孃','宋','宋诗','song-poetry','','[]','閨中女兒蘭蕙性，寒冰清澈秋霜瑩。',32,'全唐诗/poet.song.248000.json','["閨中女兒蘭蕙性，寒冰清澈秋霜瑩。", "感君恩重不勝情，容光自抱悲明鏡。"]'),
('7ecfadfc-d18b-44e1-a08d-e46756dec5cf','拜新月二章  其一','張玉孃','宋','宋诗','song-poetry','','[]','拜新月，拜月願月圓。',22,'全唐诗/poet.song.248000.json','["拜新月，拜月願月圓。", "新月有圓時，人別何時見。"]'),
('b97367f6-d1c6-4e05-95d9-de7c7dbc783c','拜新月二章  其二','張玉孃','宋','宋诗','song-poetry','','[]','拜新月，新月下庭除。',22,'全唐诗/poet.song.248000.json','["拜新月，新月下庭除。", "欲祝心間事，未語先慘悽。"]'),
('26ef9d1f-bba0-43d6-a406-bfaee44189a2','白雪曲','張玉孃','宋','宋诗','song-poetry','','[]','簾白明窗雪，風急寒威冽。',48,'全唐诗/poet.song.248000.json','["簾白明窗雪，風急寒威冽。", "欲起理冰絃，如凝指尖折。", "霜幃眠不穩，愁重腸千結。", "閒看臘梅梢，埋沒清塵絕。"]'),
('29217fcf-be35-48b9-a2d9-9a46709ee5b9','搗衣曲','張玉孃','宋','宋诗','song-poetry','','[]','入夜砧聲滿四鄰，一天霜月秋雲輕。',32,'全唐诗/poet.song.248000.json','["入夜砧聲滿四鄰，一天霜月秋雲輕。", "自憐歲歲衣裁就，欲寄無因到遠人。"]'),
('956d3871-cd20-47e1-b3b0-c9acddde7d3c','明月引','張玉孃','宋','宋诗','song-poetry','','[]','明月度天飛，團團散清暉。',52,'全唐诗/poet.song.248000.json','["明月度天飛，團團散清暉。", "中有后羿妻，竊藥化蟾蜍。", "碧海心如夢，澹澹生寒虛。", "關山一夜愁多少，照影令人添慘悽。"]'),
('29ed283b-626f-440a-b32b-4b0ef5a13a21','雙燕離','張玉孃','宋','宋诗','song-poetry','','[]','白楊花發春正美，黄鵠簾垂低。',80,'全唐诗/poet.song.248000.json','["白楊花發春正美，黄鵠簾垂低。", "燕子雙去復雙來，將雛成舊壘。", "秋風忽夜起，相呼度江水。", "風高江浪危，拆散東西飛。", "紅徑紫陌芳情斷，朱戶瓊窗旅夢違。", "憔悴衛佳人，年年愁獨歸。"]'),
('e94e2252-776e-4f6b-8729-58d8e6631443','採蓮曲','張玉孃','宋','宋诗','song-poetry','','[]','女兒採蓮拽畫船，船拽水動波摇天。',32,'全唐诗/poet.song.248000.json','["女兒採蓮拽畫船，船拽水動波摇天。", "春風笑隔荷花面，面對荷花更可憐。"]'),
('0ef095a5-c71f-44f6-afb7-182a43803c94','班婕妤  其一','張玉孃','宋','宋诗','song-poetry','','[]','一自憐捐棄，香跡玉階疏。',24,'全唐诗/poet.song.248000.json','["一自憐捐棄，香跡玉階疏。", "聞道西宮路，近亦絕鸞輿。"]'),
('f45e76d0-c063-414f-8f28-72347c910956','班婕妤  其二','張玉孃','宋','宋诗','song-poetry','','[]','翠箔玉蟾窺，天街仙籟絕。',24,'全唐诗/poet.song.248000.json','["翠箔玉蟾窺，天街仙籟絕。", "抱恨坐夜長，銀釭半明滅。"]'),
('d836030a-358b-4924-b836-99d8bd8a54a9','塞下曲','張玉孃','宋','宋诗','song-poetry','','[]','寒入關榆霜滿天，鐵衣馬上枕戈眠。',48,'全唐诗/poet.song.248000.json','["寒入關榆霜滿天，鐵衣馬上枕戈眠。", "愁生畫角鄉心破，月度深閨舊夢牽。", "愁絕驚聞邊騎報，匈奴已牧隴西還。"]'),
('b9163cd2-c740-457f-a592-300036fac6a1','塞上曲','張玉孃','宋','宋诗','song-poetry','','[]','爲國勞戎事，迢迢出玉關。',84,'全唐诗/poet.song.248000.json','["爲國勞戎事，迢迢出玉關。", "虎帳春風遠，鎧甲清霜寒。", "落雁行銀箭，開弓響鐵環。", "三更豪鼓角，頻催鄉夢殘。", "勒兵嚴鐵騎，破虜燕然山。", "宵傳前路捷，游馬斬樓蘭。", "歸書語孀婦，一宵私昵難。"]'),
('ffc6994f-cb9c-4574-bcb6-1a30d57ed7cc','從軍行','張玉孃','宋','宋诗','song-poetry','','["\u8d5e\u9882", "\u5c06\u58eb", "\u751f\u6d3b", "\u8fb9\u585e"]','二十遴驍勇，從軍事北荒。',48,'全唐诗/poet.song.248000.json','["二十遴驍勇，從軍事北荒。", "流星飛玉彈，寶劍落秋霜。", "畫角吹楊柳，金山險馬當。", "長驅空朔漠，馳捷報明王。"]'),
('44350d06-9822-4fd3-bb82-2e40c957fed6','幽州胡馬客','張玉孃','宋','宋诗','song-poetry','','[]','幽州胡馬客，蓮劍寒鋒清。',84,'全唐诗/poet.song.248000.json','["幽州胡馬客，蓮劍寒鋒清。", "笑看華海靜，怒振河山傾。", "金鞍試風雪，千里一宵征。", "韔底揪羽箭，彎弓新月明。", "仰天墜雕鵠，回首貫長鯨。", "慷慨激忠烈，許國一身輕。", "願繫匈奴頸，狼烟夜不驚。"]'),
('009cf8b8-9c5d-48bf-a6a9-7ab40f294092','山之高三章  其一','張玉孃','宋','宋诗','song-poetry','','[]','山之高，月出小。',34,'全唐诗/poet.song.248000.json','["山之高，月出小。", "月之小，何皎皎。", "我有所思在遠道，一日不見兮我心悄悄。"]'),
('aaad4457-3498-456a-86ae-d265981c07bd','山之高三章  其二','張玉孃','宋','宋诗','song-poetry','','[]','采苦采苦，于山之南。',20,'全唐诗/poet.song.248000.json','["采苦采苦，于山之南。", "忡忡憂心，其何以堪。"]'),
('5a8d4f6f-1ed2-4e4d-87ff-94342837f1c2','山之高三章  其三','張玉孃','宋','宋诗','song-poetry','','[]','汝心金石堅，我操冰雪潔。',40,'全唐诗/poet.song.248000.json','["汝心金石堅，我操冰雪潔。", "擬結百歲盟，忽成一朝別。", "朝雲暮雨心去來，千里相思共明月。"]'),
('4409e383-5d2f-4611-ad07-755b0da9db46','王將軍墓','張玉孃','宋','宋诗','song-poetry','','[]','嶺上松如旗，抉疏鐵石姿。',48,'全唐诗/poet.song.248000.json','["嶺上松如旗，抉疏鐵石姿。", "下有烈士魂，上有青菟絲。", "烈士節不改，青松色愈滋。", "欲識烈士心，請看青松枝。"]'),
('256483ed-6c7c-46a0-97ce-c7b67c3c0bec','鳴雁二章  其一','張玉孃','宋','宋诗','song-poetry','','[]','鳴雁征征，白露既零。',20,'全唐诗/poet.song.248000.json','["鳴雁征征，白露既零。", "猗嗟清兮，懷彼春冰。"]'),
('fe9a880d-4c29-45a2-b341-7755b8147535','鳴雁二章  其二','張玉孃','宋','宋诗','song-poetry','','[]','鳴雁嗥嗥，凉風飄颻。',20,'全唐诗/poet.song.248000.json','["鳴雁嗥嗥，凉風飄颻。", "猗嗟孌兮，懷彼春宵。"]'),
('22903d60-a08b-48c1-85aa-e43004468b2c','瑶琴怨','張玉孃','宋','宋诗','song-poetry','','[]','凉蟾吹浪羅衫濕，貪看無眠久延立。',128,'全唐诗/poet.song.248000.json','["凉蟾吹浪羅衫濕，貪看無眠久延立。", "欲將高調寄瑶琴，一聲絃斷霜風急。", "鳳膠難煮令人傷，茫然背向西窗泣。", "寒機欲把相思織，織又不成心愈戚。", "掩淚含羞下階看，仰見牛女隔河漢。", "天河雖隔牛女情，一年一度能相見。", "獨此絃斷無續期，梧桐葉上不勝悲。", "抱琴曉對菱花鏡，重恨風從手上吹。"]'),
('6e5e3000-ffa1-49bd-b810-85efbebc04e3','秋江辭','張玉孃','宋','宋诗','song-poetry','','[]','烟迷浦口人跡稀，老松瘦竹橫斜暉。',64,'全唐诗/poet.song.248000.json','["烟迷浦口人跡稀，老松瘦竹橫斜暉。", "舟人鱠切蓴羹美，竹葉香清蟹正肥。", "醉眠篷底呼不醒，一任春風吹鬢影。", "起來霜月白滿天，淅瀝蒹葭凉夜靜。"]'),
('8b1b0b1b-ceec-4ebc-88a8-4836a625a81e','春曉謠','張玉孃','宋','宋诗','song-poetry','','[]','到枕一聲鶑，曉窗生虛白。',84,'全唐诗/poet.song.248000.json','["到枕一聲鶑，曉窗生虛白。", "烟柳影參差，薔薇紅半拆。", "乘風雙蛺蝶，欲入珠簾隔。", "獨向花下吟，翠篠剌羅襟。", "徘徊吟不就，婢子整瑶琴。", "撫弦不堪彈，調別無好音。", "一弦腸一斷，斷盡幾回心。"]'),
('976c3b66-b667-4ad1-8dcd-e1b087faa0d3','牧童辭','張玉孃','宋','宋诗','song-poetry','','[]','朝驅牛，出竹扉，平野春深草正肥。',48,'全唐诗/poet.song.248000.json','["朝驅牛，出竹扉，平野春深草正肥。", "暮驅牛，下短陂，谷口烟斜山雨微。", "飽采黄精歸不飯，倒騎黄犢笛橫吹。"]'),
('1d795118-f96e-4fbf-ab53-0f7d9c62bf65','幽居四景 山色','張玉孃','宋','宋诗','song-poetry','','[]','遠山翠不減，滿庭摇空青。',24,'全唐诗/poet.song.248000.json','["遠山翠不減，滿庭摇空青。", "坐對太古色，終日有餘情。"]'),
