('84fd2f51-859c-4f7e-b3d0-fbedcfbb9045','題畫 蘇子','張玉孃','宋','宋诗','song-poetry','','[]','天白山高月滿川，蘆花風漾木蘭船。',32,'全唐诗/poet.song.248000.json','["天白山高月滿川，蘆花風漾木蘭船。", "倚舷一曲嗚嗚調，驚起潜蛟夜不眠。"]'),
('77747731-7a9f-4899-9e04-58f9a461ae35','題畫 子猷','張玉孃','宋','宋诗','song-poetry','','[]','日暮天寒白雪頻，扁舟夜半未歸人。',32,'全唐诗/poet.song.248000.json','["日暮天寒白雪頻，扁舟夜半未歸人。", "想因不盡山陰興，留向丹青入夢清。"]'),
('4c0f7d6f-d141-4bfe-8a99-0fe63334325e','題畫 漁舟','張玉孃','宋','宋诗','song-poetry','','[]','秋水秋空一樣明，柳陰不繫小舟輕。',32,'全唐诗/poet.song.248000.json','["秋水秋空一樣明，柳陰不繫小舟輕。", "玉堂金馬非吾夢，月色蘆花同醉醒。"]'),
('fdeb3fb2-ea10-4e11-85a6-c196aedef5b7','題畫 海棠宿鳥','張玉孃','宋','宋诗','song-poetry','','[]','幽禽底事倦春芳，相與棲遲宿野棠。',32,'全唐诗/poet.song.248000.json','["幽禽底事倦春芳，相與棲遲宿野棠。", "風攪一枝香夢醒，四天烟景夜茫茫。"]'),
('13e927f5-3896-40a4-ab7a-2866e64677d0','詠史 謝東山','張玉孃','宋','宋诗','song-poetry','','[]','風捲胡沙動地塵，薔薇深洞藹餘春。',32,'全唐诗/poet.song.248000.json','["風捲胡沙動地塵，薔薇深洞藹餘春。", "棋終偶折登山屐，方信風流社稷臣。"]'),
('07276525-d6c6-4386-9d89-34403cbec17b','詠史 綠珠','張玉孃','宋','宋诗','song-poetry','','[]','珠易佳人勝阿嬌，香塵微步獨憐腰。',32,'全唐诗/poet.song.248000.json','["珠易佳人勝阿嬌，香塵微步獨憐腰。", "危樓花落繁華盡，總付春風舞柳條。"]'),
('1e6035ec-bbe9-4fa2-a33a-38e9a1c4f34a','詠史 蒨桃','張玉孃','宋','宋诗','song-poetry','','[]','愛賞佳人白雪辭，雲綾一束費春機。',32,'全唐诗/poet.song.248000.json','["愛賞佳人白雪辭，雲綾一束費春機。", "翻然席上呈詩句，羞殺歌喉與舞衣。"]'),
('7edd79bd-a14d-4edf-a046-11c9ab2c7cd8','詠史 黨奴','張玉孃','宋','宋诗','song-poetry','','[]','江雪寒連酒思豪，歌傳錦帳醉烹羔。',32,'全唐诗/poet.song.248000.json','["江雪寒連酒思豪，歌傳錦帳醉烹羔。", "爭如取水陶承旨，茗椀清新興味高。"]'),
('d6536ec8-ef05-41a7-8ea8-79985f7d81a7','詠史 伏生','張玉孃','宋','宋诗','song-poetry','','[]','楚炬秦坑六籍埃，芳心爭忍不同灰。',32,'全唐诗/poet.song.248000.json','["楚炬秦坑六籍埃，芳心爭忍不同灰。", "若非斯道終難墜，雪鬢應消異世才。"]'),
('9d2b376a-a6ab-4d0e-9ac7-ad6e7788b4f1','詠史 馬融','張玉孃','宋','宋诗','song-poetry','','[]','堂下青衿日就文，帳中絲竹遏行雲。',32,'全唐诗/poet.song.248000.json','["堂下青衿日就文，帳中絲竹遏行雲。", "豈應魯壁遺經日，雅奏洋洋滿耳聞。"]'),
('2141e7c6-bc14-4a4f-adf4-0e19c2aef634','詠史 樂羊','張玉孃','宋','宋诗','song-poetry','','[]','自剪冰絲譬遠歸，學成何異此成衣。',32,'全唐诗/poet.song.248000.json','["自剪冰絲譬遠歸，學成何異此成衣。", "妾身不是輕恩愛，祇恐蘇郎戒下機。"]'),
('8a44e161-006b-4ce0-8c0b-13b643d24a24','詠史 賈浪仙','張玉孃','宋','宋诗','song-poetry','','[]','乘馿迢遞走紅塵，十二街中草色春。',32,'全唐诗/poet.song.248000.json','["乘馿迢遞走紅塵，十二街中草色春。", "不是眼空京兆尹，敲推原已入詩神。"]'),
('9d95d973-317c-4748-947b-9f3081343ed9','詠史 陳圖南','張玉孃','宋','宋诗','song-poetry','','[]','避名高卧白雲深，扶醉騎馿下碧岑。',32,'全唐诗/poet.song.248000.json','["避名高卧白雲深，扶醉騎馿下碧岑。", "一笑披袍驚墮處，遯時知有濟時心。"]'),
('f697c7c7-7022-4593-9f60-7b21bba9a08c','詠史 孟浩然','張玉孃','宋','宋诗','song-poetry','','[]','風剪銀潢雪滿天，蹇馿騎過灞橋邊。',32,'全唐诗/poet.song.248000.json','["風剪銀潢雪滿天，蹇馿騎過灞橋邊。", "詩愁萬斛應難載，非爲馳驅老不便。"]'),
('6263335f-f193-4c21-a8db-a0fe353b0ed2','詠史 林和靖','張玉孃','宋','宋诗','song-poetry','','[]','飲盡春觴興轉賒，竹陰扶日印窗斜。',32,'全唐诗/poet.song.248000.json','["飲盡春觴興轉賒，竹陰扶日印窗斜。", "騎馿踏遍吳山曲，處處東風出杏花。"]'),
('de0a3f6f-e7eb-4e7b-bb57-939eda2c5b96','暮春偶成','張玉孃','宋','宋诗','song-poetry','','[]','草香雲暖雨初晴，對竹敲詩坐小亭。',32,'全唐诗/poet.song.248000.json','["草香雲暖雨初晴，對竹敲詩坐小亭。", "晝永人閒啼鳥靜，花飛無語春冥冥。"]'),
('9a53e5a2-a120-46e0-9e5a-ad9cc71032f3','聞笛','張玉孃','宋','宋诗','song-poetry','','[]','小樓吹夜笛聲飛，暗度梅花入翠幃。',32,'全唐诗/poet.song.248000.json','["小樓吹夜笛聲飛，暗度梅花入翠幃。", "曲罷夢回腸欲斷，起看秋月色凝衣。"]'),
('9a5003b9-1158-44c0-9748-4b65cfc8c54b','無題二首  其一','張玉孃','宋','宋诗','song-poetry','','[]','征雁初聞廢織梭，支頤機杼恨偏多。',32,'全唐诗/poet.song.248000.json','["征雁初聞廢織梭，支頤機杼恨偏多。", "溪頭返影留斜日，湖上行舟蕩芰荷。"]'),
('683a3c0f-1072-4d9d-9610-82a9baac4453','無題二首  其二','張玉孃','宋','宋诗','song-poetry','','[]','悶來彈鵲漫停梭，竹島花潭思轉多。',32,'全唐诗/poet.song.248000.json','["悶來彈鵲漫停梭，竹島花潭思轉多。", "秋老莫言春度盡，若邪猶自惜凉荷。"]'),
('d707e459-92d6-4b50-a269-fdcc95892b0b','暮春聞鶑','張玉孃','宋','宋诗','song-poetry','','[]','膏雨初乾風日晴，綠陰深處一聲鶑。',32,'全唐诗/poet.song.248000.json','["膏雨初乾風日晴，綠陰深處一聲鶑。", "喚回午枕傷春夢，起向薔薇花下行。"]'),
('1ce22560-38c1-4c70-bf2b-8ad59de4a013','暮春夜思','張玉孃','宋','宋诗','song-poetry','','[]','夜凉春寂寞，淑氣浸虛堂。',48,'全唐诗/poet.song.248000.json','["夜凉春寂寞，淑氣浸虛堂。", "花外鐘初轉，江南夢更長。", "野春鳴澗水，山月照羅裳。", "此景誰相問，飛螢入繡牀。"]'),
('e50fb134-a0d1-4198-a41f-92a11975c7b1','游春','張玉孃','宋','宋诗','song-poetry','','[]','侍兒傳野約，趣伴出鄰姬。',48,'全唐诗/poet.song.248000.json','["侍兒傳野約，趣伴出鄰姬。", "竹外花迎佩，溪邊柳笑眉。", "春隨流水遠，日度錦雲遲。", "拾翠人爭問，含羞獨有詩。"]'),
('225f14dd-3d51-4ddc-af86-9d4bd02253bc','秋夜','張玉孃','宋','宋诗','song-poetry','','[]','暮聲雜鳴葉，靈籟生郊墟。',48,'全唐诗/poet.song.248000.json','["暮聲雜鳴葉，靈籟生郊墟。", "白霧脆楊柳，秋水翻芙蕖。", "蟾蜍澹簾箔，機杼織寒虛。", "幾度思蘋藻，茫然愧鹿車。"]'),
('7707d68f-6e10-4d5e-b3b4-60682c73f8af','夏夜園亭納凉','張玉孃','宋','宋诗','song-poetry','','[]','南園有凉氣，移席散餘情。',48,'全唐诗/poet.song.248000.json','["南園有凉氣，移席散餘情。", "新月隠修竹，清風開小亭。", "水骨靜香汗，霜紈撲亂螢。", "忽然微雨至，爽籟拂簷楹。"]'),
('d0b221eb-5c15-4cb9-b75a-6c76c6a2672e','春睡','張玉孃','宋','宋诗','song-poetry','','[]','繡倦南窗下，翛然睡思催。',48,'全唐诗/poet.song.248000.json','["繡倦南窗下，翛然睡思催。", "紅日過牆去，清風入幕來。", "幽夢迷莊蝶，荒雲隔楚臺。", "覺來香縷在，虛室絕塵埃。"]'),
('5a648ff2-ccc5-4417-a6f5-011670d47d84','新夏納凉','張玉孃','宋','宋诗','song-poetry','','[]','薰風初轉夏，綠樹老春鶑。',48,'全唐诗/poet.song.248000.json','["薰風初轉夏，綠樹老春鶑。", "暗溜穿花入，輕雲隔竹生。", "倚凉欹畫扇，拭淚聽秦箏。", "素襪香塵暗，槐陰樹底行。"]'),
('2dfd7611-5265-45fc-af4f-72331e4e5dd6','清晝','張玉孃','宋','宋诗','song-poetry','','[]','晝靜春偏遠，詩成興轉賒。',48,'全唐诗/poet.song.248000.json','["晝靜春偏遠，詩成興轉賒。", "看山凭畫閣，問竹過鄰家。", "摘翠閒驚鳥，燒烟曉煮茶。", "無端雙蛺蝶，遶袖錯尋花。"]'),
('0a9849c7-9ab7-4428-85db-15e87d4a0432','元日','張玉孃','宋','宋诗','song-poetry','','[]','曈日破寒天，紅光生紫烟。',48,'全唐诗/poet.song.248000.json','["曈日破寒天，紅光生紫烟。", "詩情歸草夢，春色染桃牋。", "眉月添明鏡，梅粧靜翠鈿。", "堂開諸弟集，相對笑迎年。"]'),
('76321632-9d7b-4bd7-aaa0-fc5241793f75','詠竹 風','張玉孃','宋','宋诗','song-poetry','','[]','滿庭修竹動秋風，掠地無痕一徑通。',64,'全唐诗/poet.song.248000.json','["滿庭修竹動秋風，掠地無痕一徑通。", "影弄綠窗金瑣碎，聲歸寶瑟玉玲瓏。", "流雲不礙湘妃佩，隔水還疑蔡女桐。", "曲罷豈知鸞鶴在，翠霞飛去玉臺空。"]'),
('1dad47d2-fc37-4a4b-a6c7-71df5ce69485','詠竹 烟','張玉孃','宋','宋诗','song-poetry','','[]','數枝瀟灑碧溪寒，水氣冥冥日欲昏。',64,'全唐诗/poet.song.248000.json','["數枝瀟灑碧溪寒，水氣冥冥日欲昏。", "青玉案前雙翡翠，紫絲帳裏萬琅玕。", "湘江舊事迷歸夢，陸海春陰無羽翰。", "晚來獨倚闌干望，暝色連天何處村。"]'),
('8c35086f-45a3-4da2-912e-b0f7708e8dad','詠竹 雪','張玉孃','宋','宋诗','song-poetry','','[]','凍雪霏霏墮九皋，竹枝垂地翠旋銷。',64,'全唐诗/poet.song.248000.json','["凍雪霏霏墮九皋，竹枝垂地翠旋銷。", "玉龍戰退飛鱗甲，青鳳翻成白羽毛。", "歲晚餘寒知勁節，夢回佳興訝清標。", "隔雲誰弄柯亭笛，落盡梅花風韻高。"]'),
('aea14994-b1ee-4173-acc4-49d00ef58226','詠竹 月','張玉孃','宋','宋诗','song-poetry','','[]','幽幽萬籟竹千竿，凉夜宜從月裏看。',64,'全唐诗/poet.song.248000.json','["幽幽萬籟竹千竿，凉夜宜從月裏看。", "翠節參差邀玉兔，金波晃漾浴青鸞。", "半簷蒼月催詩思，一徑寒輝醒醉魂。", "吹徹霓裳清露下，嫦娥猶自對芳樽。"]'),
('49a7e68d-85dd-4410-93f8-8577af92f76f','詠案頭四俊 馬肝硯','張玉孃','宋','宋诗','song-poetry','','[]','一貢西支路八千，端溪無石玉還堅。',64,'全唐诗/poet.song.248000.json','["一貢西支路八千，端溪無石玉還堅。", "龍媒带雨滴秋月，霜兔和雲染翠烟。", "鳳咮山荒幽草合，雀臺春老野花妍。", "丹砂不用醫繁鬢，留爾芸窗勗草玄。"]'),
('c0fe79a7-11bc-43ee-9b92-720c10439de6','詠案頭四俊 鳳尾筆','張玉孃','宋','宋诗','song-poetry','','[]','近來覓得管城子，修竹枝頭彩影高。',64,'全唐诗/poet.song.248000.json','["近來覓得管城子，修竹枝頭彩影高。", "氣挾風雲驅陣勢，光摇文彩動旌旄。", "詩成覽德三書俊，夢入生花五色豪。", "聖代祇今皆有象，晴窗處處鳳凰毛。"]'),
('67533533-f3bb-4fc6-a804-2b4ff9a32cf7','詠案頭四俊 錦花牋','張玉孃','宋','宋诗','song-poetry','','[]','薛濤詩思饒春色，十樣鸞箋五采誇。',64,'全唐诗/poet.song.248000.json','["薛濤詩思饒春色，十樣鸞箋五采誇。", "香染桃英清入觀，影翻藤角眩生花。", "涓涓錦水涵秋葉，苒苒剡波漾晚霞。", "却笑迴文蘇氏子，工夫空自廢韶華。"]'),
('1833b9f3-be32-40f4-b76f-d781816d6ce3','詠案頭四俊 珠麝墨','張玉孃','宋','宋诗','song-poetry','','[]','蘭煤薰透漏星房，蒼璧無痕暈漆光。',64,'全唐诗/poet.song.248000.json','["蘭煤薰透漏星房，蒼璧無痕暈漆光。", "萬杵龍珠凝海水，十分麝淚泣玄霜。", "松烟入硯還矜色，江雨翻雲別有香。", "風靜月林秋氣逼，滿天詩思動清商。"]'),
('a847da35-082f-4e8a-9128-24b3aa4c1be1','燈夕迎紫姑神','張玉孃','宋','宋诗','song-poetry','','[]','淑氣回春雪漸融，星河天上一宵通。',64,'全唐诗/poet.song.248000.json','["淑氣回春雪漸融，星河天上一宵通。", "芙蕖萬點交秋月，鼓角三更度曉風。", "燭影暈迷光綽約，簾環聲徹珮玲瓏。", "不妨鳥篆留仙迹，鳳輦殷勤出紫宮。"]'),
('9c916a4e-3cd6-49a5-a264-eb9227313862','春夜','張玉孃','宋','宋诗','song-poetry','','[]','松花香度漏初沈，人靜庭空落暗金。',64,'全唐诗/poet.song.248000.json','["松花香度漏初沈，人靜庭空落暗金。", "一枕嫩風清曉露，半窗凉月弄輕陰。", "坐移十二闌干曲，興入千層積翠深。", "彈罷雲和重問夜，薔薇影裏復長吟。"]'),
('00b5a113-a4be-4fee-a668-9bf9de7762f3','晚樓凝思','張玉孃','宋','宋诗','song-poetry','','[]','鴛鴦繡罷閣新愁，獨抱雲和散畫樓。',64,'全唐诗/poet.song.248000.json','["鴛鴦繡罷閣新愁，獨抱雲和散畫樓。", "風竹入絃歸別調，湘簾捲月笑銀鈎。", "行天雁向寒烟沒，倚檻人將清淚流。", "自是病多鬆寶釧，不因宋玉故悲秋。"]'),
('5ee28ebd-a373-4daf-9a19-917b418a5b9f','和謫弟三一三峽曉征寄回韻','張玉孃','宋','宋诗','song-poetry','','[]','鳥道縈紆入劍門，謫居惟汝獨憐恩。',64,'全唐诗/poet.song.248000.json','["鳥道縈紆入劍門，謫居惟汝獨憐恩。", "鎖天烟黑疑無地，隔樹人言知有村。", "聽雨不生池草夢，看雲應斷故鄉魂。", "平安日問南歸雁，三峽清秋依曉猿。"]'),
('a60a457b-42c1-408e-87da-276415da5c5f','春粧凝思','張玉孃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春來常是見花羞，終日簾垂懶上鈎。',64,'全唐诗/poet.song.248000.json','["春來常是見花羞，終日簾垂懶上鈎。", "淑氣薰人饒舊夢，柳條縈带綰新愁。", "情歸野草泥寒雨，目斷長江送去舟。", "笑比南金身自許，鏡鸞獨抱下粧樓。"]'),
('87fa0bdd-664b-44a2-823c-962734311bcd','新燕憶女弟京娘','張玉孃','宋','宋诗','song-poetry','','[]','三月江南綠正肥，陰陰深院燕初歸。',64,'全唐诗/poet.song.248000.json','["三月江南綠正肥，陰陰深院燕初歸。", "亂銜飛絮營新壘，閒逐花香避繡幃。", "却笑秋風紅縷在，獨憐舊事玉京非。", "蘭閨終日流清淚，愧爾雙飛拂落暉。"]'),
('6a79f504-5ff7-4e2c-b66b-7a43384feda9','海棠月','張玉孃','宋','宋诗','song-poetry','','[]','永夜無人玉漏遲，團團月上海棠枝。',64,'全唐诗/poet.song.248000.json','["永夜無人玉漏遲，團團月上海棠枝。", "月留凉露芳塵暗，花弄清暉淑影移。", "粉黛三千春對鏡，銀波萬頃曉凝脂。", "深閨爲爾牽愁興，坐問容光强賦詩。"]'),
('4e521f0e-734b-4eb1-82c4-d21ec435ad39','閨情 卜歸','張玉孃','宋','宋诗','song-poetry','','[]','南浦蕭條音信稀，百勞東去燕西飛。',64,'全唐诗/poet.song.248000.json','["南浦蕭條音信稀，百勞東去燕西飛。", "玉釵敲斷燈花冷，游網乘空蟢子非。", "沉水齋心燃寶鼎，金錢纖手卜靈龜。", "數期細認先天課，甲乙爻加歸未歸。"]'),
('bd689d25-bc66-439d-8e88-08d6900f2bd1','閨情 倦繡','張玉孃','宋','宋诗','song-poetry','','[]','綠窗春睡起常遲，繡罷鴛鴦聽子規。',64,'全唐诗/poet.song.248000.json','["綠窗春睡起常遲，繡罷鴛鴦聽子規。", "斜倚睡屏閒悵望，慵臨鸞鏡獨支頤。", "工餘綵線日空永，愁伴珊瑚夢已違。", "細數目前花落盡，傷心都付不言時。"]'),
('f32309cf-ac72-443b-b06a-aecced7036cb','閨情 沐髪','張玉孃','宋','宋诗','song-poetry','','[]','膩滑青螺寶髻黏，金盤香水吸寒蟾。',64,'全唐诗/poet.song.248000.json','["膩滑青螺寶髻黏，金盤香水吸寒蟾。", "指尖巧弄琅玕影，楚髪輕披雲母簾。", "掠霧暗疑星點點，拂波深見玉纖纖。", "起來亂綰慵雙鳳，熏徹沉檀强自添。"]'),
('94c90b8b-257f-4238-83b8-1ce0f4c1130e','閨情 秋千','張玉孃','宋','宋诗','song-poetry','','[]','瘦腰春病不成圍，閑逐秋千蕩畫衣。',64,'全唐诗/poet.song.248000.json','["瘦腰春病不成圍，閑逐秋千蕩畫衣。", "香散天風蘭佩墮，聲摇環玉綵繩飛。", "飄颻似跨雙鸞去，閑雅宜從月殿歸。", "無力尚憐扶不起，翠蛾猶蹙怨斜暉。"]'),
('6ff7ba1b-185e-412c-9edc-286e1007ea78','石榴亭諸父夜酌','張玉孃','宋','宋诗','song-poetry','','[]','永漏報高閣，榴亭出夜筵。',72,'全唐诗/poet.song.248000.json','["永漏報高閣，榴亭出夜筵。", "紫檀熏寶鼎，銀燭散青烟。", "靈籟生修竹，香風入夏絃。", "露濃羅袖重，歌遏酒杯傳。", "諸婦酣春夢，雙娥失翠鈿。", "玉山推不倒，看月背花眠。"]'),
('cbaed48c-fcc4-4553-8fb8-b5ae6c4c67c4','詠夏雨','張玉孃','宋','宋诗','song-poetry','','[]','頭上雲俱黑，一片雨浪浪。',180,'全唐诗/poet.song.248000.json','["頭上雲俱黑，一片雨浪浪。", "慘澹隠高樹，霏微迷綠楊。", "冷冷添澗水，點點落危檣。", "簾捲山流翠，郊虛草自香。", "靜嫌聲間竹，醉愛爽凝觴。", "殿閣羅閒扇，池亭送嫩凉。", "荷珠圓復碎，蘭芷脆還芳。", "拂埃亂天際，度雲喧草堂。", "乘空曳輕練，向晚洗炎光。", "幽徑荒苔滑，短簷飛鳥忙。", "湛湛翻萍影，溶溶浸柳塘。", "無心留石洞，有夢惱襄王。", "暝色欺明月，高飆透薄裳。", "入更生闃寂，欹坐訝清商。", "潤氣清湘簟，徘徊怯繡牀。"]'),
('086f6d9a-7abb-41c7-89ef-2fd4050ec033','游春','張玉孃','宋','宋诗','song-poetry','','[]','護檻花濃夢欲欹，五更清露鎖寒扉。',224,'全唐诗/poet.song.248000.json','["護檻花濃夢欲欹，五更清露鎖寒扉。", "明朝恐負尋芳約，拂曉平瞻霽影依。", "貼翠自憐羞舞鏡，送春無奈聽啼規。", "金蓮破蘚留芳跡，梨萼翻風作雪飛。", "沙上晴鳬窺淺渚，松邊黄蝶繞疏籬。", "催吟片雨雲俱黑，狂絮欺人故點衣。", "心事肯隨流水盡，新愁不與酒尊宜。", "青梅已結梢頭實，驛使難傳隴外枝。", "笑折野花輕插鬢，却嫌溪柳妬修眉。", "因過竹院參禪意，覓得雲林舊日詩。", "聽徹游郎歌古調，停看漁父下苔磯。", "紫山迢遞行應好，蒼磴縈迴出每遲。", "羅袖翩翩香氣滿，綠陰冉冉鳥聲微。", "等閒無限傷春思，芳草天涯腸斷時。"]'),
('1d04f47b-ff84-4e38-b5f7-3690f9375f5a','夢遊龍闕','張玉孃','宋','宋诗','song-poetry','','[]','香魂夜靜趨龍闕，天風吹袂凌波襪。',64,'全唐诗/poet.song.248000.json','["香魂夜靜趨龍闕，天風吹袂凌波襪。", "鮫人愁織雪綃衣，飛瓊笑問青華髪。", "肌澈冰霜玉樹寒，步摇環珮玻璃滑。", "一聲夢覺曉鶑啼，簾篩半枕梨花月。"]'),
('7bf6170c-5c9c-4771-89c8-8bf08170f613','池邊待月','張玉孃','宋','宋诗','song-poetry','','[]','待月月未升，看池池水清。',36,'全唐诗/poet.song.248000.json','["待月月未升，看池池水清。", "冰夷吹海浪，薄霧約雲英。", "惟見寒波動，嫦娥明鏡行。"]'),
('fa083bee-d385-4879-ab88-aa6f97e0a8d8','秋思','張玉孃','宋','宋诗','song-poetry','','[]','爽籟生靈逕，清秋澹碧空。',36,'全唐诗/poet.song.248000.json','["爽籟生靈逕，清秋澹碧空。", "乘凉賒月色，問夜出簾櫳。", "獨坐憐團扇，羅衣吹暗風。"]'),
('ed372fd7-6602-4e9a-8cba-f762b0a3f504','哭沈生','張玉孃','宋','宋诗','song-poetry','','[]','仙郎久未歸，一歸笑春風。',60,'全唐诗/poet.song.248000.json','["仙郎久未歸，一歸笑春風。", "中塗成永絕，翠袖染啼紅。", "悵恨生死異，夢魂還再逢。", "寶鏡照秋水，明此一寸衷。", "素情無所著，怨逐雙飛鴻。"]'),
('3e123285-a111-4785-8e12-51c633b05c50','梅花村','張玉孃','宋','宋诗','song-poetry','','[]','羅浮山下玉千株，十里長洲五里湖。',64,'全唐诗/poet.song.248000.json','["羅浮山下玉千株，十里長洲五里湖。", "嘉樹留人舒嘯地，飛花送客醉歸途。", "影橫烏帽月隨步，香襟羔裘水在鬢。", "夢想湖山身不到，詩成憑寄老申屠。"]'),
('59d9c9ab-539a-46bd-a1c7-d658248d785c','病中贈張玉孃','沈佺','宋','宋诗','song-poetry','','[]','隔水度仙妃，清絕雲爭飛。',48,'全唐诗/poet.song.248000.json','["隔水度仙妃，清絕雲爭飛。", "嬌花羞秀質，秋月見寒輝。", "高情春不染，心境塵難依。", "何當飲雲液，共跨雙鸞歸。"]'),
('c487e476-c427-45bf-881a-d075df37b148','句  其一','江砢','宋','宋诗','song-poetry','','[]','西風野如赭，見者輒吐舌。',12,'全唐诗/poet.song.248000.json','["西風野如赭，見者輒吐舌。"]'),
('d44224bc-34c2-4ec0-a5d5-7448f8b072b2','句  其二','江砢','宋','宋诗','song-poetry','','[]','太傅數日別，劉公一紙書。',12,'全唐诗/poet.song.248000.json','["太傅數日別，劉公一紙書。"]'),
('80fb0af6-12fd-4de2-b675-22d77bf98857','句  其三','江砢','宋','宋诗','song-poetry','','[]','讀書三年艾，逢世四角輪。',12,'全唐诗/poet.song.248000.json','["讀書三年艾，逢世四角輪。"]'),
('dfcf5363-9101-4a9a-ad8e-bd4a5547c835','哭妹貞娘節烈','鄭君老','宋','宋诗','song-poetry','','[]','哀哉吾妹兮，生不逢時。',207,'全唐诗/poet.song.248000.json','["哀哉吾妹兮，生不逢時。", "痛哉吾妹兮，死此亂離。", "灰塵漲空兮，鐵騎南馳。", "旌旗蔽野兮，日色無輝。", "兇徒蜂起兮，濁亂民彝。", "恣行劫掠兮，四野傷悲。", "我妹遇茲兮，尚在閨闈。", "若逃患難兮，計無可爲。", "恐被污辱兮，决死無疑。", "一刀自刎兮，澌血淋漓。", "死仆於床兮，不變容儀。", "刀不落地兮，手尚堅持。", "英烈如生兮，人誰敢欺。", "嗟我獨生兮，於世何裨。", "汝危莫援兮，恨無窮期。", "悠悠我思兮，泣涕漣如。", "人皆有死兮，特出異宜。", "哀哉痛哉兮，噫嘻。", "獨存汝名兮，萬古無遺。"]'),
('9cb54746-a00e-4411-bf3f-bf8a235cbd29','贈戴石玉','王炎午','宋','宋诗','song-poetry','','[]','琢之磨之，玉汝于成。',80,'全唐诗/poet.song.248000.json','["琢之磨之，玉汝于成。", "孰爲玉工，師友父兄。", "他山之石，今則在我。", "彼璞之棄，我責之墮。", "爲瑚爲璉，如珪如璋。", "山澤之潤，邦家之光。", "玉不自毀，人自喪寶。", "聞士稱名，不離其道。"]'),
('54d5ea26-f620-46bf-bc53-6a067431f554','岳王墓','韓信同','宋','宋诗','song-poetry','','[]','妖星隳地芒角赤，龍劍悲吼風蕭瑟。',144,'全唐诗/poet.song.248000.json','["妖星隳地芒角赤，龍劍悲吼風蕭瑟。", "中原王氣挽不回，將軍一死鴻毛擲。", "秦家小兒真戲劇，播弄造化摇樞極。", "指讎爲親忠且逆，隻手上遮天眼碧。", "九重茫茫隔天日，無由下燭臣愚直。", "臣愚萬死不足惜，國恥未湔猶憤激。", "古墳埋冤血空瀝，西風年年土花蝕。", "我恐精忠埋不得，白日英魂土中泣。", "請將衰骨斵苔痕，獻作吾皇補天石。"]'),
('88189c4f-9a47-472d-aa0a-66ef84c1d2e5','翠屏霽雪','韓信同','宋','宋诗','song-poetry','','[]','寒林靜對展翠屏，六花粧點風景清。',128,'全唐诗/poet.song.248000.json','["寒林靜對展翠屏，六花粧點風景清。", "四山簇簇瓊瑶樹，恍然照映芝蘭庭。", "寒生晴光色爍爍，含輝照耀銀海明。", "巉岩石化崑山玉，負暄猿猱出深谷。", "可憐不老山白頭，梅萼藏春暗香馥。", "紫陽留讖歌翠寒，中有玉人在其間。", "道傳前聖發未發，教開來學難亦難。", "豁然胸次冰雪釋，白照紅日上團團。"]'),
('4812905e-54b4-4c95-8985-bb9e8ecf7661','蓬萊飛峰','韓信同','宋','宋诗','song-poetry','','[]','海上神山名自昔，來去隨潮無定迹。',144,'全唐诗/poet.song.248000.json','["海上神山名自昔，來去隨潮無定迹。", "天人俯覽念虛浮，六鰲頂戴窮神力。", "群仙貝闕蕊珠宮，多種瑶芝瓊草碧。", "依然根著不堅牢，飛入石堂作南壁。", "螺紋蠣迹石龍存，雲氣隨潮時雨濕。", "仙風颯爽生羽翰，招納霓裳羽衣客。", "試登絕頂望五湖，高樓洞天纔咫尺。", "藥爐灰冷多登真，九轉丹成人未識。", "雲間鶴迹託來篇，王鄧真人久相憶。"]'),
('be110d78-ade0-4e3f-9852-fba23e2c8e15','棋盤仙迹','韓信同','宋','宋诗','song-poetry','','[]','唐山絕頂棋盤石，戲局流傳名自昔。',123,'全唐诗/poet.song.248000.json','["唐山絕頂棋盤石，戲局流傳名自昔。", "殷勤細問白髪翁，云是仙人曾對奕。", "苔封石磴不敢移，竹引清風時拂拭。", "箇中黑白子不留，想是仙童爲收拾。", "又不聞樵採之人王子質，邂逅仙人執手談，贏輸未决藏機密。", "貪看柯爛不知時，少憩山中方七日。", "誰識囊中日月長，歸來塵世無相識。"]'),
('1acbda7c-5373-444f-8231-13829fe51202','雙柱擎天','韓信同','宋','宋诗','song-poetry','','[]','白鶴岧嶢枕江曲，接岫連峰衍林麓。',112,'全唐诗/poet.song.248000.json','["白鶴岧嶢枕江曲，接岫連峰衍林麓。", "石堂峻峭萬山雄，擁翠亭亭多喬木。", "雙撐石柱峙東南，勢力擎天名不俗。", "鍾英特産棟梁材，不墜簪纓美如玉。", "左接蓬萊右洞天，峰前水带縈九曲。", "依然幻出武陵源，擬就峰傍新卜築。", "鶴歸錯認華表存，應笑世人枉追逐。"]'),
('e511ba88-86f7-4f41-8a8a-314861679a1d','澹山巖','文起傳','宋','宋诗','song-poetry','','[]','拭目澹巖景，鶑花三月時。',48,'全唐诗/poet.song.248000.json','["拭目澹巖景，鶑花三月時。", "洞堆鍾乳石，林擁梵宮基。", "泉瑩宜烹茗，崖穹好筆詩。", "勝遊情未倦，又促解舟維。"]'),
('5d206f26-e893-47d2-9b4e-f653bf651b2e','仙船巖','劉邊','宋','宋诗','song-poetry','','[]','仙舟等奡盪，萬仞架雲表。',72,'全唐诗/poet.song.248000.json','["仙舟等奡盪，萬仞架雲表。", "木石渾莫分，風雨能不朽。", "恐因堯年水，艤櫂寄巖竇。", "猶勝夜壑藏，有力莫負走。", "奈何苦海深，忍袖慈航手。", "我欲遡靈源，乘槎問牛斗。"]'),
('1d04b07a-0f63-4a4f-8edb-d49d5c2e10d8','仙機巖','劉邊','宋','宋诗','song-poetry','','[]','嘗聞昔天孫，謫落人世間。',60,'全唐诗/poet.song.248000.json','["嘗聞昔天孫，謫落人世間。", "雲霞入組織，機杼空留山。", "朅來巧相逢，遺我錦繡端。", "欲報乏綺語，再拜重捲還。", "我有大布衣，可以禦歲寒。"]'),
('a2760b64-a88b-4b5b-8049-8aa9d72f4a50','會仙巖','劉邊','宋','宋诗','song-poetry','','[]','青山解隨人，遠近互相對。',48,'全唐诗/poet.song.248000.json','["青山解隨人，遠近互相對。", "寒潭入陵谷，龍去知何處。", "歷歷沙上石，群仙昔來會。", "日暮一童歸，橫吹卧牛背。"]'),
('dbdf4897-4875-4c7a-9b61-6d1ee13c6edb','茶竈','劉邊','宋','宋诗','song-poetry','','[]','仙人足戲劇，盤石留渦房。',72,'全唐诗/poet.song.248000.json','["仙人足戲劇，盤石留渦房。", "紫陽此來遊，與客煮茗嘗。", "青烟久消歇，白雲時飛揚。", "至今潭中水，猶作笑語香。", "蒙茸履跡在，欲步不敢翔。", "三吸此清泠，回首入空蒼。"]'),
('688ab46a-6105-4c2e-b7c1-573f80f20491','林泉寺','劉邊','宋','宋诗','song-poetry','','[]','采芳仍漱潔，散策到來遲。',48,'全唐诗/poet.song.248000.json','["采芳仍漱潔，散策到來遲。", "客坐自相語，僧禪了不知。", "疏風潜入戶，暗水細鳴池。", "小作石牀夢，夢中還覓詩。"]'),
('f495287d-febb-4666-b9be-55f93e77201d','天遊峰','劉邊','宋','宋诗','song-poetry','','[]','紫翠飛來石蕊間，何年幻出小瀛寰。',64,'全唐诗/poet.song.248000.json','["紫翠飛來石蕊間，何年幻出小瀛寰。", "崖懸瘦瀑一千尺，峽束寒流八九灣。", "蒼壁向人如有待，白雲何事未知還。", "歌酣更挹浮丘伯，坐對中臺話半閒。"]'),
('9f62f8f7-f659-4fa6-9f97-0395b00905c5','梅仙山','劉邊','宋','宋诗','song-poetry','','[]','已是吳門變姓名，後來誰更識先生。',64,'全唐诗/poet.song.248000.json','["已是吳門變姓名，後來誰更識先生。", "一抔漢土丹墟在，萬古閩山劍氣橫。", "步入白雲秋石瘦，坐分黄葉午風清。", "逃奴不返松門靜，隔水寒烟起暮城。"]'),
('473a7a6c-22a8-43b4-b4b6-289c020c4793','伏羲洞','劉邊','宋','宋诗','song-poetry','','[]','一水之玄去復歸，衆峰向背儼相持。',64,'全唐诗/poet.song.248000.json','["一水之玄去復歸，衆峰向背儼相持。", "天荒地老無從問，鬼刻神劖未解奇。", "丹嶂漫留仙幻跡，白雲仍似太初時。", "欲窮畫底羲皇意，一束靈蓍萬古知。"]'),
('4bc208e8-a7ed-4288-a659-0f9baf7f650e','玉女峰','劉邊','宋','宋诗','song-poetry','','[]','不作巫陽雲雨羞，風鬟霧鬢亂蕭颼。',32,'全唐诗/poet.song.248000.json','["不作巫陽雲雨羞，風鬟霧鬢亂蕭颼。", "行人莫問當年事，獨立寒潭空幾秋。"]'),
('4b45a91b-a8ef-4810-b868-dbe1d5f3c6e0','答彥修','劉邊','宋','宋诗','song-poetry','','[]','九曲溪邊玉女峰，年年獨倚落花風。',32,'全唐诗/poet.song.248000.json','["九曲溪邊玉女峰，年年獨倚落花風。", "何因不駕青鸞去，佇立空山皓月中。"]'),
('b6950f20-af8c-40dc-a36f-8039197f64a3','仙掌峰','劉邊','宋','宋诗','song-poetry','','[]','銅盤捧露幾何年，渭水秋風淚泫然。',32,'全唐诗/poet.song.248000.json','["銅盤捧露幾何年，渭水秋風淚泫然。", "已向山中閒袖手，爲誰半壁更擎天。"]'),
('cdbea030-ef02-405a-8200-20c467758b1f','釣磯石','劉邊','宋','宋诗','song-poetry','','[]','百尺臺磯瞰碧流，紫陽仙子幾經秋。',32,'全唐诗/poet.song.248000.json','["百尺臺磯瞰碧流，紫陽仙子幾經秋。", "遊魚何事偏深逝，不道人間有直鈎。"]'),
('02cd77f2-21b5-4de6-8e4f-059d7a517ffb','句','劉邊','宋','宋诗','song-poetry','','[]','耕鋤曉雨有餘地，應接東風無暇時。',16,'全唐诗/poet.song.248000.json','["耕鋤曉雨有餘地，應接東風無暇時。"]'),
('670c6e86-5457-40be-a802-a47d24eb9000','早秋有懷寄趙華顛','陳紀','宋','宋诗','song-poetry','','[]','一葉井梧落，微凉生瘦藤。',48,'全唐诗/poet.song.248000.json','["一葉井梧落，微凉生瘦藤。", "老兼秋共至，衰與病相仍。", "砌近蟲號枕，簷疏雨翳燈。", "熏爐對經卷，清似住山僧。"]'),
('4dc2e5f9-2bc8-457d-b2f7-172e300b9fdc','遊深溪龍潭','陳紀','宋','宋诗','song-poetry','','[]','危磴上嶙峋，泉聲靜更聞。',48,'全唐诗/poet.song.248000.json','["危磴上嶙峋，泉聲靜更聞。", "雨添三尺水，僧卧半間雲。", "境勝詩難好，林深日易曛。", "忘言觀衆妙，一縷起爐熏。"]'),
('e72d9b18-5c0f-4914-8651-9aa0ce4b39e1','暮春山行  其一','陳紀','宋','宋诗','song-poetry','','[]','幽興忽不愜，山蹊策杖遊。',48,'全唐诗/poet.song.248000.json','["幽興忽不愜，山蹊策杖遊。", "林深樹疊影，溪漲水重流。", "對酒愁先醉，看花老却羞。", "平生倚樓意，搔首轉悠悠。"]'),
('99f678a2-4f3a-4e81-9424-0fd65d44b1d3','暮春山行  其二','陳紀','宋','宋诗','song-poetry','','[]','不具看花眼，蕭然綠暗邨。',48,'全唐诗/poet.song.248000.json','["不具看花眼，蕭然綠暗邨。", "貧來疑筆硯，老去信乾坤。", "日澹樹無影，潮回草有痕。", "詩成鷗沒處，鴉外又黄昏。"]'),
('a48ff68f-4a56-4cab-8ad9-04978a37a27b','早起','陳紀','宋','宋诗','song-poetry','','[]','星斗淡欲落，銀河白向斜。',48,'全唐诗/poet.song.248000.json','["星斗淡欲落，銀河白向斜。", "人間猶夢蟻，樹杪已聞鴉。", "池水偷山影，朝陽禪月華。", "升沈無限事，秋草滿天涯。"]'),
('66c7b642-d576-4268-8d9a-71fe2a7ea8b7','雨中出廓','陳紀','宋','宋诗','song-poetry','','[]','幽人寧免俗，踸踔且泥行。',48,'全唐诗/poet.song.248000.json','["幽人寧免俗，踸踔且泥行。", "雲過溪流動，雨餘池草生。", "長身成跼蹐，暮景學將迎。", "應被鄰翁笑，有田胡不耕。"]'),
('282b8d2e-91f9-429a-bc95-94fc16eba629','哭月橋兄','陳紀','宋','宋诗','song-poetry','','[]','前輩風流盡，鄉枌孰表儀。',48,'全唐诗/poet.song.248000.json','["前輩風流盡，鄉枌孰表儀。", "如公又凋謝，末俗恐澆漓。", "幼學皆真踐，瀕危屬近思。", "端爲吾道慟，不但哭吾私。"]'),
('3a07fd66-609a-432a-aefe-9f09d098ecdc','輓趙秋曉  其一','陳紀','宋','宋诗','song-poetry','','[]','鵬運南來駐海涯，熟聞諸老說瑰奇。',64,'全唐诗/poet.song.248000.json','["鵬運南來駐海涯，熟聞諸老說瑰奇。", "周瓜正接雲仍瓞，郗桂駢生父子枝。", "閲世忽更龍漢劫，蓋棺猶見義熙詩。", "每嗟嶺海無英特，况失斯人重可悲。"]'),
('4b634599-a6af-4318-a0c7-3eda0eb50f30','輓趙秋曉  其二','陳紀','宋','宋诗','song-poetry','','[]','摩室興居問亦詳，祗言永訣語琅琅。',64,'全唐诗/poet.song.248000.json','["摩室興居問亦詳，祗言永訣語琅琅。", "情知豎子膏肓病，謾試庸醫補瀉方。", "華屋邱山真俛仰，長瓶短管付淒凉。", "平生曾賞窮吟者，莫訝銜哀入些章。"]'),
('9b8fdf2a-34ac-4962-8f42-09a73745154c','輓趙秋曉  其三','陳紀','宋','宋诗','song-poetry','','[]','年頭歲尾足追隨，暢飲高歌送落暉。',64,'全唐诗/poet.song.248000.json','["年頭歲尾足追隨，暢飲高歌送落暉。", "賡詠每思彈丸句，談諧常落箭鋒機。", "漸成瓜葛緣方熟，共看茱萸事已非。", "數尺茅簷楊柳岸，故應經此尚依依。"]'),
('8cc9a792-7002-4a83-893c-a76fa3a2d3e4','窮吟','陳紀','宋','宋诗','song-poetry','','[]','窮吟之外百無功，鬢髪蕭蕭漸已翁。',64,'全唐诗/poet.song.248000.json','["窮吟之外百無功，鬢髪蕭蕭漸已翁。", "自枕書眠聽夜雨，偶披襟去納雌風。", "男兒未死身難量，豪傑雖貧氣未窮。", "緩步短筇誰會得，野花啼鳥夕陽紅。"]'),
('388a9a98-4227-4ace-8e3d-f4caf67bdc4b','甲辰元日','陳紀','宋','宋诗','song-poetry','','[]','屋角雞聲一歲分，起搔吟鬢惜芳辰。',64,'全唐诗/poet.song.248000.json','["屋角雞聲一歲分，起搔吟鬢惜芳辰。", "江山有恨英雄老，天地無私草木春。", "柏葉又傾新歲酒，梅花同是隔年人。", "東風著物能多少，寫入清詩句句新。"]'),
('63e08376-d762-4b67-9b4f-61e61a29f551','夜夢遊一野人家萬竹蒼寒老翁款留意甚厚予題詩贈之獨記一聯云與誰共住只明月所可論交惟此君覺足成之亦夢中意也','陳紀','宋','宋诗','song-poetry','','[]','一徑蒼寒長綠筠，雞聲人語隔林聞。',64,'全唐诗/poet.song.248000.json','["一徑蒼寒長綠筠，雞聲人語隔林聞。", "與誰共住祇明月，所可論交惟此君。", "世事乘除天已定，人生勞逸念中分。", "卜鄰倘許通來往，分我南山一片雲。"]'),
('9cf5a0cb-01af-4afc-a1f8-774e4038c2b4','題李竹隠山齋','陳紀','宋','宋诗','song-poetry','','[]','法界人寰共一邱，欲窮遠目更登樓。',64,'全唐诗/poet.song.248000.json','["法界人寰共一邱，欲窮遠目更登樓。", "蒼藤碧蘚樹容晚，凉月好風山意秋。", "莎徑荒寒聞鶴唳，竹叢摇落見漁舟。", "一聲橫笛碧天暮，詩在滄波蘆荻洲。"]'),
('ad639c23-05ef-4e69-88c2-fba6c7a45c37','舟行','陳紀','宋','宋诗','song-poetry','','[]','落日殘霞島嶼明，淡烟衰草古今情。',64,'全唐诗/poet.song.248000.json','["落日殘霞島嶼明，淡烟衰草古今情。", "青山偏向意中遠，白鳥正當吟處橫。", "歲晚梅花和我老，愁來竹葉向誰傾。", "浪遊無奈徂年感，遠浦晚風潮又生。"]'),
('a6bcad9d-88d0-441c-9f0a-3189bd0563c7','夜起','陳紀','宋','宋诗','song-poetry','','[]','萬籟沈沈見息機，輕寒獵獵入單衣。',64,'全唐诗/poet.song.248000.json','["萬籟沈沈見息機，輕寒獵獵入單衣。", "新霜欲落露痕重，缺月漸高河影微。", "村犬驚寒時自吠，水禽失侶夜猶飛。", "更須景物完詩句，莫訝更闌未掩扉。"]'),
('ed018710-c0af-43a5-b1b6-e5efd0ce9b83','初夏','陳紀','宋','宋诗','song-poetry','','[]','梅子黄時雨又晴，春衫未脫暑猶輕。',64,'全唐诗/poet.song.248000.json','["梅子黄時雨又晴，春衫未脫暑猶輕。", "天橫遠岫半眉綠，雲漏斜陽一眼明。", "野樹晚風清蝶夢，曲池芳草亂蛙聲。", "浮生囂寂何窮已，搔首蓬窗感慨生。"]'),
('386decf6-8ef4-45d0-9f31-da9a3d3ecee0','和趙華顛梅花','陳紀','宋','宋诗','song-poetry','','[]','起舞簪花老尚狂，梅花應記舊高陽。',64,'全唐诗/poet.song.248000.json','["起舞簪花老尚狂，梅花應記舊高陽。", "蕊宮仙子無塵韻，幽谷佳人有靚粧。", "斜月半簷微弄影，斷橋深夜忽聞香。", "真成坐對被渠惱，不信先生鐵石腸。"]'),
('ba5efd7b-773e-42a2-adda-bfb5c0310c7c','謝謝疊山惠杜詩紙被','陳紀','宋','宋诗','song-poetry','','[]','貪詩如蜜睡如餳，二貺偕來敢不登。',64,'全唐诗/poet.song.248000.json','["貪詩如蜜睡如餳，二貺偕來敢不登。", "錦軸一編夔府稿，雪衾萬桿剡溪藤。", "朝來誦句能驅瘧，夜半眠雲稱伴僧。", "只恐癡兒驕踏裂，起來仍喚讀書燈。"]'),
('138851f4-5bb9-4387-adbc-d45d0e10b163','春感','陳紀','宋','宋诗','song-poetry','','[]','唾壺壯氣已休休，呼酒田翁與勸酬。',64,'全唐诗/poet.song.248000.json','["唾壺壯氣已休休，呼酒田翁與勸酬。", "九十日春長是雨，三千丈髪總緣愁。", "棱棱顔面塵埃滿，渺渺山河歲月遒。", "谷飲芝餐皆可飽，人生何必稻粱謀。"]'),
('49489a8b-9442-453a-a7a2-4d80964a96c9','秋懷','陳紀','宋','宋诗','song-poetry','','[]','書劍飄零學稼遲，吾儕捨此欲安之。',64,'全唐诗/poet.song.248000.json','["書劍飄零學稼遲，吾儕捨此欲安之。", "愁懷慣對寒燈話，老態惟應曉鏡知。", "中散不堪長忤俗，陶潜所好每違時。", "西風落日蘋花岸，獨立蒼茫自詠詩。"]'),
('72aa5db6-2901-46a2-959f-6d8b0dcbcf65','夜宿增江松鶴庵','陳紀','宋','宋诗','song-poetry','','[]','木落風高夜欲冰，襥衾來此愛幽清。',64,'全唐诗/poet.song.248000.json','["木落風高夜欲冰，襥衾來此愛幽清。", "壁燈未滅見花影，山雨忽來聞竹聲。", "謾憶同遊期後會，因思往事悟前生。", "自憐粗带山林骨，坐待寒鐘吼五更。"]'),
('ae4110fb-b8af-457b-a7df-b0e9d6aae7a0','寄朱滄洲','陳紀','宋','宋诗','song-poetry','','[]','不見滄洲已十霜，夢中炯炯此靈光。',64,'全唐诗/poet.song.248000.json','["不見滄洲已十霜，夢中炯炯此靈光。", "青山拄杖尚能否，華髪與秋俱老蒼。", "夜雨豐湖吟浩蕩，夕陽鶴觀弔興亡。", "通家有子今頭白，此意堪君累十觴。"]'),
('52666388-8e3f-460a-aa88-655f4a2c80a9','早春有懷亡友秋曉恕齋小山諸公','陳紀','宋','宋诗','song-poetry','','[]','詩成誰與共賡酬，又綠前汀杜若洲。',64,'全唐诗/poet.song.248000.json','["詩成誰與共賡酬，又綠前汀杜若洲。", "舊友凋零渾似夢，新春蕭索亦如秋。", "陰晴氣候惟供睡，今古乾坤只載愁。", "我與東風俱是客，肯緣華屋妬山邱。"]'),
('9cd6b2db-75d9-4405-9ee0-a6d51c3542fb','餞黎希明赴興寧教諭','陳紀','宋','宋诗','song-poetry','','[]','冷官仍冷地，况味淡於僧。',48,'全唐诗/poet.song.248000.json','["冷官仍冷地，况味淡於僧。", "泮水無一畝，亂山知幾層。", "樹雲侵絳帳，山雨翳青燈。", "若有登臨句，寄予能不能。"]'),
('cf83ce2b-dc86-44e8-9b7b-72eec8678979','梅花','陳紀','宋','宋诗','song-poetry','','[]','冰霜骨格玉精神，索笑巡簷不厭頻。',64,'全唐诗/poet.song.248000.json','["冰霜骨格玉精神，索笑巡簷不厭頻。", "清瘦絕如人有韻，品題除是筆無塵。", "一枝影裏溪山晚，萬斛香中天地春。", "幾度見渠詩便好，此花前世定詩人。"]'),
('573cb7cb-a67b-494d-8ec3-ccc9249384af','錢唐懷古','汪斗建','宋','宋诗','song-poetry','','[]','江上城低烟樹紅，江潮西去幾時東。',64,'全唐诗/poet.song.248000.json','["江上城低烟樹紅，江潮西去幾時東。", "吳王花草隨春暮，禹會樓臺入夢空。", "萬里孤雲留夕照，千年遺恨訴秋風。", "鳳凰飛去無消息，漠漠遥岑烟雨中。"]'),
('5508e866-d892-4653-b183-1a0b138395bc','句','鍾克俊','宋','宋诗','song-poetry','','[]','自許有身埋漢土，終憐無淚哭秦廷。',16,'全唐诗/poet.song.248000.json','["自許有身埋漢土，終憐無淚哭秦廷。"]'),
('ea159391-60a5-4052-99a6-404bc47fb9f1','軍中行','陳宗傳','宋','宋诗','song-poetry','','[]','胡馬出幽燕，風塵起北陬。',108,'全唐诗/poet.song.248000.json','["胡馬出幽燕，風塵起北陬。", "天兵偶不利，王氣黯然收。", "六龍守沙漠，誰復爲報仇。", "耿耿孤臣衷，長懷麥秀憂。", "回首望京闕，血淚相和流。", "安得衆猛士，盡如穰苴儔。", "戮力共廝殺，梟取可汗頭。", "掃清犬羊群，釐復舊神州。", "奇功勒燕石，芳名播千秋。"]'),
('8b72b131-ebe7-49b4-a89a-fa3e29d6048e','義合寺二首  其一','徐瑞','宋','宋诗','song-poetry','','[]','峭壁空翠濕，幽林煙霏清。',24,'全唐诗/poet.song.248000.json','["峭壁空翠濕，幽林煙霏清。", "峰巔忽長嘯，疑是孫登聲。"]'),
('a6599cf5-46b3-445c-94fc-55dfae535753','義合寺二首  其二','徐瑞','宋','宋诗','song-poetry','','[]','枯根絆老石，槁葉填古逕。',24,'全唐诗/poet.song.248000.json','["枯根絆老石，槁葉填古逕。", "四山悄無人，鏗然一聲磬。"]'),
