('fb2b446f-e8ce-4c4a-bf0a-ec48ab4b84db','次韻寄題文溪許氏秋圃','徐瑞','宋','宋诗','song-poetry','','[]','我看黄花意甚長，紛紛蕭艾不能荒。',32,'全唐诗/poet.song.248000.json','["我看黄花意甚長，紛紛蕭艾不能荒。", "無論楚晉韓家事，萬古秋風只自芳。"]'),
('97b6372d-3859-4be0-afd8-803a757121c8','飯牛','徐瑞','宋','宋诗','song-poetry','','[]','飯牛夙志老方酬，看似溈山水牯牛。',32,'全唐诗/poet.song.248000.json','["飯牛夙志老方酬，看似溈山水牯牛。", "水草尋常自調伏，鼻端不用拽繩頭。"]'),
('28e9d25c-f017-4296-bc38-1f7dddc1ff9d','腰痛苦甚戲作二絕句','徐瑞','宋','宋诗','song-poetry','','[]','十萬腰纏不足珍，腰圍頓減可憐人。',32,'全唐诗/poet.song.248000.json','["十萬腰纏不足珍，腰圍頓減可憐人。", "折腰不爲五斗米，彭澤元來解忍貧。"]'),
('faeee415-6c98-4026-87b4-89965fe25db7','正月廿七月灣來訪折千葉紅梅一枝爲贈','徐瑞','宋','宋诗','song-poetry','','[]','喜聞環佩響然臻，笑語芬芳絕世塵。',32,'全唐诗/poet.song.248000.json','["喜聞環佩響然臻，笑語芬芳絕世塵。", "林壑荒凉無所有，殷勤送似一枝春。"]'),
('6d857873-055d-4634-b23e-02a220fca584','七月十六夜對月有感','徐瑞','宋','宋诗','song-poetry','','[]','神遊赤壁水光浮，想見元豐壬戌秋。',32,'全唐诗/poet.song.248000.json','["神遊赤壁水光浮，想見元豐壬戌秋。", "甲子四周月長好，更無人續宋風流。"]'),
('622d6d56-5898-4d0d-943c-71db0f5fca66','次韻吳仲退見貽  其一','徐瑞','宋','宋诗','song-poetry','','[]','瘦竹相隨立，輕堅九節青。',48,'全唐诗/poet.song.248000.json','["瘦竹相隨立，輕堅九節青。", "川平雲澹澹，風定樹亭亭。", "汩沒悲流俗，驅馳累有形。", "揜關差有味，危坐玩羲經。"]'),
('002729e7-192e-401e-9ba6-47d943008055','次韻吳仲退見貽  其二','徐瑞','宋','宋诗','song-poetry','','[]','天秋分袂後，擾擾似年時。',48,'全唐诗/poet.song.248000.json','["天秋分袂後，擾擾似年時。", "竟負梅花約，空哦春樹詩。", "斷崖粘凍雪，碎石漾流嘶。", "悵望灣頭路，扁舟樂泳思。"]'),
('778e4947-64f0-4cad-95c1-6fc855a9a4f9','溪上晚眺','徐瑞','宋','宋诗','song-poetry','','[]','望逐飛雲去，天低落景黄。',48,'全唐诗/poet.song.248000.json','["望逐飛雲去，天低落景黄。", "江湖流不盡，宇宙事何長。", "帆影行空闊，漁歌出莽蒼。", "沙平秋草遠，鷗鷺未相忘。"]'),
('2e5373ef-158f-4329-b143-9db85265109f','秋夜','徐瑞','宋','宋诗','song-poetry','','[]','沉沉秋夜靜，輕策步中庭。',48,'全唐诗/poet.song.248000.json','["沉沉秋夜靜，輕策步中庭。", "止酒天真澹，烹茶世夢醒。", "風枝繞驚鵲，露草度流螢。", "物化猶如此，浮生可得停。"]'),
('49112480-df45-4cb5-a1ef-780e8cf90cbf','臨泉寺','徐瑞','宋','宋诗','song-poetry','','[]','扁舟駐寒瀨，輕策到臨泉。',48,'全唐诗/poet.song.248000.json','["扁舟駐寒瀨，輕策到臨泉。", "僧說黄巢事，碑鑱慶曆年。", "幽花荒甃晚，落木古城煙。", "興廢俱陳迹，相看一惘然。"]'),
('f34a9319-dba5-4e5d-9c43-90740710fe9d','重過鐘潭寺月灣有詩次韻','徐瑞','宋','宋诗','song-poetry','','[]','五年三到此，門逕怪頻移。',48,'全唐诗/poet.song.248000.json','["五年三到此，門逕怪頻移。", "絕壁何年樹，空廊異代碑。", "微瀾生古瀨，浮翠擁修眉。", "煮茗談時事，山僧總未知。"]'),
('19bee1cb-acc1-4fb3-9762-9bdcd38d9258','無庵道人贈硯報之以詩','徐瑞','宋','宋诗','song-poetry','','[]','別去驚離索，重來更劇談。',48,'全唐诗/poet.song.248000.json','["別去驚離索，重來更劇談。", "送人還有硯，住世却無庵。", "白鶴千年化，黄粱萬枕酣。", "區中緣未畢，一見一回慚。"]'),
('c3c27a92-f813-474d-aac5-b40491d337a6','求余敬可字與小兒習不至','徐瑞','宋','宋诗','song-poetry','','[]','點槸今誰妙，波戈古莫稽。',48,'全唐诗/poet.song.248000.json','["點槸今誰妙，波戈古莫稽。", "要令識陣馬，不是厭家雞。", "鄴瓦玄雲濕，溪藤暮雨凄。", "媿無鵝可換，萬一付歸奚。"]'),
('91b840b9-ce2e-4955-8813-017436fa3369','月磵自杭歸以詩問訊','徐瑞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','記別秋風裏，聞歸禁火初。',48,'全唐诗/poet.song.248000.json','["記別秋風裏，聞歸禁火初。", "深慚聊爾耳，久闕問何如。", "梅雪西湖鶴，潮風東海魚。", "經行入詩否，早晚叩精廬。"]'),
('6db15702-5f50-41b2-947e-59e46ed72f5c','涉世','徐瑞','宋','宋诗','song-poetry','','[]','涉世頭將白，耽詩貌欲枯。',48,'全唐诗/poet.song.248000.json','["涉世頭將白，耽詩貌欲枯。", "晨齋參玉版，夜渴飲冰壺。", "咄咄知今是，栖栖媿故吾。", "窮通端有命，一笑視平蕪。"]'),
('639fe135-f499-4b95-9da4-70a11379f43d','題舊藁','徐瑞','宋','宋诗','song-poetry','','[]','書向愁邊著，詩添病後吟。',48,'全唐诗/poet.song.248000.json','["書向愁邊著，詩添病後吟。", "不成千古事，空費一生心。", "華髪江湖晚，青燈風雪深。", "鍾期那可鑄，塵網斷紋琴。"]'),
('59316f7d-2a17-4077-9e8f-a23118047fa9','醉中作','徐瑞','宋','宋诗','song-poetry','','[]','歲月驚虛擲，風霜信飽更。',48,'全唐诗/poet.song.248000.json','["歲月驚虛擲，風霜信飽更。", "蚤知窮有命，惟以飲留名。", "人事宜藏拙，天工亦惡盈。", "浩歌因起舞，月到紙窗明。"]'),
('878e5eab-2131-49e5-ac7b-3ac1f2c5760a','戊子元日','徐瑞','宋','宋诗','song-poetry','','[]','歲歲春風面，年年山澤儒。',48,'全唐诗/poet.song.248000.json','["歲歲春風面，年年山澤儒。", "不知老將至，但有醉如愚。", "殘雪明岡阜，新晴樂鳥烏。", "身安即如願，何必問清湖。"]'),
('7f61347f-9b8f-41a2-b14e-b851c253ed79','雨中對酴醿','徐瑞','宋','宋诗','song-poetry','','[]','隠隠滃綠霧，盈盈積玉塵。',48,'全唐诗/poet.song.248000.json','["隠隠滃綠霧，盈盈積玉塵。", "濃香欲醉客，妙質不爭春。", "已是園林晚，那堪風雨頻。", "先生如有素，終日澹相親。"]'),
('6881c068-f753-42f4-9231-6e05b80bf86b','讀畫史','徐瑞','宋','宋诗','song-poetry','','[]','子敬因成駮，曹興偶畫蠅。',48,'全唐诗/poet.song.248000.json','["子敬因成駮，曹興偶畫蠅。", "初非有意作，竟以絕倫稱。", "鑄錯吾何恨，求全古所懲。", "中年思爛熟，巧力不須矜。"]'),
('b7b88a21-7a1d-47f7-857e-9e13193d50d6','題王朝英修竹齋','徐瑞','宋','宋诗','song-poetry','','[]','文章虎豹皮，標格雪霜枝。',48,'全唐诗/poet.song.248000.json','["文章虎豹皮，標格雪霜枝。", "孤立天所賦，一清人得知。", "勿論千戶等，可忍十年饑。", "會得箇中趣，何須汗漫期。"]'),
('da8e5a28-a5bb-4158-a00a-f5efc6697e09','與陳善從','徐瑞','宋','宋诗','song-poetry','','[]','出門小天下，知子欲昌詩。',48,'全唐诗/poet.song.248000.json','["出門小天下，知子欲昌詩。", "廬阜孤雲眼，芝山夜雨思。", "勿輕千里別，動是隔年期。", "萬一踰淮去，毋忘橘頌詞。"]'),
('bf12bfe8-6d64-4634-a99a-8cc5b09b329a','庚寅正月十六携家入山大雪彌旬止既月叔祖東綠翁以那知風雨夜復此對床眠分韻瑞得那眠字  其一','徐瑞','宋','宋诗','song-poetry','','[]','辟俗過逢少，離居感慨多。',48,'全唐诗/poet.song.248000.json','["辟俗過逢少，離居感慨多。", "豈伊泉石勝，奈此簡書何。", "風雪日如此，乾坤理則那。", "鄰翁能貰酒，一笑且酣歌。"]'),
('5c801e30-a940-40dd-b3c9-32c255262f71','庚寅正月十六携家入山大雪彌旬止既月叔祖東綠翁以那知風雨夜復此對床眠分韻瑞得那眠字  其二','徐瑞','宋','宋诗','song-poetry','','[]','骨肉終青眼，一林有素緣。',48,'全唐诗/poet.song.248000.json','["骨肉終青眼，一林有素緣。", "偶來成許日，此聚豈非天。", "悟解由災疾，遲留費歲年。", "東風方作惡，萬事付佳眠。"]'),
('084f5c74-2459-44ad-a767-4f7f7fa45ec5','夏五有旨徙豪右郡邑以吾家充數與章正卿同泊舟琵琶洲下','徐瑞','宋','宋诗','song-poetry','','[]','去國羈懷惡，開帆眼界新。',48,'全唐诗/poet.song.248000.json','["去國羈懷惡，開帆眼界新。", "同爲萬里客，猶是一鄉人。", "浪說王孫富，誰憐郭解貧。", "江妃應笑我，從此素衣塵。"]'),
('dfaef9f9-9bd7-4a77-bf92-738664c3e593','故友湯景文別六年乃十月廿一尋我松下臨別見贈次韻奉答','徐瑞','宋','宋诗','song-poetry','','[]','占氣頻翹首，青牛忽度關。',48,'全唐诗/poet.song.248000.json','["占氣頻翹首，青牛忽度關。", "相看雙眼碧，劇論寸心丹。", "時俗容遲鈍，交情見往還。", "盟言天爲聽，萬一莫辭難。"]'),
('66dd7206-9e7a-490e-b754-f4737a49be08','次韻景文社屋留題','徐瑞','宋','宋诗','song-poetry','','[]','四海誰知己，江濤正渺然。',48,'全唐诗/poet.song.248000.json','["四海誰知己，江濤正渺然。", "山林聊偃息，歲月易流連。", "行李清霜曉，荒祠落木天。", "留題不盡意，感激尚君賢。"]'),
('edf3b1ff-6a7c-4ba0-8687-575dd669a9d3','馬可卿棄家學道衲衣椎髻飄然有物外之思賦二詩爲贈  其一','徐瑞','宋','宋诗','song-poetry','','[]','去去休驚俗，循循且任真。',48,'全唐诗/poet.song.248000.json','["去去休驚俗，循循且任真。", "端能一宿覺，不負百年身。", "有種穀斯熟，深根樹自春。", "向來陳處士，還带華陽巾。"]'),
('e7196f13-b757-495b-9fa5-debb8e9a2f18','馬可卿棄家學道衲衣椎髻飄然有物外之思賦二詩爲贈  其二','徐瑞','宋','宋诗','song-poetry','','[]','我祖徐從事，君家馬自然。',48,'全唐诗/poet.song.248000.json','["我祖徐從事，君家馬自然。", "何曾絕倫誼，皆得列神仙。", "四百金丹字，參同鼎器篇。", "能通言外意，即此是單傳。"]'),
('214e3723-9e94-4fb6-9199-a720b903eb71','次韻芳洲見寄','徐瑞','宋','宋诗','song-poetry','','[]','地偏寡迎送，書至慰蹉跎。',48,'全唐诗/poet.song.248000.json','["地偏寡迎送，書至慰蹉跎。", "此世知音少，吾生可悔多。", "虛懷忘寵辱，遇物任誰何。", "未了山中約，期君難重過。"]'),
('b6803023-6aef-4598-be05-5cb992e7576f','次仲退賦牡丹韻詩中有欲將傾國色故惱在家禪之句','徐瑞','宋','宋诗','song-poetry','','[]','雨餘春意足，睡起曉光懸。',48,'全唐诗/poet.song.248000.json','["雨餘春意足，睡起曉光懸。", "衆卉自開落，吾心無醜妍。", "掃空方是道，下語已非禪。", "隠几翛然久，疏林起淡烟。"]'),
('89cf58ca-ccba-42bf-9b4c-0e92aa042b62','吳義甫號宜山以星躔推賤庚并遺以詩次韻奉謝','徐瑞','宋','宋诗','song-poetry','','[]','爲愛山宜隠，從教世莫知。',48,'全唐诗/poet.song.248000.json','["爲愛山宜隠，從教世莫知。", "虛心觀象緯，戲墨出蛟螭。", "詩卷今餘事，丹爐彼一時。", "宜山子姚子，千載共風期。"]'),
('0b6ed83e-6175-4be7-932e-86a0314b7914','十月乙酉西山訖事悼亡二首  其一','徐瑞','宋','宋诗','song-poetry','','[]','渺渺箜篌夢，茫茫石鏡緣。',48,'全唐诗/poet.song.248000.json','["渺渺箜篌夢，茫茫石鏡緣。", "斷絃終莫續，浮沫更堪憐。", "濕土新阡雨，啼鴉老樹煙。", "一聲鄰笛起，凄咽泪如泉。"]'),
('c84214c0-b565-481d-852f-a086e5dac39c','十月乙酉西山訖事悼亡二首  其二','徐瑞','宋','宋诗','song-poetry','','[]','我已空諸幻，君今斷後緣。',48,'全唐诗/poet.song.248000.json','["我已空諸幻，君今斷後緣。", "圓明應頓悟，成壞不須憐。", "玉宇行孤月，冰溪破冥烟。", "兒曹修菲薦，再拜酹寒泉。"]'),
('f2c42f8c-0e2e-4fef-9c7d-0ff41ecb8c94','送姚聖可歸旴江  其一','徐瑞','宋','宋诗','song-poetry','','[]','識面三年久，論心此日同。',48,'全唐诗/poet.song.248000.json','["識面三年久，論心此日同。", "相從方款款，索去又匆匆。", "宇宙塵機息，江湖老眼空。", "南枝春信早，歸路載東風。"]'),
('179522cb-44b9-4067-8833-02331264da97','送姚聖可歸旴江  其二','徐瑞','宋','宋诗','song-poetry','','[]','未了區中事，先留方外盟。',48,'全唐诗/poet.song.248000.json','["未了區中事，先留方外盟。", "仙才雖有數，大器豈無成。", "白髪高堂夢，青山故國情。", "君歸相慰藉，未及水初生。"]'),
('73aa4592-7ff8-4b7d-89b2-8367d53a4943','次韻東皋雨後行','徐瑞','宋','宋诗','song-poetry','','[]','久雨書闈坐，初晴竹伴行。',48,'全唐诗/poet.song.248000.json','["久雨書闈坐，初晴竹伴行。", "遠林更舊綠，流水带新聲。", "隨境皆天趣，無心任世情。", "芒田公獨樂，吟嘯了浮生。"]'),
('7b3bf1e4-e093-41cf-8747-343f09d30765','梅山周公挽章  其一','徐瑞','宋','宋诗','song-poetry','','[]','才力千鈞弩，襟期百尺樓。',48,'全唐诗/poet.song.248000.json','["才力千鈞弩，襟期百尺樓。", "吾生能幾見，異世有同流。", "起起悲前夢，堂堂閟一丘。", "哀榮動州里，外此復何求。"]'),
('f840be8c-0f8d-4c6f-87da-5be67e995310','梅山周公挽章  其二','徐瑞','宋','宋诗','song-poetry','','[]','東閣游從久，西州慟哭頻。',48,'全唐诗/poet.song.248000.json','["東閣游從久，西州慟哭頻。", "感君敦古誼，待我異他人。", "對酒言猶在，看山迹已陳。", "惟應舊賓客，相對一沾巾。"]'),
('463da222-a87d-4c6d-9a78-89abf094d925','寄周南翁用月灣寒食韻','徐瑞','宋','宋诗','song-poetry','','[]','獨夢雲千里，清愁雨一林。',48,'全唐诗/poet.song.248000.json','["獨夢雲千里，清愁雨一林。", "江山空有約，桃李易成陰。", "自是乖幽賞，何由話苦心。", "興來當逕造，剪燭夜堂深。"]'),
('2d0d3805-4aad-4d0a-acb7-1bb5909371f3','夏日讀陶韋詩偶成','徐瑞','宋','宋诗','song-poetry','','[]','詩道貴和平，由來寫性情。',48,'全唐诗/poet.song.248000.json','["詩道貴和平，由來寫性情。", "要知衝口出，絕勝撚髭成。", "理到辭須達，神超韻自清。", "無人融此趣，庭戶綠陰生。"]'),
('5e68e448-f1d8-44bc-8923-f0b253678ac9','吳長裕惠詩次韻爲贈','徐瑞','宋','宋诗','song-poetry','','[]','此士睽違久，流年倏忽更。',48,'全唐诗/poet.song.248000.json','["此士睽違久，流年倏忽更。", "詞章如水進，談笑喜風生。", "無以小害大，當期實勝名。", "傳家有師法，晦木定春榮。"]'),
('f9516686-185b-4799-9d4d-005e1e9484eb','李田道中','徐瑞','宋','宋诗','song-poetry','','[]','老樹圍修竹，清流浸白沙。',48,'全唐诗/poet.song.248000.json','["老樹圍修竹，清流浸白沙。", "沿山石磊磈，隔岸路丫叉。", "漸漸鄉音別，迢迢去意賒。", "瀹茶誰氏女，鬒髪墮烏鴉。"]'),
('0b5f906f-35c2-45e5-a8d4-4a2a3abdc898','除夜哭仲孫概  其一','徐瑞','宋','宋诗','song-poetry','','[]','階庭皆秀發，念汝獨敦龐。',48,'全唐诗/poet.song.248000.json','["階庭皆秀發，念汝獨敦龐。", "處事怯藏勇，臨機智若戇。", "痛渠二豎惡，何日片心降。", "硯席凝塵滿，依然在北窗。"]'),
('ab637413-1417-4d8e-a7c6-0a128812436a','除夜哭仲孫概  其二','徐瑞','宋','宋诗','song-poetry','','[]','我老那堪哭，吞聲泪一襟。',48,'全唐诗/poet.song.248000.json','["我老那堪哭，吞聲泪一襟。", "應門差慰眼，伏枕獨傷心。", "白璧歸黄壤，孤墳寄古林。", "凄凉重泣痛，臨絕有遺音。"]'),
('14ce0c53-fad9-4b95-94f4-b2efaa2d95f3','次劉東仲見寄咏','徐瑞','宋','宋诗','song-poetry','','[]','丰姿明玉樹，清論瀉秋泉。',48,'全唐诗/poet.song.248000.json','["丰姿明玉樹，清論瀉秋泉。", "霧豹文何澤，風鸞意自仙。", "超然由靜悟，妙處可言傳。", "倘遂卜鄰願，游從不計年。"]'),
('5b59d7aa-4b49-42db-979a-7509080e502c','用月灣咏寄題江儀仲心遠堂','徐瑞','宋','宋诗','song-poetry','','[]','湛湛秋潭靜，沉沉夜璧光。',48,'全唐诗/poet.song.248000.json','["湛湛秋潭靜，沉沉夜璧光。", "歛之不盈握，舒則可包荒。", "今古事無盡，乾坤夢正長。", "爐香清晝永，物我兩俱忘。"]'),
('b738420a-eea5-4d14-bff2-a2f5fd2a0c7b','歸來','徐瑞','宋','宋诗','song-poetry','','[]','歸來便覺此身尊，傲世猶嫌習氣存。',64,'全唐诗/poet.song.248000.json','["歸來便覺此身尊，傲世猶嫌習氣存。", "已是半生走風雨，但持一笑信乾坤。", "貪閒且復逃空谷，自衒終羞倚市門。", "庭院綠陰生午寂，坐聽禽語對清樽。"]'),
('52100edc-2fbb-41d7-871c-75e1d0744332','東綠叔祖得園池之勝於萬山深處將拔宅而居焉以詩奉餞','徐瑞','宋','宋诗','song-poetry','','[]','兩僮自足負琴書，載具何勞遠借車。',64,'全唐诗/poet.song.248000.json','["兩僮自足負琴書，載具何勞遠借車。", "客至未妨投轄飲，地荒正好带經鉏。", "欲從隠者歸盤谷，尚念先人有敝廬。", "擇勝懷居竟誰是，定知明哲笑迂疏。"]'),
('5861a649-fbb1-4c64-a2b7-e9f0727435b0','東綠翁既居山中而瑞方葺敝廬再用前韻','徐瑞','宋','宋诗','song-poetry','','[]','見說移居只載書，高人從此可懸車。',64,'全唐诗/poet.song.248000.json','["見說移居只載書，高人從此可懸車。", "看松北崦風吹面，種豆南山月滿鉏。", "拙計不能爭子所，癡心尚自愛吾廬。", "辟人辟世將焉擇，獨立西風鬢影疏。"]'),
('fd704724-5218-45a8-a3c5-8bfb4a95ea06','留汪子明','徐瑞','宋','宋诗','song-poetry','','[]','美人渺渺隔秋水，六年不見心茫茫。',64,'全唐诗/poet.song.248000.json','["美人渺渺隔秋水，六年不見心茫茫。", "麥昂黍低各自媚，鶴長鳬短庸何傷。", "荷鉏未厭素業在，讀書從來真味長。", "是間偪仄不稱意，待晴携酒登重岡。"]'),
('693fb224-6126-4e90-a499-eeae9a79ba5e','次韻寄題李氏月心精舍','徐瑞','宋','宋诗','song-poetry','','[]','坎陽爲心亦爲月，妙質一點何玲瓏。',64,'全唐诗/poet.song.248000.json','["坎陽爲心亦爲月，妙質一點何玲瓏。", "君看靈光湛止水，孰與明鏡行秋空。", "萬古娟娟不改色，百年忽忽俱成翁。", "盈虛如彼莫消長，試參此語將無同。"]'),
('1a8a32b9-4ec6-45b9-827c-2ff212bd1705','次韻陳心田郊居即事二首  其一','徐瑞','宋','宋诗','song-poetry','','[]','想見從來種種迂，讀書採藥灌園蔬。',64,'全唐诗/poet.song.248000.json','["想見從來種種迂，讀書採藥灌園蔬。", "看山不厭風期別，與世相忘機事疏。", "正自未妨犀首飲，足知不作子公書。", "詩名莫落江湖去，怕有人來畫子廬。"]'),
('08b12916-3ba6-4552-8789-bd229af6c234','次韻陳心田郊居即事二首  其二','徐瑞','宋','宋诗','song-poetry','','[]','五老亭亭翠塞門，煙霏雲氣濕前軒。',64,'全唐诗/poet.song.248000.json','["五老亭亭翠塞門，煙霏雲氣濕前軒。", "浮華安有千年寶，至潔何如一尺渾。", "曉瀑分寒歸茗椀，春江瀉綠入藤樽。", "君詩已是肱三折，爲我探囊試合昏。"]'),
('62d66662-58f2-448e-a724-e551c1b782d6','用仲退韻別周南翁','徐瑞','宋','宋诗','song-poetry','','[]','薄俗難諧祇自知，百年幾見費心思。',64,'全唐诗/poet.song.248000.json','["薄俗難諧祇自知，百年幾見費心思。", "平生鮑叔深憐我，後代揚雲不並時。", "春雨情懷惟有酒，男兒歲月但供詩。", "汀洲草長東風軟，一笑旗亭又語離。"]'),
('5f7e7c6e-2f7f-41ac-b40c-64e5b1968201','癸巳二月寓城與趙希文','徐瑞','宋','宋诗','song-poetry','','[]','城郭春深午夢醒，覺來玄思獨冥冥。',64,'全唐诗/poet.song.248000.json','["城郭春深午夢醒，覺來玄思獨冥冥。", "靜中自笑渠非我，醉裏渾忘影答形。", "有客不傳皇極數，何人獨愛太玄經。", "古今此意誰能會，雨暗長堤草樹青。"]'),
('f981c3c3-de1e-4bb7-8891-7f342f00434a','壁侍者來訪作此贈之','徐瑞','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u957f\u6c5f"]','俗論卑卑不足聞，相從松下慰離群。',64,'全唐诗/poet.song.248000.json','["俗論卑卑不足聞，相從松下慰離群。", "喜師一吸西江水，許我平分華嶽雲。", "更向鋒前來妙悟，莫于紙上泥陳文。", "純陽石薜黄龍老，肥瘦何曾彼此分。"]'),
('df76c67f-31e2-4eaf-92ae-f6804f50bab0','寄芳洲先生','徐瑞','宋','宋诗','song-poetry','','[]','秋入郊原四望空，石梁老樹立西風。',64,'全唐诗/poet.song.248000.json','["秋入郊原四望空，石梁老樹立西風。", "文章子不減班掾，丘壑吾能過庾公。", "池上紛紛成底事，尊前兀兀有奇功。", "山中芋栗今朝熟，萬一尋盟榾柮紅。"]'),
('12ce4430-f69b-478b-af55-74100fd3230e','用前韻寄仲退','徐瑞','宋','宋诗','song-poetry','','[]','虛堂宴坐萬緣空，疏竹泠泠度晚風。',64,'全唐诗/poet.song.248000.json','["虛堂宴坐萬緣空，疏竹泠泠度晚風。", "政自悠悠隨世運，無論憒憒到天公。", "病來茗枕成奇祟，老去蒲團策雋功。", "忽憶樂平吳直學，八年不共地爐紅。"]'),
('699a2b34-e2f8-431f-964f-66d04127132e','芳洲寄示和章且及方外之學再疊奉謝','徐瑞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','前修零落典刑空，堆筆須君振古風。',64,'全唐诗/poet.song.248000.json','["前修零落典刑空，堆筆須君振古風。", "敢意嚴詩編杜集，但希顔詠黜山公。", "區中隨順何妨道，物外佯狂更有功。", "安得相携登岱嶽，天門夜看海濤紅。"]'),
('75097cff-0a14-441c-90d3-2625e1fbf87a','三月廿夜同徐月齋讀參同契次所贈詩韻以謝','徐瑞','宋','宋诗','song-poetry','','[]','天高地下物林林，生化無過陽與陰。',64,'全唐诗/poet.song.248000.json','["天高地下物林林，生化無過陽與陰。", "誰向一中窺竅妙，君于靜處見幾深。", "蟾烏有象明生鏡，桐梓何情音在琴。", "正好小留論此事，可堪杜宇促歸吟。"]'),
('31d1f23e-7cb2-442e-bfcc-adfaaa81dccb','對酒','徐瑞','宋','宋诗','song-poetry','','[]','坎止流行信此身，只憑詩酒過殘春。',64,'全唐诗/poet.song.248000.json','["坎止流行信此身，只憑詩酒過殘春。", "地偏自覺日成趣，道在何妨歲食貧。", "且養金丹娛晚境，難將白髪事時人。", "但餘未了名山債，竹杖芒鞋入夢頻。"]'),
('6b654107-ff42-4ab9-8968-47bd7323bae7','余自戊子至丁酉十年之間詩不及百首而困窮流落之狀歷歷可見雖然政使歲得百首亦不過流連光景而已焉攸用感嘆之餘賦此自警','徐瑞','宋','宋诗','song-poetry','','[]','吾生汩汩何所就，祇送流光添鬢絲。',64,'全唐诗/poet.song.248000.json','["吾生汩汩何所就，祇送流光添鬢絲。", "起尋諸老已半鬼，回首十年無百詩。", "刻意文章終害道，無心世路任多岐。", "便須擘畫三千歲，不住青城即武夷。"]'),
('37738e78-80bb-4b0e-aacc-726e71ca0c57','寄宗玉弟','徐瑞','宋','宋诗','song-poetry','','[]','日長獨坐耿相思，每報平安慰我饑。',64,'全唐诗/poet.song.248000.json','["日長獨坐耿相思，每報平安慰我饑。", "舉動豈知遭齒舌，送迎誰念用符移。", "轉丸鳴鏑應無滯，絅錦弢旌未是癡。", "更著加餐題紙背，晚成在子莫憂遲。"]'),
('af151161-dc91-42c6-91f9-61a3293fefa0','偶題','徐瑞','宋','宋诗','song-poetry','','[]','陶公恒得法外意，張顛獨悟書中神。',64,'全唐诗/poet.song.248000.json','["陶公恒得法外意，張顛獨悟書中神。", "口耳不到方是妙，言動可擬皆非真。", "寒泉泠泠出空谷，幽鳥亹亹鳴陽春。", "政索解人不可得，舉似俗子翻成嗔。"]'),
('35da5017-6208-4558-bc3d-1bea2c0fb007','余與仲退讀書山間壬午至戊子無一日相捨己丑仲退去此余亦連年憂患回首已九寒暑念此樂不可復得感慨不已作字寄仲退覬其蚤賦歸來也','徐瑞','宋','宋诗','song-poetry','','[]','獨聽松風度九夏，兩鬢無情生二毛。',64,'全唐诗/poet.song.248000.json','["獨聽松風度九夏，兩鬢無情生二毛。", "渠儂翰墨流聲遠，老我山林畜眼高。", "往日相從不知樂，只今說夢竟徒勞。", "男兒肯受人拘束，相見頻頻賦大刀。"]'),
('ab6b65d5-7e1f-4132-9c53-db3a2d289a6a','自省','徐瑞','宋','宋诗','song-poetry','','[]','閉閣焚香一欠伸，晴窗如鏡暖如春。',64,'全唐诗/poet.song.248000.json','["閉閣焚香一欠伸，晴窗如鏡暖如春。", "平生自有會心處，後世豈無知我人。", "漫註蟲魚消白日，莫緣蠻觸喪天真。", "客來指點牆東柏，雪壓風欺色轉新。"]'),
('0eac5d15-3e39-42f6-b115-8e0e91ba118f','仲退示芳洲閒居律詩三首并示和章次韻寄芳洲一笑并簡仲退  其一','徐瑞','宋','宋诗','song-poetry','','[]','契闊難逢笑口開，溪雲山雨首頻回。',64,'全唐诗/poet.song.248000.json','["契闊難逢笑口開，溪雲山雨首頻回。", "未能千橘爲身計，尚笑三槐待子栽。", "我道從來高勇退，君詩况自耻嗟來。", "有親可養人生樂，拚取餘年學老萊。"]'),
('b036b806-b9b8-4e0d-a9d8-b66a43ba8822','仲退示芳洲閒居律詩三首并示和章次韻寄芳洲一笑并簡仲退  其二','徐瑞','宋','宋诗','song-poetry','','[]','老子文章興尚狂，看花可復夢名場。',64,'全唐诗/poet.song.248000.json','["老子文章興尚狂，看花可復夢名場。", "誰憐用意平生苦，欲俟知音來世長。", "郢俗但能聽下里，騷人更待賦高唐。", "年來頗欲焚吾硯，蓑笠田間百念忘。"]'),
('aa108121-449c-4199-992e-05af25b7f434','仲退示芳洲閒居律詩三首并示和章次韻寄芳洲一笑并簡仲退  其三','徐瑞','宋','宋诗','song-poetry','','[]','翟公莫厭雀羅門，杜老甘居獨樹村。',64,'全唐诗/poet.song.248000.json','["翟公莫厭雀羅門，杜老甘居獨樹村。", "諤諤固應賢唯唯，昭昭元不似昏昏。", "窮居有分行吾意，君子觀人論所存。", "未必鍾期曠千載，興來一再撫桐孫。"]'),
('3fd598e0-e2a1-4b01-83c2-ffe5f6f1c7a8','讀仲退和胡秀才詩有感斯文用韻','徐瑞','宋','宋诗','song-poetry','','[]','文章聖處無誰語，獨立蒼茫祇屢臏。',64,'全唐诗/poet.song.248000.json','["文章聖處無誰語，獨立蒼茫祇屢臏。", "從渠高眼空四海，自古名家能幾人。", "愛烏怒蟹言何淺，畫虎雕龍技漫新。", "吾道澹成終雋永，莫矜盛氣怨私貧。"]'),
('d1031e2e-7753-4ca4-b149-421e1fed4ec1','次韻寄題嚴氏尋古齋','徐瑞','宋','宋诗','song-poetry','','[]','馬圖龜畫未是易，龍文鳥章豈其書。',64,'全唐诗/poet.song.248000.json','["馬圖龜畫未是易，龍文鳥章豈其書。", "能窮有象有數外，始識無聲無臭初。", "身從浩劫得所賦，神遊太虛以爲居。", "吾人尋古儻悟此，以後觀今非古與。"]'),
('6174e5f7-bc75-4877-bb74-03d1246b1687','次韻金壁夫見寄','徐瑞','宋','宋诗','song-poetry','','[]','萬緣勘破等飛煙，習氣消除得聖顛。',64,'全唐诗/poet.song.248000.json','["萬緣勘破等飛煙，習氣消除得聖顛。", "撲滿無情又佚老，鴟夷有味可留年。", "美人渺渺空勤夢，吾道悠悠莫問天。", "上界從來足官府，山林自好更求仙。"]'),
('4964d555-9599-427e-a640-25c77f8e635a','二月廿九日收宗玉弟京口書還家有日喜而賦詩','徐瑞','宋','宋诗','song-poetry','','[]','半歲無書界我胸，短蓬念汝過殘冬。',64,'全唐诗/poet.song.248000.json','["半歲無書界我胸，短蓬念汝過殘冬。", "官情但可京口酒，客夢應隨浮玉鐘。", "棄縱向來緣底事，妍粧今日爲誰容。", "書來賸喜歸期近，伴我清吟倚老松。"]'),
('1d6189ef-fb6f-41b5-baa5-c9035233bca1','壬寅和謝拙逸寄芳洲韻','徐瑞','宋','宋诗','song-poetry','','[]','塵埃野馬謾勞形，遠想高標愧此生。',64,'全唐诗/poet.song.248000.json','["塵埃野馬謾勞形，遠想高標愧此生。", "已許過從陪杖屨，敢辭來往涉途程。", "幔亭山色長如畫，破衲秋風自有情。", "更待焚香參太極，朱絃端爲發奇聲。"]'),
('3a731644-5313-45bf-9115-6b3bd8c2c72c','正月十五日月灣偕胡茂元來訪別後用月灣韻寄贈茂元','徐瑞','宋','宋诗','song-poetry','','[]','敲門驚怪有此客，清似金莖秋露盤。',64,'全唐诗/poet.song.248000.json','["敲門驚怪有此客，清似金莖秋露盤。", "名驥已超千里疾，老松甘卧故山寒。", "共商今古須臻極，遠遡風騷不作難。", "從此頻頻相料理，案頭苜蓿對闌干。"]'),
('1fc0e4b6-5f2a-4834-9ce2-7ab7829d6c40','寄徐逢原求墨','徐瑞','宋','宋诗','song-poetry','','[]','北李骨朽呼不起，老石珍藏癡可憐。',64,'全唐诗/poet.song.248000.json','["北李骨朽呼不起，老石珍藏癡可憐。", "松身鏡面徒外美，犀紋玉質知誰傳。", "古今賞覽那復有，舉世繆幻何由湔。", "一螺點漆倘寄我，會見枯筆生春煙。"]'),
('c6d7b53e-63b3-4294-a1e0-df26aedade17','送表弟王復翁赴武陵教諭','徐瑞','宋','宋诗','song-poetry','','[]','漢朝最貴文學掾，況遇明時早及瓜。',64,'全唐诗/poet.song.248000.json','["漢朝最貴文學掾，況遇明時早及瓜。", "鄉國幾年工取友，詩書累世克承家。", "斜飛聊展天南翼，逸興應隨海上槎。", "聞說秦人遺跡在，更尋漁父問桃花。"]'),
('2ddec953-decb-4b9d-92c3-6a627ef21454','胡和卿用所贈王復翁韻見寄疊韻奉謝','徐瑞','宋','宋诗','song-poetry','','[]','世味居然如嚼蠟，貪閒猶愛故丘瓜。',64,'全唐诗/poet.song.248000.json','["世味居然如嚼蠟，貪閒猶愛故丘瓜。", "寸心自欲期千載，一理端能貫百家。", "爲山功夫在進簣，窮源消息問乘槎。", "此去相從須有日，裂牋聊當寄梅花。"]'),
('6594ac0f-7ba9-41f1-ae81-a21c72585b01','送從祖還黄州桃花鎮寓居','徐瑞','宋','宋诗','song-poetry','','[]','禮服悠悠歲月深，歸來城郭豈堪尋。',64,'全唐诗/poet.song.248000.json','["禮服悠悠歲月深，歸來城郭豈堪尋。", "葬防不背先師訓，居潁能知前輩心。", "古驛桃花勞遠夢，征途柳色動新吟。", "秋風儻有南飛雁，莫惜頻頻一寄音。"]'),
('c6975592-e1e4-4d31-9999-35cc900f103b','仲春留周氏館中與仲退怡如劇論旬日而後返二君寄詩次韻爲謝','徐瑞','宋','宋诗','song-poetry','','[]','番君遠韻衆辟易，崖仙清致莫誰何。',64,'全唐诗/poet.song.248000.json','["番君遠韻衆辟易，崖仙清致莫誰何。", "二士共談敦古誼，一夫獨醉許高歌。", "人疑桑下留何久，我喜鋒前悟已多。", "會見漁樵成保社，典衣先自買青蓑。"]'),
('0074dcd3-6eed-4008-8e53-894c1aa83ce0','從弟楚玉來言將有湘陰之役蘭玉見寓衡陽甚適求詩送行爲賦長句','徐瑞','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽崚嶒太古色，青湘窈窕千尺深。',64,'全唐诗/poet.song.248000.json','["南嶽崚嶒太古色，青湘窈窕千尺深。", "山川絕勝宜嘉客，兄弟相望愜素心。", "共看驊騮誇汗血，從知朝市遠雲林。", "高堂白髪能無念，可是朝朝候鵲音。"]'),
('47af60e7-93a1-40cb-a3cd-6147c688598d','用仲退韻寄芳洲','徐瑞','宋','宋诗','song-poetry','','[]','早年厭俗不免俗，老去求閒未遂閒。',64,'全唐诗/poet.song.248000.json','["早年厭俗不免俗，老去求閒未遂閒。", "學道已輸先得髓，讀書空媿僅窺班。", "逍遥我欲遊塵外，屈曲渠能自世間。", "目斷漢廬煙樹老，悠悠白鳥獨飛還。"]'),
('67fa9bd7-a969-46d6-b3ce-1ff957a5978e','客中清明','徐瑞','宋','宋诗','song-poetry','','[]','光陰迅速一百六，老境侵尋五十三。',64,'全唐诗/poet.song.248000.json','["光陰迅速一百六，老境侵尋五十三。", "千里懷人黯風雨，五更歸夢到松柟。", "丹爐火足心兵息，茗椀香濃舌本甘。", "次第盡償芒竹債，結茅歸老此山南。"]'),
('afd191a4-0068-4bf7-ad3a-f93aab27eb20','次韻仲退木犀一首','徐瑞','宋','宋诗','song-poetry','','[]','門前老樹繁秋英，濃香醉客我獨醒。',64,'全唐诗/poet.song.248000.json','["門前老樹繁秋英，濃香醉客我獨醒。", "空山無人境寂寂，蕭齋如水風冥冥。", "清標自是欠花譜，遠韻差堪著酒經。", "君家剛猛兩荒幻，且挹危露培修齡。"]'),
('a8d6173e-68b1-4e18-b663-e8a0652c34e8','吾族盤石將挾堪輿家出遊索詩送行','徐瑞','宋','宋诗','song-poetry','','[]','天星墜地化爲石，盤石即是星之精。',64,'全唐诗/poet.song.248000.json','["天星墜地化爲石，盤石即是星之精。", "觀天必識經緯象，相地始知流峙情。", "豹林將軍累世顯，龍岡文章千載名。", "古人妙中非浪漫，發抉幽微在此行。"]'),
('5c517364-6ea0-4a38-9ef7-d9108db0ef34','春日感興有懷芳洲','徐瑞','宋','宋诗','song-poetry','','[]','老去空驚歲月遒，桑榆雖晚尚堪收。',64,'全唐诗/poet.song.248000.json','["老去空驚歲月遒，桑榆雖晚尚堪收。", "鬢霜任自桃花笑，客意難憑燕語留。", "勝地有緣頻入夢，清吟無興獨登樓。", "故人家住滄洲上，幾夜相思欲泛舟。"]'),
('e54a0bad-0e8d-48dc-ae1c-bad363c5957e','劉元輔寄詠史詩六十首賦此爲謝','徐瑞','宋','宋诗','song-poetry','','[]','永嘉諸老不可作，史傳紛紜孰與評。',64,'全唐诗/poet.song.248000.json','["永嘉諸老不可作，史傳紛紜孰與評。", "一字不輕嚴衮鉞，千年如見審權衡。", "常憂此道無人識，忽得公詩老眼明。", "雪手焚香三讀罷，小樓坐對晚山橫。"]'),
('ac84ea5d-e79b-4ccf-b01d-b44075f95971','贈別彭東皋','徐瑞','宋','宋诗','song-poetry','','[]','芝山相識廿年前，我齒如冰子鬢玄。',64,'全唐诗/poet.song.248000.json','["芝山相識廿年前，我齒如冰子鬢玄。", "顔貌頓驚俱醜老，光陰自嘆祇流連。", "近來酒渴應剛制，此去詩篇莫浪傳。", "語別有期頻作惡，預憐清夢繞新田。"]'),
('5beb1935-db45-414f-82bb-edc8c17da1cb','次韻題南翁悠然閣','徐瑞','宋','宋诗','song-poetry','','[]','去家幾度憶瓜丘，付與閒人一壑秋。',64,'全唐诗/poet.song.248000.json','["去家幾度憶瓜丘，付與閒人一壑秋。", "林下定知無俗駕，室中應自有天游。", "幽懷時撫竹根枕，清賞堪浮蓮葉舟。", "夜直玉堂明月冷，迴光還是照高樓。"]'),
('fbe3c3f6-2c5e-4925-907e-3b7302acd47a','題節婦馮氏傳後用南翁韻','徐瑞','宋','宋诗','song-poetry','','[]','夫征婦孕判居行，夫沒兒存婦節清。',64,'全唐诗/poet.song.248000.json','["夫征婦孕判居行，夫沒兒存婦節清。", "不背所天終此義，信知有欲甚于生。", "芳名真足留千載，百僞無如仗一誠。", "定謚何人敢當筆，春秋萬古自昭明。"]'),
('7bfa8ff1-7dac-4b9e-8c6b-0010322e1c9d','月灣約遊鵝塘不果再約送南翁北上共了廬阜之債以詩訂盟','徐瑞','宋','宋诗','song-poetry','','[]','鵝塘阻趁登山屐，廬阜端隨下水船。',64,'全唐诗/poet.song.248000.json','["鵝塘阻趁登山屐，廬阜端隨下水船。", "況是故人當送遠，不乘清興待何年。", "英雄埋沒龍長卧，道學榛蕪鹿自眠。", "訪古歸來春意動，倚峰要了看山緣。"]'),
('ceab4c06-fa18-4e56-860e-ec0989017b64','送南翁待制北上','徐瑞','宋','宋诗','song-poetry','','[]','生來畏別不堪聞，十四年中三送君。',64,'全唐诗/poet.song.248000.json','["生來畏別不堪聞，十四年中三送君。", "挂席壓平彭蠡浪，載家喜見太行雲。", "對揚入掌絲綸寵，紀頌行看金石文。", "猶有鵝塘遺意在，一麾須早乞江濆。"]'),
('2ef11598-f1ab-4144-8001-aa7704d29106','次韻月灣午坐偶成','徐瑞','宋','宋诗','song-poetry','','[]','年來與世亦嬰兒，衆欲紛紛看朵頤。',64,'全唐诗/poet.song.248000.json','["年來與世亦嬰兒，衆欲紛紛看朵頤。", "簡策祇留遺事在，英雄空有大名垂。", "斵輪老去誰堪付，彈鋏歸來未覺遲。", "少約林泉今白髪，不償素願待何時。"]'),
('fe2b4315-5d31-4345-af91-2ac64b280c64','月灣闢地山中誅茅歸隠怡如賦詩次韻贊决  其一','徐瑞','宋','宋诗','song-poetry','','[]','一去山中廿二年，重來有約竟茫然。',64,'全唐诗/poet.song.248000.json','["一去山中廿二年，重來有約竟茫然。", "窮居笑我頑同石，文事多君彩印椽。", "今日開山作宗祖，向來彈鋏等風煙。", "餘齡賸喜遊從樂，更結青烏白鶴緣。"]'),
('0f2bafe2-8323-4a21-a497-1a22de7eb19c','月灣闢地山中誅茅歸隠怡如賦詩次韻贊决  其二','徐瑞','宋','宋诗','song-poetry','','[]','作意歸來孰謂非，挹芳有地復何疑。',64,'全唐诗/poet.song.248000.json','["作意歸來孰謂非，挹芳有地復何疑。", "遲留固是全交道，勇退方知識事宜。", "尚用侍郎書戶契，肯求節度買山貲。", "風流莫遣諸兒覺，共被同行又一奇。"]'),
('b50c8443-0630-4284-a3bd-ad6c8edaf620','題周南甫草窗吟卷後','徐瑞','宋','宋诗','song-poetry','','[]','水中鹽味誰能識，鐸裏宮聲未易聽。',64,'全唐诗/poet.song.248000.json','["水中鹽味誰能識，鐸裏宮聲未易聽。", "正惜無人繼風雅，忽傳佳句到林坰。", "雲開灊岳撐千仞，春入雷江漲四溟。", "遥想清吟得天趣，窗前草色自青青。"]'),
('04727c94-3380-4fb5-8a4f-2ccdd3f140a3','許季高怡如相繼而逝仲退有詩悼之亦復次韻','徐瑞','宋','宋诗','song-poetry','','[]','鳴呼二子遂如此，里閈凄凉誰與歸。',64,'全唐诗/poet.song.248000.json','["鳴呼二子遂如此，里閈凄凉誰與歸。", "生養死藏情永痛，霤號野哭涕徒揮。", "久悲前輩存無幾，今嘆斯文事轉非。", "獨到青燈哦楚些，西風獵獵颭簾衣。"]'),
('fb897697-31b6-4607-971e-5e16636b2552','送凌霽雲赴餘姚州學正','徐瑞','宋','宋诗','song-poetry','','[]','天門振鐸聲彌遠，越上橫經任更專。',64,'全唐诗/poet.song.248000.json','["天門振鐸聲彌遠，越上橫經任更專。", "頗怪風雲紆宦轍，故因山水著名賢。", "圩田秋足先生飯，海月春浮坐客氈。", "聞有世南遺墨在，歸鴻儻一寄林泉。"]'),
('65258655-d444-43b8-bbc1-a858c8cd4c13','元日題仲退漫游四藁後','徐瑞','宋','宋诗','song-poetry','','[]','夫君汗漫路萬里，翰墨游戲詩百篇。',64,'全唐诗/poet.song.248000.json','["夫君汗漫路萬里，翰墨游戲詩百篇。", "高歌不覺屢擊節，畫寫似曾親執鞭。", "奇探馬遷作史意，老氣杜陵出峽年。", "何當囊筆撰杖屨，與君題徧名山川。"]'),
('670a0033-33af-4d79-a384-9b86d0385af0','次韻仲退元日  其一','徐瑞','宋','宋诗','song-poetry','','[]','松根坐穩逢元日，雲外詩來寄此翁。',64,'全唐诗/poet.song.248000.json','["松根坐穩逢元日，雲外詩來寄此翁。", "入眼辛盤春意綠，多情蜜炬曉光紅。", "兒孫拜舞歡聲洽，節物暄妍往日同。", "却憶少年觴柏酒，觥船到手吸長虹。"]'),
('511b3714-301f-467c-8939-23b5219fe17d','次韻仲退元日  其二','徐瑞','宋','宋诗','song-poetry','','[]','上元曾記昔年游，歌曲如山浩莫收。',64,'全唐诗/poet.song.248000.json','["上元曾記昔年游，歌曲如山浩莫收。", "公子喜陪蒼玉佩，佳人笑指水晶球。", "一天星斗飄仙樂，萬頃芙蓉簇彩樓。", "風雪與誰堪說夢，酒闌驚覺在吾州。"]'),
('36804e6f-9ba5-41bd-a1f4-0ef9d398a6a1','梅巖','徐瑞','宋','宋诗','song-poetry','','[]','不見此山四十載，巖石相看亦粲然。',64,'全唐诗/poet.song.248000.json','["不見此山四十載，巖石相看亦粲然。", "顧我丹心今不改，信渠鐵面晚猶堅。", "人生出處無非數，文運昌明自屬天。", "尚恨山靈知我淺，小樓呼酒對嬋娟。"]'),
('b17ad0ec-e00c-44da-bebe-684dcc2119b9','王辛甫示朱敬堂釣臺詩卷次韻','徐瑞','宋','宋诗','song-poetry','','[]','七里灘光照客裘，雙臺登覽意難休。',64,'全唐诗/poet.song.248000.json','["七里灘光照客裘，雙臺登覽意難休。", "當時蔑視麒麟楦，季漢反成黨錮鈎。", "山水何心供弔古，奸雄有面肯包羞。", "摩挲蒼峭追陳迹，四十四年重泛舟。"]'),
('7bce994d-eb75-44da-bf97-41e26e2f9a40','江道可用前韻見屬再疊謝之','徐瑞','宋','宋诗','song-poetry','','[]','秋風吹破木綿裘，一棹東遊興未休。',64,'全唐诗/poet.song.248000.json','["秋風吹破木綿裘，一棹東遊興未休。", "幼學古人徒自好，遺經深義不能鈎。", "槐黄滿路君宜往，髪白盈簪我亦羞。", "共飲番江不相識，富陽磯下却聯舟。"]'),
('6476509b-29e0-457e-a969-9f7acf5856e2','月灣以路學正攝番江長收租長洲有懷朽鈍賦詩遠寄次韻爲謝','徐瑞','宋','宋诗','song-poetry','','[]','學道如撐上峽船，蹉跎富貴與神仙。',64,'全唐诗/poet.song.248000.json','["學道如撐上峽船，蹉跎富貴與神仙。", "對床猶記聽風雨，講席何堪數歲年。", "少日朋儕隨化盡，晚塗老病有誰憐。", "故人厚問今何似，筋力雖衰尚服田。"]'),
('c1cf6a39-ad4e-4051-bf0c-571adf27395c','閏八月望日登青陽峰觀可玉所得天池之勝','徐瑞','宋','宋诗','song-poetry','','[]','天風吹我上崔嵬，凍面灑塵亦快哉。',64,'全唐诗/poet.song.248000.json','["天風吹我上崔嵬，凍面灑塵亦快哉。", "止水泓澄金鏡凈，遠峰羅列畫屏開。", "幽奇定有神仙到，險怪從教俗子咍。", "莫道此中無勝概，會看變化起風雷。"]'),
('3730a5e0-bbb1-4e94-88be-7cfa214ee76b','石林董先生年八十七厚齋詹先生年八十四會于文溪月灣賦詩次韻奉寄','徐瑞','宋','宋诗','song-poetry','','[]','石林居士詹山老，鶴骨山清出秀眉。',64,'全唐诗/poet.song.248000.json','["石林居士詹山老，鶴骨山清出秀眉。", "己卯相逢芹泮日，戊申共釂菊花枝。", "年華迅若東流去，道貌巋然太古遺。", "不恨文溪不同會，續貂猶得寄篇詩。"]'),
('6db53116-f350-4c9d-8b52-9d7db1407a1c','李俊民三十年前凡兩寄詩時困于世故俱不克和常抱此欠近理敗篋忽見兩詩歲月可驚凄然有感輒賦長句附便以謝不敏','徐瑞','宋','宋诗','song-poetry','','[]','囊錦當時兩度傳，篋藏中襲墨尤鮮。',64,'全唐诗/poet.song.248000.json','["囊錦當時兩度傳，篋藏中襲墨尤鮮。", "高情應怪詩郵斷，末路那禁俗累纏。", "過客談君吟轉妙，閉門笑我病堪憐。", "擘牋漫寄西風去，喚起鄉盟三十年。"]'),
('797af959-d837-4818-bf1f-94b6cf1a2a8c','門外意行有感書示二孫','徐瑞','宋','宋诗','song-poetry','','[]','門前老樹飽風霜，封植良勤不可忘。',64,'全唐诗/poet.song.248000.json','["門前老樹飽風霜，封植良勤不可忘。", "累世衣冠流澤遠，百年基緒慶源長。", "穉松怒長堪藏屋，新筍初抽已過牆。", "珍重先人有遺訓，讀書餘力及耕桑。"]'),
('84285023-1f30-49f7-8d41-8a19b925c7d0','夏五寄趙菊東','徐瑞','宋','宋诗','song-poetry','','[]','溪堂相望一百里，音問相疏十五年。',64,'全唐诗/poet.song.248000.json','["溪堂相望一百里，音問相疏十五年。", "眼底浮華俱已矣，籬東老菊獨依然。", "登臨不減青山興，陶寫猶懷白石編。", "待得秋風稍凉冷，方壺深處扣真玄。"]'),
('34e5f376-1711-40bc-9fc2-d87fd67959e6','寄山村仇公','徐瑞','宋','宋诗','song-poetry','','[]','山村老子知何似，想見龐眉鶴骨清。',64,'全唐诗/poet.song.248000.json','["山村老子知何似，想見龐眉鶴骨清。", "千里相望勞遠夢，六年不見耿深情。", "雲歸山翠沾衣濕，雨過湖光照眼明。", "最是湖山圖畫裏，輸公吟嘯了平生。"]'),
('06273d4a-8fa0-4f2c-a52a-84801f203365','李俊民寄詩一首次韻答之','徐瑞','宋','宋诗','song-poetry','','[]','世途險隘任崖顛，萬古人心只一天。',64,'全唐诗/poet.song.248000.json','["世途險隘任崖顛，萬古人心只一天。", "桂辣何須分老嫩，蜜甜自是透中邊。", "多君歌嘯酬風月，顧我呻吟了歲年。", "何日相從討幽事，松醪滿意泛觥船。"]'),
('151905e3-e70d-42f0-b799-fcb4abbc3e7f','雜感  其一','徐瑞','宋','宋诗','song-poetry','','[]','夸父以渴斃，麥杖終死兵。',60,'全唐诗/poet.song.248000.json','["夸父以渴斃，麥杖終死兵。", "項王稱拔山，霸圖竟無成。", "區區諸勇力，如何與天爭。", "子房類婦人，談笑立功名。", "去去從穀城，迢遥學長生。"]'),
('d1e652ac-a522-44b6-a9bc-03ef08fd357b','雜感  其二','徐瑞','宋','宋诗','song-poetry','','[]','阿瞞事鞍馬，橫槊尚賦詩。',48,'全唐诗/poet.song.248000.json','["阿瞞事鞍馬，橫槊尚賦詩。", "淮淝政交鋒，別墅方圍棋。", "何哉情事迂，俗論乃嗤嗤。", "斯人機械深，政爾未易窺。"]'),
('bc5d50f1-7207-4463-b93d-c8002a46d020','雜感  其三','徐瑞','宋','宋诗','song-poetry','','[]','長公不肯仕，曼容亦辭官。',48,'全唐诗/poet.song.248000.json','["長公不肯仕，曼容亦辭官。", "高車與駟馬，祇可誇外觀。", "玄鳳棲崑崙，杳杳天風寒。", "沆瀣以爲飲，朝霞以爲餐。"]'),
('106c0249-aac5-48fb-8a3f-8475209d2b3a','雜感  其四','徐瑞','宋','宋诗','song-poetry','','[]','六根本清凈，人自滓六根。',48,'全唐诗/poet.song.248000.json','["六根本清凈，人自滓六根。", "傾奪相糾結，不如此身尊。", "梯空智愈鑿，金注道逾昏。", "稽首劉伯倫，酒放過一生。"]'),
('97777c58-71ed-43a3-8789-5ec6b5b0514b','雜感  其五','徐瑞','宋','宋诗','song-poetry','','[]','獻璞乃取刖，求封而得黥。',48,'全唐诗/poet.song.248000.json','["獻璞乃取刖，求封而得黥。", "進退當以道，自售胡爾輕。", "堪嗟賤良貴，甘作狼藉人。", "寄語張季鷹，見幾已近神。"]'),
('97b0924e-0497-4bf2-bc1a-e763813bedf6','壬午清明拜先君墓下','徐瑞','宋','宋诗','song-poetry','','[]','鏘鏘澗水鳴，陰陰宰木春。',96,'全唐诗/poet.song.248000.json','["鏘鏘澗水鳴，陰陰宰木春。", "晨興羞清酌，酹我柏下人。", "山蹊塞欲斷，呼童剪荆榛。", "斷甃土暈碧，古瓦垣衣青。", "席草再俛伏，泫然淚沾巾。", "音容一以遠，魂夢何由尋。", "終天不可報，九原諒斯聞。", "願言領諸孤，年年拜清明。"]'),
('812d028b-59f6-4c77-b074-f8745e56c86c','五月初一日煮茶偶作','徐瑞','宋','宋诗','song-poetry','','[]','讀書了清暇，空齋長閉門。',96,'全唐诗/poet.song.248000.json','["讀書了清暇，空齋長閉門。", "冥冥晚雨潤，唶唶時禽喧。", "悠悠白雲度，沉沉綠陰繁。", "枯桐覓古意，石鼎烹山泉。", "清吟振巖木，亂以離騷篇。", "此道無不在，但覺山林尊。", "意根漸無有，世累何時捐。", "即事良可娛，一笑俱忘言。"]'),
('85660384-9663-474d-b984-45660bbe84c9','松風','徐瑞','宋','宋诗','song-poetry','','[]','屋山老髯龍，雪霜不能死。',84,'全唐诗/poet.song.248000.json','["屋山老髯龍，雪霜不能死。", "長身傲林壑，翠雲屯萬壘。", "夜半天風生，颯颯動窗几。", "秋江響怒潮，春空行急雨。", "須臾逗餘音，九霄笙鶴起。", "虛庭坐落月，欲去還復止。", "獨恨世間人，無此天籟耳。"]'),
('3730b5ac-7f66-4342-9e78-1011f5371faa','夜月如晝與仲退坐松巢煮茶','徐瑞','宋','宋诗','song-poetry','','[]','河淡星欲無，碧展天一幅。',72,'全唐诗/poet.song.248000.json','["河淡星欲無，碧展天一幅。", "天孫分錦章，薦此半規玉。", "明入千家窗，此興幾人足。", "慷慨商聲歌，主客俱不俗。", "泠泠古松根，枯樵煮寒瀑。", "清嘯拍闌干，悲猿挂高木。"]'),
('781f57f9-e28b-4a7e-9364-8c42bd36ed92','九月初七夜寓雙溪精舍','徐瑞','宋','宋诗','song-poetry','','[]','深巷足秋意，市聲寂無譁。',84,'全唐诗/poet.song.248000.json','["深巷足秋意，市聲寂無譁。", "門前籬落閒，淡淡牽牛花。", "老樹罷西風，羈鴻叫寒沙。", "念我同袍子，渺焉天一涯。", "別離悵交情，漂零惜年華。", "清坐撫遺編，行吟岸烏紗。", "世味嘗已熟，呼童烹靈芽。"]'),
('af9bda2e-d48c-4de8-bfa8-482b2d39ab23','客枕有感','徐瑞','宋','宋诗','song-poetry','','[]','寒關掩秋寂，幽齋俗塵空。',84,'全唐诗/poet.song.248000.json','["寒關掩秋寂，幽齋俗塵空。", "沉沉夜將半，孤燈結花紅。", "衣杵響深巷，塔鈴哦天風。", "依依訴幽恨，四壁惟秋蟲。", "市人競刀錐，奔走猶憧憧。", "衆欲何有涯，百年會須窮。", "高眠道心長，無言候晨鐘。"]'),
('6d02a121-191e-4569-96fb-c3f11289d9f2','癸未三月初七日泛舟東溪尋訪趙石齋於方壺山中臨分留呈','徐瑞','宋','宋诗','song-poetry','','[]','短篷載煙雨，鼓栧過東溪。',156,'全唐诗/poet.song.248000.json','["短篷載煙雨，鼓栧過東溪。", "盤桓萬山間，乘興信所之。", "桃花流水岸，繚繞路欲迷。", "隠隠雞犬聲，時時出翠微。", "支筇試幽討，中有高人居。", "平湖湛寒碧，疏林擢新枝。", "始至俗眼明，延緣遂忘疲。", "方瞳綠髪翁，一笑深相知。", "高譚潄芳潤，探囊出新詩。", "拍手孤鴻翔，拄杖凌空飛。", "舉酒對東風，獻酬各不辭。", "欲去不忍去，綠樹鳴催歸。", "我欲從公住，奈此塵鞅羈。"]'),
('fca63a38-d7df-4079-ac84-ceb82ebc3038','晚步用簡齋韻','徐瑞','宋','宋诗','song-poetry','','[]','沉沉萬竹間，舟行欲佳適。',48,'全唐诗/poet.song.248000.json','["沉沉萬竹間，舟行欲佳適。", "樵兒未歸來，笛聲在蒼壁。", "我本非隠淪，偶得喧中寂。", "延緣不知疲，小逕光已夕。"]'),
('0afae99d-300d-445c-a721-84cb10bbf717','田園  其一','徐瑞','宋','宋诗','song-poetry','','[]','結茅北山下，竹樹深以幽。',120,'全唐诗/poet.song.248000.json','["結茅北山下，竹樹深以幽。", "門前二頃田，躬耕遂吾謀。", "東風二三月，綠水如潑油。", "戴星事犁鉏，戮力期有秋。", "經行彼何人，黄金絡馬頭。", "停鞭略躊躇，爲問幾時休。", "所得不償勞，胡不從我遊。", "再拜謝行人，此意何綢繆。", "相從良不惡，違己誠所羞。", "卿宜用卿法，吾亦飯吾牛。"]'),
('0287f5a0-aca4-4e72-bd70-cd56481dc97a','田園  其二','徐瑞','宋','宋诗','song-poetry','','[]','去年種麥時，瘦骨寒欲折。',60,'全唐诗/poet.song.248000.json','["去年種麥時，瘦骨寒欲折。", "芃芃麥苗青，貿貿積霜雪。", "今年麥上場，鄰家粒已絕。", "我麥難堪飯，我耕力已竭。", "我力雖已竭，我計未爲拙。"]'),
('c88a4540-5aee-4cb5-bd10-f11f60bcabb5','田園  其三','徐瑞','宋','宋诗','song-poetry','','[]','山下十畝陂，可灌十頃田。',72,'全唐诗/poet.song.248000.json','["山下十畝陂，可灌十頃田。", "頻年費修築，堤堰久不完。", "泥沙況填壅，旱歲無源泉。", "凶荒貴有備，烏可盡付天。", "呼兒運木石，及此冬日暄。", "悠悠最害道，努力勿辭難。"]'),
('0c9f8195-a74a-47fe-b5e0-64f010cdf361','田園  其四','徐瑞','宋','宋诗','song-poetry','','[]','斵桐作秧馬，斷木刳泥船。',48,'全唐诗/poet.song.248000.json','["斵桐作秧馬，斷木刳泥船。", "咄此至微物，當趁歲月閒。", "阿童御觳𧥆，吹笛前山前。", "迎我相指似，村西吹晚煙。"]'),
('f5a3b021-5350-4666-b575-db192624ac65','田園  其五','徐瑞','宋','宋诗','song-poetry','','[]','屋山東南偏，手種一區芋。',48,'全唐诗/poet.song.248000.json','["屋山東南偏，手種一區芋。", "炎炎六七月，挈瓶事灌注。", "茲焉有佳思，役役不知暑。", "寒夜羹玉糝，聊用娛歲暮。"]'),
('8955628d-bb5f-4f02-90eb-188657f80858','田園  其六','徐瑞','宋','宋诗','song-poetry','','[]','連筒通稻渠，分溉五畝園。',60,'全唐诗/poet.song.248000.json','["連筒通稻渠，分溉五畝園。", "桑麻日青青，畦蔬亦已繁。", "晨興荷鉏出，日入荷鉏還。", "所樂固有在，辛苦不足言。", "鄰翁笑相勞，子乃不憚煩。"]'),
('21610fb7-7f58-44fe-ac22-806913f3aafd','田園  其七','徐瑞','宋','宋诗','song-poetry','','[]','寒溪橫略彴，窄徑通村墟。',60,'全唐诗/poet.song.248000.json','["寒溪橫略彴，窄徑通村墟。", "樵夫下山來，俗氣鄙且麤。", "野花鬢闌斑，藍縷寒無襦。", "賣薪招我飲，醉倒相携扶。", "明日復入山，真樂孰爾如。"]'),
('252cda88-a63c-414a-bc02-cc6683eb1578','田園  其八','徐瑞','宋','宋诗','song-poetry','','[]','種茶石岡上，草盛茶欲枯。',60,'全唐诗/poet.song.248000.json','["種茶石岡上，草盛茶欲枯。", "劬躬自薅薙，青青復厥初。", "新雷破幽鬰，一雨土脈蘇。", "槍旗漸堪摘，纖纖出香腴。", "此物不救饑，此味何可無。"]'),
('62a47b6d-4836-4dcb-a70d-7e99bebc4d88','田園  其九','徐瑞','宋','宋诗','song-poetry','','[]','方湖涵深碧，移種水芙蕖。',72,'全唐诗/poet.song.248000.json','["方湖涵深碧，移種水芙蕖。", "壤沃不待培，周回已芬敷。", "豈惟花實美，根葉尤所須。", "今年種菱芡，明年種菰蒲。", "生涯日已廣，而不勞耘鋤。", "月明撐舴艋，長嘯足自娛。"]'),
('db8ff964-8359-44a7-8fb6-c84be998300d','送八家叔之蘄春','徐瑞','宋','宋诗','song-poetry','','[]','飛梅收宿潤，曉氣含晴暉。',84,'全唐诗/poet.song.248000.json','["飛梅收宿潤，曉氣含晴暉。", "摩挲鐵如意，一笑千里期。", "江山信如昨，興廢良可悲。", "執手言遠別，念當何時歸。", "利害况同途，舉足皆危機。", "爰陳素履戒，爲誦行路詩。", "行行重回首，莫忘孤雲飛。"]'),
('7930a66d-6b84-4e14-864d-91609ef9b993','雨坐城邸登葆真院小樓望湖山清坐至暮','徐瑞','宋','宋诗','song-poetry','','[]','濕雲低古城，絲雨迷寒空。',72,'全唐诗/poet.song.248000.json','["濕雲低古城，絲雨迷寒空。", "平湖北風惡，雁叫菰蒲叢。", "疑有隠君子，孤舟釣空濛。", "煙波渺蒼莽，欲往嗟無從。", "道人數龜息，默坐饑腸充。", "湖東古招提，暮鼓鳴鼕鼕。"]'),
('066cbbb4-cea0-4c9a-9ebf-4b56fcedacbe','修禊後三日與仲退坐小齋煖雨初歇忽聞異香於是花事已罷春在塵土意其爲草木暢茂有自然之香而卒莫詰其所從來明日仲退以心清聞妙香爲韻作五詩奉次一噱  其一','徐瑞','宋','宋诗','song-poetry','','[]','齋居屏塵迹，讀易洗我心。',48,'全唐诗/poet.song.248000.json','["齋居屏塵迹，讀易洗我心。", "微風逗天香，縹緲不可尋。", "時時觸鼻觀，恍恍生空林。", "掩卷坐床側，桂樹交繁陰。"]'),
('f88b20e6-fc73-4518-a0c4-afb8e005195a','修禊後三日與仲退坐小齋煖雨初歇忽聞異香於是花事已罷春在塵土意其爲草木暢茂有自然之香而卒莫詰其所從來明日仲退以心清聞妙香爲韻作五詩奉次一噱  其二','徐瑞','宋','宋诗','song-poetry','','[]','金華太史公，隠几降心兵。',48,'全唐诗/poet.song.248000.json','["金華太史公，隠几降心兵。", "濛濛香事已，吟事方施行。", "我方慕高致，澹境奇趣生。", "不知何從來，乃有如許清。"]'),
('7a8b849e-15e9-4878-a5c0-286cd0bca70a','修禊後三日與仲退坐小齋煖雨初歇忽聞異香於是花事已罷春在塵土意其爲草木暢茂有自然之香而卒莫詰其所從來明日仲退以心清聞妙香爲韻作五詩奉次一噱  其三','徐瑞','宋','宋诗','song-poetry','','[]','異時參上乘，成種芸自薰。',48,'全唐诗/poet.song.248000.json','["異時參上乘，成種芸自薰。", "茫茫世界中，變幻如浮雲。", "豈知無盡法，真修不在聞。", "我猶未免俗，志一誰能分。"]'),
('c49aa988-7069-4bcf-b4fe-cd4e2dadde48','修禊後三日與仲退坐小齋煖雨初歇忽聞異香於是花事已罷春在塵土意其爲草木暢茂有自然之香而卒莫詰其所從來明日仲退以心清聞妙香爲韻作五詩奉次一噱  其四','徐瑞','宋','宋诗','song-poetry','','[]','眼纈龜甲屏，耳聞蚯蚓竅。',48,'全唐诗/poet.song.248000.json','["眼纈龜甲屏，耳聞蚯蚓竅。", "二者本無有，客感足悲弔。", "君看此幽芬，無情尤可笑。", "只作偶然觀，冥冥會衆妙。"]'),
('4f2d8986-8999-473d-87cb-b1e95776c5ac','修禊後三日與仲退坐小齋煖雨初歇忽聞異香於是花事已罷春在塵土意其爲草木暢茂有自然之香而卒莫詰其所從來明日仲退以心清聞妙香爲韻作五詩奉次一噱  其五','徐瑞','宋','宋诗','song-poetry','','[]','何年有野人，聞香未肯忘。',48,'全唐诗/poet.song.248000.json','["何年有野人，聞香未肯忘。", "世俗誇富貴，爭費柟櫖黄。", "我雖一掃空，奈此風韻長。", "一笑與神遇，底用譜異香。"]'),
('05e19c93-658a-4b8b-80db-5df9d04f60e2','次韻仲退山中小景四首 夕陽煙樹','徐瑞','宋','宋诗','song-poetry','','[]','暝煙出山阿，返照映紅樹。',48,'全唐诗/poet.song.248000.json','["暝煙出山阿，返照映紅樹。", "微茫極有態，目盡鴻飛處。", "迢遞溪西鐘，繚繞溪上路。", "惟聞喚渡人，兩岸爭來去。"]'),
('3582a41d-619d-4e95-bccf-ed0f6071442f','次韻仲退山中小景四首 荒陂鳬鴨','徐瑞','宋','宋诗','song-poetry','','[]','古埭浸寒漪，日至凡數四。',48,'全唐诗/poet.song.249000.json','["古埭浸寒漪，日至凡數四。", "沼洄沙水嚙，蕪廢歲復歲。", "野鳬以爲宗，出沒有閒思。", "誰能靜處觀，爲我畫其意。"]'),
('5f1b2296-8835-459c-b4c7-9a7b944c4c42','次韻仲退山中小景四首 霜林月影','徐瑞','宋','宋诗','song-poetry','','[]','中天行素月，炯炯白玉團。',48,'全唐诗/poet.song.249000.json','["中天行素月，炯炯白玉團。", "空林現百怪，滿地龍蛇盤。", "超然立於獨，亭亭老蒼官。", "有形亦是幻，一笑凌高寒。"]'),
('8928ea9d-86fd-4a14-9483-cdf46983dac1','次韻仲退山中小景四首 屋山夜雨','徐瑞','宋','宋诗','song-poetry','','[]','我昔浪漫遊，一葉浮虛空。',48,'全唐诗/poet.song.249000.json','["我昔浪漫遊，一葉浮虛空。", "短篷雨聲來，凄然念山中。", "巢居遂初志，靜聽忘吾窮。", "青燈亦多情，伴此滄浪翁。"]'),
('cbe9d399-a534-4613-8028-b9cfdf1978da','次韻仲退對月感懷四首  其一','徐瑞','宋','宋诗','song-poetry','','[]','方池納明月，坐看雲影移。',48,'全唐诗/poet.song.249000.json','["方池納明月，坐看雲影移。", "孤光動寒碧，一洗摇落悲。", "耽耽吾喪我，役役子爲誰。", "往來皆外物，妙質何曾虧。"]'),
('2a4eedce-0329-4665-95ec-133843b9f7a5','次韻仲退對月感懷四首  其二','徐瑞','宋','宋诗','song-poetry','','[]','一鏡行中天，地籟寂不動。',48,'全唐诗/poet.song.249000.json','["一鏡行中天，地籟寂不動。", "影散家家窗，萬枕酣短夢。", "何爲紅塵裏，綠酒笑鉛汞。", "𠻳齒吸英華，龍虎出妙用。"]'),
('5a2cf069-41ab-4415-9609-ff5d3b7d9533','次韻仲退對月感懷四首  其三','徐瑞','宋','宋诗','song-poetry','','[]','水火互爲宅，此理不在遠。',48,'全唐诗/poet.song.249000.json','["水火互爲宅，此理不在遠。", "君看烏與兔，可以悟一本。", "吾將罪儵忽，何事鑿混沌。", "大笑睨八荒，落木西風晚。"]'),
('4edb4c47-3442-4f89-bc0c-14eafec0411a','次韻仲退對月感懷四首  其四','徐瑞','宋','宋诗','song-poetry','','[]','日月兩彈丸，萬古春復秋。',48,'全唐诗/poet.song.249000.json','["日月兩彈丸，萬古春復秋。", "遷次有始終，合符無遲留。", "舉酒邀明月，浮子白玉舟。", "願毋渝此盟，坐待天運周。"]'),
('9f0c8447-f1b4-46de-aab2-8b42fea28626','壬辰社日芳洲領客梁必大湯景文吳德昭吳仲退李思宣周南翁遊芝山寺登五峰亭瑞在其間羽士洪和叟方君用載酒來會以雲飛江外去花落入城來分韻賦詩瑞得江字','徐瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔我落城市，日厭塵滿腔。',120,'全唐诗/poet.song.249000.json','["昔我落城市，日厭塵滿腔。", "携書歸故山，三年師老龐。", "興來復此遊，名勝萃一邦。", "東風三日雨，孤吟倚篷窗。", "晴天澹新碧，扶藜度危矼。", "同袍二三子，聲應不待撞。", "意行得古寺，共尋葛藤樁。", "天風鳴珮環，冉冉白鶴雙。", "坐看廬山雲，大釂傾酒缸。", "欲去復裴徊，返照明春江。"]'),
('dbc5a89b-bdfa-4d8b-8fbf-a85918c18062','仲退對月有懷芳洲景文至不忘僕爲古詩三首語意濃至次韻以謝并寄芳洲景文  其一','徐瑞','宋','宋诗','song-poetry','','[]','我行溪上路，行雲爲徘徊。',108,'全唐诗/poet.song.249000.json','["我行溪上路，行雲爲徘徊。", "天高北風惡，叫叫鴻雁來。", "起望杜若洲，渺渺絕沿洄。", "孤芳據其勝，修潔無纖埃。", "俗子不敢近，石梁尚崔嵬。", "我如剪翎鶴，老志空低回。", "又如渴蠹木，枯根莽難培。", "巧拙有定賦，神功若爲栽。", "持此欲叩君，溪寒雪皚皚。"]'),
('0c01ab72-1205-4443-ba80-71a4746f2e7f','仲退對月有懷芳洲景文至不忘僕爲古詩三首語意濃至次韻以謝并寄芳洲景文  其二','徐瑞','宋','宋诗','song-poetry','','[]','景文大兄行，世念如浮雲。',132,'全唐诗/poet.song.249000.json','["景文大兄行，世念如浮雲。", "自讀仲退詩，夜夜夢見君。", "憶昨初識君，所見溢所聞。", "促席傾底裏，談諧意彌勤。", "尚論三湯公，剪燭夜達分。", "共悲風流遠，纍纍北邙墳。", "今年芝山聚，有感蘭亭文。", "醉墨出三昧，逸氣凌鵝群。", "茲聞賦遠遊，應接當紛紜。", "中洲盛吟事，群公氣如焚。", "勗哉爭長難，吾衰不能軍。"]'),
('ab5bb6eb-af92-4347-acc2-cc61c2c91bcb','仲退對月有懷芳洲景文至不忘僕爲古詩三首語意濃至次韻以謝并寄芳洲景文  其三','徐瑞','宋','宋诗','song-poetry','','[]','丈夫貴意氣，豈必在合并。',108,'全唐诗/poet.song.249000.json','["丈夫貴意氣，豈必在合并。", "琅琅對月篇，中有伐木聲。", "夫子黎湯流，事事誇奇情。", "未忘雷張舊，蒯綆媿青萍。", "向來在匣時，雌雄互悲鳴。", "分離未云遠，涇渭判濁清。", "精靈諒密契，歲月空崢嶸。", "吾方師漆園，因劍論養生。", "時時呼斗酒，磊落澆使平。"]'),
('fdb01a97-8c42-4659-af3e-1f32347d1ccf','丁酉正月九日省謁家叔潔山居士于郭仙峰下是日仲退亦省其叔四山翁於是偕行潔山既留飯送別烏龍潭上裴回久之絕壁梅花炯然獨立如高人招之不來凍泉泠泠下巖竇如瑟筑聲相顧絕賞因以春山多勝事分韻約四山父子同賦時四山留外未歸也韻以齒次瑞得多字','徐瑞','宋','宋诗','song-poetry','','[]','新年未入山，今晨風日和。',96,'全唐诗/poet.song.249000.json','["新年未入山，今晨風日和。", "況復得勝友，發興凌嵯峨。", "冰澌激陰湍，草色明陽坡。", "老梅高標致，疏花自巖阿。", "樵兒與牧豎，迎笑相誰何。", "問我結茅意，何年此婆娑。", "悠然會深情，臨風發清歌。", "回首紅塵中，孰與青山多。"]'),
('16a37be9-619f-4929-84d0-900f8655250e','次韻芳洲先生題法雲寺流玉閣','徐瑞','宋','宋诗','song-poetry','','[]','危簷面長洲，晴雨各有趣。',72,'全唐诗/poet.song.249000.json','["危簷面長洲，晴雨各有趣。", "灘鳴九霄珮，江瀉千丈素。", "笑問流玉師，歲月不知度。", "心空忘境勝，力定得實悟。", "師云住是間，非住非非住。", "更問有句無，寒藤倚枯樹。"]'),
('355989a2-fd9a-4386-b138-77cb109eacd4','芳洲寄古詩一首申山中之約次韻奉謝','徐瑞','宋','宋诗','song-poetry','','[]','憎欲毋已甚，同塵正自佳。',120,'全唐诗/poet.song.249000.json','["憎欲毋已甚，同塵正自佳。", "我如張仲蔚，蓬蒿滿荒階。", "觀化有妙悟，委運增曠懷。", "鴻飛正冥冥，雞鳴漫喈喈。", "美人芳杜姿，玩世善打乖。", "曲肱有真樂，俟命且潔齋。", "身屈道則尊，不事塹與崖。", "平生山中約，高致許我儕。", "此語二十年，此事行當諧。", "試看紅塵客，踏破幾鐵鞋。"]'),
('36a247e1-8594-44b0-89cf-a5d1a70a2ed6','君子法天運','徐瑞','宋','宋诗','song-poetry','','[]','君子法天運，小人昧時幾。',48,'全唐诗/poet.song.249000.json','["君子法天運，小人昧時幾。", "法天貴自强，時哉幾甚微。", "强則無退惰，微則有是非。", "終期德業成，無爲小人歸。"]'),
('627d9ec6-f25e-4094-bff1-3e48b13a82b3','次仲退韻','徐瑞','宋','宋诗','song-poetry','','[]','達士樂夷曠，俗子尚矜持。',96,'全唐诗/poet.song.249000.json','["達士樂夷曠，俗子尚矜持。", "緬懷同心人，春風久別離。", "辭章五色線，絢爛逢明時。", "顧我何所事，不耕復不菑。", "屢空良可笑，我道固如茲。", "但憂德未進，名浮亦奚爲。", "周遊豈不佳，去去當從誰。", "有酒但痛飲，莫問醇與醨。"]'),
('140f5f54-450c-489a-9d56-0dd48337d6b8','次韻南翁出郊','徐瑞','宋','宋诗','song-poetry','','[]','聽雨不出戶，不知春已深。',84,'全唐诗/poet.song.249000.json','["聽雨不出戶，不知春已深。", "綠水漲洄塘，翠氣明遥岑。", "我家樹遶屋，庶蕃來時禽。", "觀其引吭鳴，何如結舌瘖。", "物理存比興，人事有升沉。", "丈夫趣詣遠，道德遂初心。", "知行貴兩盡，論說何足欽。"]'),
('fa8e052c-31bd-4c49-9fa4-d1bcc824aeef','次韻芳洲蘭花','徐瑞','宋','宋诗','song-poetry','','[]','殘雪消陰崖，柔風被晴麓。',120,'全唐诗/poet.song.249000.json','["殘雪消陰崖，柔風被晴麓。", "蘭根得天和，芳蕤出叢綠。", "澹然如幽人，皎皎在空谷。", "味薄趣自長，香遠韻更足。", "尚嫌荃惠伍，肯與桃李凟。", "中洲有吟仙，自愛稱初服。", "丘壑賞孤清，泥塗憐久辱。", "乃知松柏姿，均此受命獨。", "石君瘦欲涸，毛穎老不沐。", "爲子操猗蘭，清商出枯木。"]'),
('39690089-bed4-458d-a7e0-7ca87b5e5cb5','辛丑二月初晴與仲退從芳洲縱遊溪山間私念吾黨會聚殆不偶然賦古詩一首後五百歲有知音者於吾詩物色可乎','徐瑞','宋','宋诗','song-poetry','','[]','天地以氣合，人物以類從。',168,'全唐诗/poet.song.249000.json','["天地以氣合，人物以類從。", "孰是同類中，道同志復同。", "槃槃石梁翁，閲世如老松。", "若士古溪灣，水月印心胸。", "相去不十里，而我居其中。", "既無山川阻，隨此心迹融。", "譚諧屢參伍，杖屨時從容。", "巖下酌秋泉，溪上行春風。", "奇文辨魚魯，古學窺鴻濛。", "玄同執尤契，妙中值箭鋒。", "從今不厭數，曠代或一逢。", "願言各自珍，慎勿攖樊籠。", "會同拾瑶草，更約摩金銅。", "賦詩俟來者，物色傳畫工。"]'),
('54b3a7ad-b419-4167-9bcc-74232520d1b3','題金翁牧牛歌後','徐瑞','宋','宋诗','song-poetry','','[]','我幼在田間，頗識牧牛趣。',120,'全唐诗/poet.song.249000.json','["我幼在田間，頗識牧牛趣。", "寒蓑煙雨林，短笛斜陽路。", "十年陷世網，自悔一念悞。", "歸來丘壑中，幸不失吾素。", "平生愛顔闔，寧戚非所慕。", "古今樂此事，僂指自有數。", "阿翁老無營，尺箠了朝暮。", "絕勝介葛盧，未鳴意已悟。", "長謠遠屬我，真實見情愫。", "勿遣兒輩覺，千載有知遇。"]'),
('9724d0d3-1915-481a-b8c2-ae982bd9d193','鄰翁王道人送武夷圖','徐瑞','宋','宋诗','song-poetry','','[]','客從建安歸，遺我武夷圖。',144,'全唐诗/poet.song.249000.json','["客從建安歸，遺我武夷圖。", "開圖掛素壁，風煙生座隅。", "奇峰三十六，拔起凌天衢。", "一水從中來，九折何縈紆。", "想見岩壑間，縹緲藏仙都。", "荒哉武與夷，遼遼不可呼。", "尚聞雲谷仙，舊跡未深蕪。", "櫂歌留絕唱，遺書鎮精廬。", "高操誰能攀，幽致或可摹。", "三年規一遊，神往形尤拘。", "便須理行纏，勿遣歲月徂。", "山靈有夙契，清風爲前驅。"]'),
('682c5bf9-2b2d-444e-980d-c2b906d5c140','今日行我圃','徐瑞','宋','宋诗','song-poetry','','[]','今日行我圃，欣然會吾心。',108,'全唐诗/poet.song.249000.json','["今日行我圃，欣然會吾心。", "町畦分燥濕，種蒔論淺深。", "柔脆置其陽，堅實值其陰。", "瓜芋既蓊蓊，桑麻亦森森。", "晚菘與早韭，鬰然起如林。", "雖無五畝勝，寸寸皆黄金。", "學圃聖所鄙，勢塗力難任。", "不辭鋤銍勞，且免蒿艾侵。", "君看門前客，此樂無由尋。"]'),
('2ea3c269-4498-43a9-bcef-6c929627ab2a','夜中不成寐','徐瑞','宋','宋诗','song-poetry','','[]','夜中不成寐，披衣步前庭。',132,'全唐诗/poet.song.249000.json','["夜中不成寐，披衣步前庭。", "榮榮無塵雜，四面敞且平。", "俯聽衆竅靜，仰視疏星明。", "眇然寓其間，一粟浮大瀛。", "滔滔匯衆濁，涓流若爲清。", "矧今六八年，華髪日夜生。", "平生信古學，及此將何成。", "妄動多險阻，深居來譏評。", "和同豈不願，矯揉非其情。", "世眼自醜好，千載有重輕。", "所志不可移，坐待鄰雞鳴。"]'),
('8775945b-e416-454a-9efb-e078f3a066ac','有酒相與飲','徐瑞','宋','宋诗','song-poetry','','[]','有酒相與飲，無酒但啜茶。',96,'全唐诗/poet.song.249000.json','["有酒相與飲，無酒但啜茶。", "人情貴真實，豈在崇浮夸。", "高人賞我趣，謂悃愊無華。", "世士乃不然，傳食謗且誇。", "更欲論施報，終身置齒牙。", "乾餱或速愆，口體亦可嗟。", "清風郭與茅，千古無以加。", "去去欲語誰，挈瓶灌吾瓜。"]'),
('76dd7dfe-98be-43e6-bfa1-eda82419207e','六月三日赴周南翁之招時芳洲留梅山堂述行實僕與觀焉臨別以高山流水四字分韻約仲退同賦瑞得山字','徐瑞','宋','宋诗','song-poetry','','[]','人事恒有數，一聚百阻難。',144,'全唐诗/poet.song.249000.json','["人事恒有數，一聚百阻難。", "朅來集斯堂，主客俱蕭閒。", "明公圖不朽，盤礴筆墨間。", "諏求逮耆耄，采錄及蒯菅。", "論述本至公，不待潤與刪。", "居然是傳信，可但起澆頑。", "古今文章家，我粗窺一斑。", "茲事未易言，千載有相關。", "周旋得所願，欣快忘幽孱。", "炎塵屏四野，清風洗沈瘝。", "佳興殊未極，延緣念當還。", "呼童夙嚴駕，東明映青山。"]'),
('a0be2bfb-fdb1-44aa-aa28-db1f661fe9db','辛丑九月十二與芳洲留宿雅山堂歲且周矣芳洲再往賦古詩十二韻奉寄壬寅九月十一日也','徐瑞','宋','宋诗','song-poetry','','[]','山林或塵土，城郭無市譁。',144,'全唐诗/poet.song.249000.json','["山林或塵土，城郭無市譁。", "境勝固繇人，況是詩書家。", "小齋貯虛明，景物亦可嘉。", "怪石卧屭贔，修藤綰龍蛇。", "清泉纖纖草，小樹疏疏花。", "主人古衣冠，宴坐勝紛華。", "群從儼連璧，學子鏗衝牙。", "喜我味稍同，下榻煮秋茶。", "道充韻更長，身退心自遐。", "豈惟擅清致，當在勒與差。", "別來入夢頻，急景令人嗟。", "寄詩寫幽懷，勿與世俗誇。"]'),
('e98afbda-b7d5-475f-b092-d256167f0ac9','送余晉仲游廬山','徐瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','登山信有道，游山誠好奇。',144,'全唐诗/poet.song.249000.json','["登山信有道，游山誠好奇。", "胸中無丘壑，歷覽將何爲。", "廬君倚天立，秀甲東南垂。", "非有千里遥，匯澤同津涯。", "平生幾入夢，未往神先馳。", "玄煙鎖青牛，鹿場草離離。", "竹林隠雲表，真漢不可窺。", "子行勿浪漫，尋訪宜舒遲。", "靈扃憑誰啟，絕學從誰師。", "老我世味淡，愛山心不移。", "床頭赤藤杖，時作龍吟悲。", "爲我謝廬君，行當赴幽期。"]'),
('5e368834-e03a-44f8-bba9-a6782088e25b','次韻仲退見貽一首','徐瑞','宋','宋诗','song-poetry','','[]','先慮所不到，事乃謬不然。',120,'全唐诗/poet.song.249000.json','["先慮所不到，事乃謬不然。", "兩失竟相當，富貴與神仙。", "真意寓採菊，苦心懷食蓮。", "古來賢達人，何適而非天。", "惟君淡世味，胸中著千年。", "衆濁紛其前，每以至理湔。", "憐我根器鈍，未試麻姑鞭。", "時時出匕劑，欲俾沈疴痊。", "歲晚有深期，逝川無西還。", "何事更留衣，必待夜半傳。"]'),
('68ef7ae1-68ff-492b-8dce-433d93e3350b','饒娥祠','徐瑞','宋','宋诗','song-poetry','','[]','三極勢雖異，一理實貫通。',120,'全唐诗/poet.song.249000.json','["三極勢雖異，一理實貫通。", "人極苟不立，天地亦將窮。", "饒娥小家子，至老根彝衷。", "精誠裂金石，冥感驅魚龍。", "予幼讀柳碑，凄其仰英風。", "茲焉訪遺蹟，山椒峙靈宮。", "灘石既嵯峨，古木亦巃嵷。", "乃知一念烈，天地同其功。", "天地不可盡，此念曷有終。", "再拜下山去，日射春江紅。"]'),
('3c365ad2-c6c7-4dba-8a59-594ca2337551','九月四日偕弟可玉外甥張敏修吾孫棟游西山訪古追懷甲戌舊游感嘆不已紀事五十韻','徐瑞','宋','宋诗','song-poetry','','[]','秋日清且厲，發興山西游。',288,'全唐诗/poet.song.249000.json','["秋日清且厲，發興山西游。", "步出錢塘門，纍纍但荒丘。", "繁華歘消歇，王氣竟誰收。", "寂寞石函橋，小水清淺流。", "秦皇纜船處，螺髻現佛頭。", "雖非凌雲像，雄偉亦罕儔。", "開示一指禪，觀者領悟不。", "作禮三皈依，將行復綢繆。", "浮屠踞山巔，何年困鬰攸。", "返步遵大路，叢薄新篁抽。", "前有佛足泉，一竇清瀏瀏。", "凄凉鄂王祠，墓道鎖松楸。", "可憐忠烈魂，寄此土一抔。", "遺像儼中堂，怒氣橫雙眸。", "誤國彼何人，寸斬不足酬。", "迤𨓦訪玉泉，泓澄湛靈湫。", "老龍閟神蹤，金鱗自夷猶。", "白詩揭楣間，三嘆歲月悠。", "荆榛何王府，瓦礫誰家樓。", "當年歌舞地，今縱羊與牛。", "或爲少僧廬，或爲老圃耰。", "徑趨九里松，吳筆勁且遒。", "靈鷲號飛來，荒幻不可諏。", "直北抵靈隠，殿宇壯岩陬。"]'),
('44b05834-eff0-44c2-bf05-67561eb446ee','次韻江道可贈別古詩二首  其一','徐瑞','宋','宋诗','song-poetry','','[]','我家白雲中，幽興何蹁躚。',48,'全唐诗/poet.song.249000.json','["我家白雲中，幽興何蹁躚。", "惟有十八公，共結三生緣。", "苓珀誰能待，風霜逼彫年。", "忽聞笙鶴音，忘我食與眠。"]'),
('d50a58cd-e6c4-4b81-bea8-803eb3be8869','次韻江道可贈別古詩二首  其二','徐瑞','宋','宋诗','song-poetry','','[]','千金買鉛刀，佩者增意氣。',48,'全唐诗/poet.song.249000.json','["千金買鉛刀，佩者增意氣。", "豈知豐城匣，雲深不知處。", "道逢張與雷，握手笑相謂。", "靈物寧終潜，時來會飛去。"]'),
('32d0b019-7f6f-4ef4-8920-ff3d5929099a','九月廿一自虎林回同程曉崖游梅巖','徐瑞','宋','宋诗','song-poetry','','[]','弛擔息虛館，釋屩解行纏。',216,'全唐诗/poet.song.249000.json','["弛擔息虛館，釋屩解行纏。", "一笑得妙士，揖我謂我儇。", "相携履巉岩，共訪梅花仙。", "石門歘谺豁，空洞別一天。", "徐行呼二豎，秉炬導其前。", "沿崖異草垂，繞逕秋香妍。", "行行漸深入，響答殊清圓。", "下有苔磴峙，上有孔穴穿。", "深處窅如穽，曠處平如田。", "或如人坐立，或如獸蹲跧。", "古石列怪狀，時聞滴幽泉。", "向來開天牖，坐看日月旋。", "兒童撞嵌岩，如鐘鼓咽咽。", "領覽不能盡，荒幻難言宣。", "我從虎林來，足繭歸心懸。", "舉瓢挹危露，塵肺聊用湔。", "清寒不可留，欲去還延緣。", "賦詩紀茲游，絕筆憑誰鎸。"]'),
('f4a49a32-62e7-4b23-960d-a46b684d4c69','次韻月灣見寄古詩一首','徐瑞','宋','宋诗','song-poetry','','[]','白石煮不爛，饑來意楚萍。',120,'全唐诗/poet.song.249000.json','["白石煮不爛，饑來意楚萍。", "流落固應爾，敢恨鬢星星。", "鴻飛一何高，矯翮凌青冥。", "下視蜩與鳩，意趣自徑庭。", "松間乖舊約，三霜五秋螢。", "來章敦古誼，吟諷慰漂零。", "羨公筆有口，遇我眼終青。", "殷勤爲發藥，非芝朮參苓。", "豈惟起衰懦，誠足制頹齡。", "感激絃清商，調古無誰聽。"]'),
('fd62a2ba-4419-44f4-9fd5-b984ca5a7b4a','戊寅雪中有感','徐瑞','宋','宋诗','song-poetry','','[]','五更窗白鳴早鴉，北風獵獵號谽谺。',224,'全唐诗/poet.song.249000.json','["五更窗白鳴早鴉，北風獵獵號谽谺。", "凍雲不開天雨雪，漫空作態紛橫斜。", "披衣起立儘蕭散，睥睨神巧令人嗟。", "深山荒怪號狐兔，古木蜿蜒蟠龍蛇。", "空林野鶻棲又起，寒簷饑雀喧且呀。", "斷橋古埭欲無路，孤城疊鼓方停撾。", "老農嘻嘻慶豐樂，羈旅瑣瑣愁荒遐。", "酒壚群聚澆毷氉，市樓歌吹聞嘔啞。", "縱觀山川絕塵土，坐嘆造物真空花。", "世間萬事蕉覆鹿，回首二曜如奔車。", "老仙騎鯨東海去，誰尚風雅排淫哇。", "遺音妙寄不可續，嗟我悵望迷天涯。", "蕭蕭竹屋白晝閴，俗子不到山人家。", "呼童屏置勿舉飲，石鼎且試曾坑茶。"]'),
('418af02a-28d5-4318-ac70-4f92e4863c24','聞促織有感','徐瑞','宋','宋诗','song-poetry','','[]','苔花露重銅鋪濕，深閨蠟盡紗籠碧。',51,'全唐诗/poet.song.249000.json','["苔花露重銅鋪濕，深閨蠟盡紗籠碧。", "嗷嗷四壁候蟲鳴，促人早織聲不停。", "君不見宮中自置機與絡，儘君有絲難得著。"]'),
('5d0c9e25-a579-4319-a267-0de1a16c0da6','城上謠','徐瑞','宋','宋诗','song-poetry','','[]','北風吹沙湖水黄，離離衰草覆女牆。',64,'全唐诗/poet.song.249000.json','["北風吹沙湖水黄，離離衰草覆女牆。", "曼纓紫鬢馬上郎，腰間短劍明秋霜。", "城西砧杵登登處，夫君已戍交河去。", "角聲漸起鼓聲住，亂鴉啼斷斜陽樹。"]'),
('71865a46-6ca1-4273-b8b3-e518bde381f2','三月十一夜仲退留宿山中即景賦詩次韻','徐瑞','宋','宋诗','song-poetry','','[]','夫夫去尋桃李逕，老我卧雲彌歲年。',64,'全唐诗/poet.song.249000.json','["夫夫去尋桃李逕，老我卧雲彌歲年。", "遠志何妨作小草，破鏡且喜飛上天。", "誦詩只今病自失，抱琴一笑醉欲眠。", "山空月落天未曙，幽夢耿耿聞啼鵑。"]'),
('bae0f687-0288-4584-9627-2ae3d977ebcc','余敬可示汪子明諸君大雪詩卷次韻','徐瑞','宋','宋诗','song-poetry','','[]','當年聚星堂上雪，醉翁一時盛賓客。',208,'全唐诗/poet.song.249000.json','["當年聚星堂上雪，醉翁一時盛賓客。", "賦詩下令自作古，寸鐵不持渠戰白。", "坡翁晚出繼風流，號令尤嚴筆尤特。", "兩翁高蹈二百年，對雪興懷足悲悅。", "癡雲漠漠落未已，忍聽窮闍嗟困踣。", "寒江短艇釣空濛，孤城暮角傳嗚咽。", "獵徒原上肆鷹犬，幽士坐窗唯一默。", "豪門夜釂不知旦，粧樓曉鏡驚明豁。", "眼前種種總堪詩，歐蘇故事成闊絕。", "劃聞雲君出新語，字如瘦竹行欹仄。", "臨湖道人口業在，宛然箎仲賡塤伯。", "何如松下觀幻質，仰天大笑累墮幘。", "吾家兒女況能貧，海圖爭把波濤拆。"]'),
('b7bad978-f6ee-4596-bf71-2faf8fcb6617','壁侍者歸自廬山以詩問訊','徐瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','壁公挑雲廬山去，自我不見今三年。',64,'全唐诗/poet.song.249000.json','["壁公挑雲廬山去，自我不見今三年。", "出家本是丈夫事，成佛不作文章禪。", "西竺東震非道二，心宗教意難言傳。", "何時尋我青陽巔，分我一滴廬山泉。"]'),
('bb5f6ef3-7035-4ee8-bd66-14427b0a8573','丙申元日','徐瑞','宋','宋诗','song-poetry','','[]','丙申正月初一日，巢君野人拈禿筆。',192,'全唐诗/poet.song.249000.json','["丙申正月初一日，巢君野人拈禿筆。", "塗窗作鴉憶少年，不知老醜光陰疾。", "退藏未了桑蠶繭，生涯僅似崖蜂蜜。", "小兒怪我不同塵，進不能寸退盈尺。", "豈知窮通自有命，我手可斷不書乞。", "安道何事竟碎琴，管寧何意至割席。", "五斗不換東籬菊，千戶寧如江陵橘。", "蚊虻甕盎互起滅，歡樂幾何長鬰鬰。", "我從方外得天游，始嘆世緣如沐漆。", "縱橫妙用劍兩枝，出入無方馬一隻。", "老師雲邊親授記，許我虛空轟霹靂。", "東風吹動老虬枝，笑拂蒼髯雙眼碧。"]'),
('7663d14b-9672-4d0a-8093-b2ef06914ce2','大德元年丁酉歲六月大雨前所未見父老云百八十年無此水矣仲退賦長句紀事次韻','徐瑞','宋','宋诗','song-poetry','','[]','曾將太乙推主客，不眠坐數蓮花滴。',160,'全唐诗/poet.song.249000.json','["曾將太乙推主客，不眠坐數蓮花滴。", "今年春夏甲子雨，白髪無端爲憂國。", "乘船入市讖不虛，平陸成江勢何斥。", "乃當六月初五夜，天意冥冥難察識。", "直疑女媧功未完，石破天穿地維折。", "飛廉上助澎湃威，馮夷不闢泉源脈。", "城中魚鱉混生人，樓堞瀰漫不計尺。", "彭城當年二丈八，蘇公隄衛無遺蹟。", "喜聞賢守力賑濟，安得神人拔其塞。", "不然帝復陸渾怨，特遣五龍施此溺。"]'),
('0b5188b7-9aad-404b-be03-be6e8381fc72','次景文聽松風韻','徐瑞','宋','宋诗','song-poetry','','[]','萬壑蒼烟深閉閣，此客入山童放鶴。',144,'全唐诗/poet.song.249000.json','["萬壑蒼烟深閉閣，此客入山童放鶴。", "天球琬琰一代珍，合止笙鏞九成樂。", "胸懷正自小滄溟，風骨端宜寘岩壑。", "三年烏帽墊京塵，至今夢裏喧車鐸。", "渴來醉卧白雲根，飽聽松風中夜作。", "空中起用一何奇，聲外生聞本無著。", "閒情空自貞白癡，雅罰何妨半山謔。", "知君此興復不淺，安得松間相倚薄。", "君山吟嘯早歸來，蛟鱷縱橫風水惡。"]'),
('2a4f3a33-35f6-4515-87f0-85631d43ed9f','夏五門外小池白蓮盛開有一莖雙花巋然出于群花之上賦長句志之','徐瑞','宋','宋诗','song-poetry','','[]','方塘風露清泠泠，萬荷嶷立森高青。',160,'全唐诗/poet.song.249000.json','["方塘風露清泠泠，萬荷嶷立森高青。", "群花迎日各有態，一莖出水初亭亭。", "雙苞並蒂發天巧，雕飾盡去殊瞻聽。", "風標自是絕塵土，道氣直欲凌青冥。", "恍然兩仙來帝庭，翠雲綠霧浮輜軿。", "飄飄羽服共蕭散，隠隠水珮爭瓏玲。", "同輿鄙笑岳及湛，專城彷彿石與丁。", "看花何啻日千轉，屬辭含意行且停。", "涪翁食蓮寄深感，如此妙質誰當銘。", "我歌此詩百其聆，一洗千古脂粉腥。"]'),
('083f6845-71fd-4b42-b45b-0e4f6592214e','己亥二月仲退寄桃花雪倡和詩卷次韻','徐瑞','宋','宋诗','song-poetry','','[]','天公笑子成詩顛，雕琢肝腎窮歲年。',192,'全唐诗/poet.song.249000.json','["天公笑子成詩顛，雕琢肝腎窮歲年。", "桃自成蹊天何言，桃開雪落無媸妍。", "我呼斗酒看花飲，酒酣停杯爲問天。", "正色蒼蒼以意對，癡人說夢真可憐。", "陰陽迭運有饒乏，化機妙斡存經權。", "茫茫下土汩聲色，九河翻倒不足湔。", "偶然相值等戲劇，過眼變滅如飛煙。", "炎天梅蘂發冷趣，冬月齏韭誇賓筵。", "天時人事古如此，水陸何必病車船。", "萼華阿母在何許，若事狡獪奚其仙。", "莫將幻語駭聾俗，東風有恨應難傳。", "還君此卷三嘆息，坐看綠色歸平田。"]'),
('14de4ef7-03bb-4873-8ea8-d8cf350836b1','題劉東仲所藏長江圖','徐瑞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','誰將剡素尺有咫，萬里屈盤歸筆底。',64,'全唐诗/poet.song.249000.json','["誰將剡素尺有咫，萬里屈盤歸筆底。", "江天漠漠水雲寬，樓堞微茫煙樹裏。", "岷山濫觴東入海，自古興亡難盡紀。", "詩人莫作畫圖看，中有英雄淚如洗。"]'),
('9a855024-fe8f-4bc3-af55-c8284f827d15','餘干學錄徐君名桂蟾號月齋龍游人善文詞善談方外之學春晚來山中談七日乃別今重到玄妙寄樂府一闋賦此爲別','徐瑞','宋','宋诗','song-poetry','','[]','博雅南州士，風流小隠仙。',167,'全唐诗/poet.song.249000.json','["博雅南州士，風流小隠仙。", "橫經越水夢，會弁鵲湖緣。", "蕩蕩乾坤理，明明日月懸。", "鈎深發奇藴，觀象洞真詮。", "不謂宗盟合，能令古道還。", "肯來留七日，遽別半年。", "流水高山趣，陽春白雪篇。", "朗吟驚玉立，抱玩美珠連。", "更憶彈馮鋏，兼懷訪戴船。", "續貂吾豈敢，韞匵爾宜專。", "老驥思騰櫪，潜鱗樂在淵。", "邯鄲正炊黍，黄石有遺編。", "撫己懷難盡，忘言意已傳。", "會同速風馭，去採華山蓮。"]'),
('64bc7d5e-33e9-44f0-ad56-dd74b2b621c9','馬君采刲羊置酒作九日之會少長咸集主勸賓酬飲酒樂甚明日成小詩寄君采','徐瑞','宋','宋诗','song-poetry','','[]','節序催成歲，朋曹阻異方。',144,'全唐诗/poet.song.249000.json','["節序催成歲，朋曹阻異方。", "幽懷興獨感，舉俗愛重陽。", "有美珠灣客，能勤秋月章。", "華堂開晚集，勝友侑清觴。", "饌設羊肪白，杯持菊蘂黄。", "髹盤行棗栗，甆玉進齏粻。", "擊缶歌呼雜，飛觥賞罰忙。", "群豪矜爪利，二老鬬身强。", "且用酒爲日，何妨鬢欲霜。", "風松薦琴石，水竹煉丹房。", "境勝身宜適，心閒味自長。", "明年應更健，此會未渠央。"]'),
('c63b3627-2f1e-441e-80ab-e74d2e8caf67','芳洲先生挽詞','徐瑞','宋','宋诗','song-poetry','','[]','宇宙靈光在，山川爽氣銷。',240,'全唐诗/poet.song.249000.json','["宇宙靈光在，山川爽氣銷。", "天公奪此老，人望絕今朝。", "蚤歲收名第，華章爛慶霄。", "晚成端有待，穎出一何超。", "風浪鰲山動，煙塵翠水遥。", "退藏工用拙，小試略舒翹。", "講學重師席，咨謀贊使軺。", "奇書萃鐘鼎，雅道播咸韶。", "匵美誰能賈，知音不恨焦。", "瓜園秋寂寞，梅逕雪蕭條。", "丘壑情深重，功名意自消。", "春暉娛寢膳，夜雨樂朋僚。", "老走違時好，深心託久要。", "共期采杜若，幾度寄蘭苕。", "每疾浮文陋，還驚末俗澆。", "頹波回渺渺，古韻振寥寥。", "舊夢南柯蟻，英魂東海潮。", "凄凉留筆塚，零落付詩瓢。", "戲墨人爭購，遺編手自標。", "神交惟宋玉，哀意寓三招。"]'),
('d01fc273-b38a-4510-bf68-0567bfb68d5e','表兄王俊夫客當塗以古詩見寄賦此奉謝','徐瑞','宋','宋诗','song-poetry','','[]','自嘆離群淹在茲，詩來一讀一相思。',64,'全唐诗/poet.song.249000.json','["自嘆離群淹在茲，詩來一讀一相思。", "人言毛遂早成事，我怪何蕃久不歸。", "燈火十年俱舊夢，江湖萬里有新知。", "秋風蕭颯蘋花老，目斷晴雲片片飛。"]'),
('deaafa15-24af-46b5-8d18-ac57002ee9f1','客邸呈諸友','徐瑞','宋','宋诗','song-poetry','','[]','不用猖狂放泣岐，回車復路未爲非。',64,'全唐诗/poet.song.249000.json','["不用猖狂放泣岐，回車復路未爲非。", "客愁無奈唯憑酒，口業未除猶說詩。", "騎鶴吹笙初志在，聞雞舞劍壯心違。", "秋風紅葉青山下，準擬相携把菊枝。"]'),
('7f1ef941-8621-4a7b-b143-8328efb51a9a','客談西湖舊事感而賦詩','徐瑞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖上輕風颭酒旗，水光山色漾晴暉。',64,'全唐诗/poet.song.249000.json','["湖上輕風颭酒旗，水光山色漾晴暉。", "紅塵駿馬青絲鞚，畫舫佳人白紵詞。", "錦瑟兩行春宴罷，玉笙十里夜遊歸。", "錢塘一枕繁華夢，回首凄凉鬢欲絲。"]'),
('e2883984-ec13-4a4f-aab2-4b793e0bfabc','王子賢疲於役移家彭澤示詩索和','徐瑞','宋','宋诗','song-poetry','','[]','何人筆削晉東西，豈是王家父子癡。',64,'全唐诗/poet.song.249000.json','["何人筆削晉東西，豈是王家父子癡。", "可奈秋風吹破屋，誰憐夜月揀寒枝。", "載書共羨知幾早，懷土空慚見事遲。", "欲理瘦筇尋五柳，摩挲方竹已成規。"]'),
('7dbe227c-d692-4a00-84f9-f7cacec9afd8','春日田園雜興','馮澄','宋','宋诗','song-poetry','','[]','編闌春思倩吟鞭，著面和風軟似綿。',64,'全唐诗/poet.song.249000.json','["編闌春思倩吟鞭，著面和風軟似綿。", "黄犢烏犍秧穀候，雄蜂雌蝶菜花天。", "把鉏健婦踏烟壟，抱甕丈人分野泉。", "忙事關心在何處，流鶑不聽聽啼鵑。"]'),
('8e097ce3-6117-4df7-8062-c46b47e88136','春日田園雜興二首  其一','梁相','宋','宋诗','song-poetry','','[]','膏雨初晴布穀啼，村村景物正熙熙。',64,'全唐诗/poet.song.249000.json','["膏雨初晴布穀啼，村村景物正熙熙。", "誰知農圃無窮樂，自與鶑花有舊期。", "彭澤歸來惟種柳，石湖老去最能詩。", "桃紅李白新秧綠，問著東風總不知。"]'),
('5123b357-8dc4-4d76-90d4-f97f52c66330','春日田園雜興二首  其二','梁相','宋','宋诗','song-poetry','','[]','麥疇連草色，蔬逕带蕪痕。',48,'全唐诗/poet.song.249000.json','["麥疇連草色，蔬逕带蕪痕。", "布穀叫殘雨，杏花開半村。", "吾生老農圃，世事付兒孫。", "但遇芳菲景，高歌酒滿尊。"]'),
('f8f22317-97c6-4ad8-868e-5a81597199a9','春日田園雜興','仙村人','宋','宋诗','song-poetry','','[]','芳草東郊外，疏籬野老家。',48,'全唐诗/poet.song.249000.json','["芳草東郊外，疏籬野老家。", "平疇一尺水，小圃百般花。", "青箬閑耕雨，紅裙鬬采茶。", "村村寒食近，插柳遍檐牙。"]'),
('10028c67-6de9-454c-9d7f-bfae3738cfae','春日田園雜興','楊本然','宋','宋诗','song-poetry','','[]','春風建業馬如飛，誰肯田園拂袖歸。',64,'全唐诗/poet.song.249000.json','["春風建業馬如飛，誰肯田園拂袖歸。", "栗里久無彭澤賦，松江僅有石湖詩。", "踏歌槌鼓麥秧綠，沽酒裹鹽菘芥肥。", "吳下風流今莫續，杜鵑啼處草離離。"]'),
('5a4ac591-9e4c-4c43-89af-ad1782bc70a7','春日田園雜興','全璧','宋','宋诗','song-poetry','','[]','倦遊歸隠白雲鄉，芳草庭閑晝日長。',64,'全唐诗/poet.song.249000.json','["倦遊歸隠白雲鄉，芳草庭閑晝日長。", "晉氏衣冠門外柳，豳人風俗屋邊桑。", "青林伐鼓村村社，綠水平疇處處秧。", "未分東風欺老眼，一編牛背卧斜陽。"]'),
('60518b2c-7b3f-41dc-a422-91e2cae758ff','春日田園雜興','呂文老','宋','宋诗','song-poetry','','[]','月筩紀閏附青煒，民野陶然化日熙。',64,'全唐诗/poet.song.249000.json','["月筩紀閏附青煒，民野陶然化日熙。", "祀備枌榆祈稔歲，宴酣花柳樂清時。", "洛中富貴斜陽恨，綿上勳勞千古思。", "浩興歸來吟不盡，陶詩和後和豳詩。"]'),
('f4758d11-5801-47b5-adfa-3e397fbbfda0','春日田園雜興','方德麟','宋','宋诗','song-poetry','','[]','繞畦晴綠弄潺湲，倚杖東風却黯然。',64,'全唐诗/poet.song.249000.json','["繞畦晴綠弄潺湲，倚杖東風却黯然。", "往夢更誰憐秀麥，閒愁空自託啼鵑。", "犁鉏相種地力盡，花柳無私春色偏。", "白髪老農猶健在，一蓑牛背聽鳴泉。"]'),
('3f61b995-0ee9-4f0c-9343-f60377992fee','題鄭所南老子推蓬竹圖','方德麟','宋','宋诗','song-poetry','','[]','雅操端如金鐵，幾度凌霜傲雪。',28,'全唐诗/poet.song.249000.json','["雅操端如金鐵，幾度凌霜傲雪。", "風前略露烟梢，未許人窺全節。"]'),
('e3411458-15c7-41b5-a459-2c456201e52a','春日田園雜興二首  其一','何鳴鳳','宋','宋诗','song-poetry','','[]','東風轉矚又東臯，久賦將蕪力未薅。',64,'全唐诗/poet.song.249000.json','["東風轉矚又東臯，久賦將蕪力未薅。", "古木陰深巢燕弱，荒陂水淺怒蛙豪。", "兒癡方擬半栽秫，身隠尚嫌全種桃。", "何許蕨薇君欲采，饑眠堪羨華山高。"]'),
('f7757269-1d9d-4a42-891a-80f3f135130d','春日田園雜興二首  其二','何鳴鳳','宋','宋诗','song-poetry','','[]','星明天駟兆興農，稼圃犁鉏處處同。',64,'全唐诗/poet.song.249000.json','["星明天駟兆興農，稼圃犁鉏處處同。", "播穀競趨新禹甸，條桑猶記舊豳風。", "草緣疆畎縱橫綠，花隔藩籬深淺紅。", "自笑偷生勞種植，西山輸與采薇翁。"]'),
('8b5067fb-df49-463d-9ce3-6b9f71f097a4','春日田園雜興','翁合老','宋','宋诗','song-poetry','','[]','韶華到處入冥搜，郭外人家事更幽。',64,'全唐诗/poet.song.249000.json','["韶華到處入冥搜，郭外人家事更幽。", "土脈正融催觳觫，林陰微合聽鉤輈。", "誰家酒熟社公醉，明日桑空蠶妾愁。", "祇恐春工忙裏度，又吟風雨滿城秋。"]'),
('65485992-534f-4bb7-8f5e-5bedb7ced652','春日田園雜興','劉蒙山','宋','宋诗','song-poetry','','[]','桑風吹綠滿原頭，西崦東臯暖氣浮。',64,'全唐诗/poet.song.249000.json','["桑風吹綠滿原頭，西崦東臯暖氣浮。", "村婦祈蠶分麵絸，老農占歲說泥牛。", "田烏飛逐耕烟犢，桑扈鳴隨喚雨鳩。", "鄰叟相邀同社飲，旋將新酒向花篘。"]'),
('b48b965e-eb21-4687-ba89-c92419dc6d47','春日田園雜興','周暕','宋','宋诗','song-poetry','','[]','蛙聲似吹雨初足，桑葚欲紅風始和。',64,'全唐诗/poet.song.249000.json','["蛙聲似吹雨初足，桑葚欲紅風始和。", "少婦每憂蠶利薄，老夫惟喜秫苗多。", "舊栽花木山鶑識，新買陂塘野鷺過。", "此境東風元自好，當年金谷事如何。"]'),
('7546a27c-90b5-4c8e-87e6-e9371c353f54','送僧歸蜀','周暕','宋','宋诗','song-poetry','','[]','詩禪寄杖錫，不問道途難。',48,'全唐诗/poet.song.249000.json','["詩禪寄杖錫，不問道途難。", "到水浮杯渡，逢山卸笠看。", "悟空諸念寂，傳佛一燈寒。", "蜀國又歸去，令人憶道安。"]'),
('ef7b50e5-08bb-47d1-8185-4d7df1a531de','寄悅上人','周暕','宋','宋诗','song-poetry','','[]','一錫千峰遠，聞師住少林。',48,'全唐诗/poet.song.249000.json','["一錫千峰遠，聞師住少林。", "雲生坐處石，佛見定時心。", "清福人間少，紅塵山外深。", "何當重問訊，來借朱堂吟。"]'),
('41316675-bfe0-4de8-9d74-d429c6b02d49','次秋山月上人韻','周暕','宋','宋诗','song-poetry','','[]','十指曾彈月下琴，已知太古有遺音。',64,'全唐诗/poet.song.249000.json','["十指曾彈月下琴，已知太古有遺音。", "三乘四諦無非道，萬法千門只此心。", "得句何妨聞鼓□，□機不復有魔侵。", "近來□□□□□，無奈□□三尺深。"]'),
('decdef68-0459-4155-8d04-5231c90b4376','次僧韻','周暕','宋','宋诗','song-poetry','','[]','曾對寒爐細畫灰，幾番回首重徘徊。',64,'全唐诗/poet.song.249000.json','["曾對寒爐細畫灰，幾番回首重徘徊。", "山間已有幽人占，門外寧教俗子來。", "老杜句留修覺寺，東坡詩在妙高臺。", "新凉擬辦登山屐，莫待黄花逸興催。"]'),
('d01a9ca3-4764-472a-98cb-21d1afc302a3','聞平湖僧紹義自嶺歸又入浙','周暕','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾寫當年送別詩，小窗幾度夢魂飛。',64,'全唐诗/poet.song.249000.json','["曾寫當年送別詩，小窗幾度夢魂飛。", "句從薝蔔林中得，人在梅花嶺外歸。", "禮罷祖師無有相，遍參老宿悟來機。", "歸舟久駐西湖上，聞道新來景又非。"]'),
('b60b179b-7f40-4b86-be55-4ac8195096a8','春日田園雜興','趙必范','宋','宋诗','song-poetry','','[]','一歲農功只在春，夫夫婦婦幾艱辛。',64,'全唐诗/poet.song.249000.json','["一歲農功只在春，夫夫婦婦幾艱辛。", "青門舊有種瓜地，綠野新添躬稼人。", "早把牛衣教諸子，欲修蠶具問良辰。", "夜來谷口東風過，只恐逢人問子真。"]'),
('29ec7dac-7163-4e52-ac7b-c44ef796583a','句  其一','趙必范','宋','宋诗','song-poetry','','[]','卜歲聊憑六壬課，有生未識五辛盤。',16,'全唐诗/poet.song.249000.json','["卜歲聊憑六壬課，有生未識五辛盤。"]'),
('58a6151a-a544-415a-ac6e-547bed42397c','句  其二','趙必范','宋','宋诗','song-poetry','','[]','幸有漁樵同此樂，苦無車馬自相諠。',16,'全唐诗/poet.song.249000.json','["幸有漁樵同此樂，苦無車馬自相諠。"]'),
('4afeb606-8946-4c42-878c-5f08d74b4f99','句  其三','趙必范','宋','宋诗','song-poetry','','[]','幾點飛花芳徑雨，一雙新燕荻簾風。',16,'全唐诗/poet.song.249000.json','["幾點飛花芳徑雨，一雙新燕荻簾風。"]'),
('a8443a62-5aac-45d4-9db3-d8c2439f3fde','句  其四','趙必范','宋','宋诗','song-poetry','','[]','茭白生苗藏蛤地，桑黄含葚浴蠶天。',16,'全唐诗/poet.song.249000.json','["茭白生苗藏蛤地，桑黄含葚浴蠶天。"]'),
('42ba65cd-d28f-44ee-9080-7526b158335e','春日田園雜興','姚潼翔','宋','宋诗','song-poetry','','[]','壁寫新年百事昌，春盤次第蓼芽香。',64,'全唐诗/poet.song.249000.json','["壁寫新年百事昌，春盤次第蓼芽香。", "燒燈過了爭挑菜，祭社歸來便撒秧。", "布穀幾聲催耜畝，吳蠶三伏正條桑。", "一春忙過無多日，又聽鸝鶊報麥黄。"]'),
('83ea3502-9a06-48e3-8041-cbea10429ea1','春日田園雜興','高鎔','宋','宋诗','song-poetry','','[]','已學淵明早賦歸，東風吹醒夢中非。',64,'全唐诗/poet.song.249000.json','["已學淵明早賦歸，東風吹醒夢中非。", "鶑聲睍睆來談舊，牛背安閑勝策肥。", "時聽樵歌時牧笛，間披道氅間農衣。", "篇詩那可形容盡，何似忘言對夕暉。"]'),
('00c72830-2dab-4e65-8b34-b7f98dfeff4a','春日田園雜興','吳㻦','宋','宋诗','song-poetry','','[]','野水渾邊戲乳鵝，疏籬缺處曬耕蓑。',64,'全唐诗/poet.song.249000.json','["野水渾邊戲乳鵝，疏籬缺處曬耕蓑。", "草青隨意牛羊卧，門靜無人燕雀多。", "夫倦倚犁需婦饁，翁歡擊壤和孫歌。", "新來別有營生計，又喜巡檐住蜜窠。"]'),
('9114590a-b744-42ef-8c3d-f16da5c497a8','游罏山','吳㻦','宋','宋诗','song-poetry','','[]','通都無羊腸，罏中有羊腸。',60,'全唐诗/poet.song.249000.json','["通都無羊腸，罏中有羊腸。", "都人有羊腸，罏人無羊腸。", "發原馬之肝，委蛇豸之背。", "曲曲達藍橋，意與仙靈會。", "靜夜非笙簧，依微送天籟。"]'),
('6ba7c4b1-c14e-41a4-8987-fbb911d7ddbc','春日田園雜興','胡南','宋','宋诗','song-poetry','','[]','世數有遷革，田園無古今。',48,'全唐诗/poet.song.249000.json','["世數有遷革，田園無古今。", "鳥喧爭樹暖，牛倦憩牆陰。", "水活土膏動，風微花氣深。", "淵明千古士，佇立此時心。"]'),
('a1b5a995-dfa0-4f58-96bb-9a0ba0981594','春日田園雜興','姜霖','宋','宋诗','song-poetry','','[]','老盆傾酒試新嘗，社鼓村村閙夕陽。',64,'全唐诗/poet.song.249000.json','["老盆傾酒試新嘗，社鼓村村閙夕陽。", "麥隴風微牛睡穩，芹塘泥滑燕歸忙。", "半村飛雨斷烟濕，一徑落花流水香。", "鼎貴安知此中意，徒能學犬吠村莊。"]'),
('796109f3-22dc-46d3-9c7a-82f12ea9007c','春日田園雜興','東必曾','宋','宋诗','song-poetry','','[]','噀綠郊原春事深，治生幽趣豁塵襟。',64,'全唐诗/poet.song.249000.json','["噀綠郊原春事深，治生幽趣豁塵襟。", "聲聲禽語耕人意，種種花開老圃心。", "桑葉漸舒梯欲整，麥苗暗長路難尋。", "日長雖有荷鉏倦，薄暮歸來常醉吟。"]'),
('322024b0-980d-4530-b567-31cac948dc53','春日田園雜興','方子靜','宋','宋诗','song-poetry','','[]','東臯雨後土膏肥，夙駕烏犍出短扉。',64,'全唐诗/poet.song.249000.json','["東臯雨後土膏肥，夙駕烏犍出短扉。", "秧水平疇蛙閣閣，菜花滿稜蝶飛飛。", "比鄰社酒歡猶在，牆壁農書事已非。", "獨喜桑麻今正長，淵明歸去最知幾。"]'),
('d198041e-b1c8-4d5e-91dc-c82749920d0c','春日田園雜興','朱孟翁','宋','宋诗','song-poetry','','[]','餖飣蔬槃已竹萌，如何布穀未催耕。',64,'全唐诗/poet.song.249000.json','["餖飣蔬槃已竹萌，如何布穀未催耕。", "牧兒懶散騎牛過，遊子牽連信馬行。", "秧際窺魚翹白鷺，花間捎蝶下黄鶑。", "東風歲歲添新綠，獨我霜髯多幾莖。"]'),
('ce0e0f07-a84b-4dce-bcd9-e0ef5f5eef32','春日田園雜興','趙必拆','宋','宋诗','song-poetry','','[]','一段佳山水，芳時事正妍。',48,'全唐诗/poet.song.249000.json','["一段佳山水，芳時事正妍。", "犢耕青燒雨，鶴卧碧桃烟。", "社老邀嘗煮，鄰僧伴摘鮮。", "莫嫌陶令拙，農圃得餘年。"]'),
('f92e83f9-0954-4959-a848-f59267f3f55a','春日田園雜興','劉時可','宋','宋诗','song-poetry','','[]','土膏初動雨初收，草徑茅亭趣最幽。',64,'全唐诗/poet.song.249000.json','["土膏初動雨初收，草徑茅亭趣最幽。", "坐睡略無朝市夢，踏歌時有里閭遊。", "半丘秧秫醉堪酒，五畝樹桑寒可裘。", "老圃老農誠足學，不成吾道付滄洲。"]'),
('be7deb8b-7712-4971-a9cc-8f7eb41af3b5','春日田園雜興','釋了慧','宋','宋诗','song-poetry','','[]','平疇水遶徑微分，小圃雲深景不繁。',64,'全唐诗/poet.song.249000.json','["平疇水遶徑微分，小圃雲深景不繁。", "此處農桑雖是僻，多情鶑燕不嫌村。", "倦眠芳草閑黄犢，靜對幽花倒綠樽。", "見說弓旌方四出，欲更名姓掩衡門。"]'),
('70a81cec-d3f7-4a39-845f-56e908901e93','春日田園雜興','許元發','宋','宋诗','song-poetry','','[]','片雲豈是出山時，曾被東風誤一吹。',64,'全唐诗/poet.song.249000.json','["片雲豈是出山時，曾被東風誤一吹。", "歸意不煩啼鴂勸，閑情只許落花知。", "桑麻窮巷扉長掩，烟火空林黍自炊。", "栗里輞川非謬計，晴窗子細味渠詩。"]'),
('c56e8201-ae64-4d23-9f2f-79dd169001f0','春日田園雜興','洪貴叔','宋','宋诗','song-poetry','','[]','棄官杜甫罹天寶，辭令陶潜歎義熙。',64,'全唐诗/poet.song.249000.json','["棄官杜甫罹天寶，辭令陶潜歎義熙。", "暖日浣溪仍舊迹，春風栗里只前時。", "苗生阡陌培嘉種，花繞林塘發故枝。", "佳興二公能領會，可能胸次太多詩。"]'),
('19bbe218-6e69-4ac9-813a-4819d6eadfa4','春日田園雜興','楊舜舉','宋','宋诗','song-poetry','','[]','露畦烟陌裏，名利等秋毫。',48,'全唐诗/poet.song.249000.json','["露畦烟陌裏，名利等秋毫。", "引犢隨牛放，祈蠶望繭繅。", "和根挑薺菜，带葉摘櫻桃。", "讀罷歸來賦，臨風欲和陶。"]'),
('a577e88e-6b10-4440-9025-396d79614b97','春日田園雜興','徐端甫','宋','宋诗','song-poetry','','[]','曉出東郊跨蹇馿，弄晴微雨潤如酥。',64,'全唐诗/poet.song.249000.json','["曉出東郊跨蹇馿，弄晴微雨潤如酥。", "犬依桑下烏犍卧，鳩雜花間黄鳥呼。", "楊柳嫩摇風氣力，稻秧新著雨工夫。", "農家滋味誰知得，飽飫豚蹄酒一盂。"]'),
('6ef8f1ca-9fc9-4b81-96ba-0e57d61c5219','春日田園雜興','朱釋老','宋','宋诗','song-poetry','','[]','家山萬象春歸好，詩筆拈來感物情。',64,'全唐诗/poet.song.249000.json','["家山萬象春歸好，詩筆拈來感物情。", "泉脈動時毋待灌，土膏起處正宜耕。", "無窮懷抱風和暢，不盡形容雨發生。", "試問封侯萬里客，何如守拙晉淵明。"]'),
('64b3114a-5279-4935-a06f-0952fb3e9b6c','春日田園雜興','李萼','宋','宋诗','song-poetry','','[]','村居只是舊衣冠，北墅南園熟往還。',64,'全唐诗/poet.song.249000.json','["村居只是舊衣冠，北墅南園熟往還。", "雨外泥深牛觳觫，花邊風暖鳥閒關。", "躬耕自得莘郊樂，日涉誰知陶逕閑。", "只說桑麻元自好，不須釋耒歎時艱。"]'),
('bc4225c8-b350-4eb3-8887-936ac58a3f06','春日田園雜興二首  其一','陳公凱','宋','宋诗','song-poetry','','[]','春風冗我田園務，野思芳情約不齊。',64,'全唐诗/poet.song.249000.json','["春風冗我田園務，野思芳情約不齊。", "檢點瓜邱仍芋壟，按行桑墅更秧畦。", "偶陪靈運山前屐，或學東坡雨外犁。", "薄暮倦歸專一事，旋誅生菜甕黄虀。"]'),
('cb4c22fa-380c-4511-a930-5a3cfc064a14','春日田園雜興二首  其二','陳公凱','宋','宋诗','song-poetry','','[]','世事不挂眼，寄情農圃中。',48,'全唐诗/poet.song.249000.json','["世事不挂眼，寄情農圃中。", "鉏犁衝曉雨，杖屨立東風。", "芽穀驗仁脈，澆花趲化工。", "獨餘真意味，濁酒自燒菘。"]'),
('4de58f41-3b64-4535-a9ee-2040777a10f3','春日田園雜興','蔡潭','宋','宋诗','song-poetry','','[]','雲過催花雨，風收困麥烟。',48,'全唐诗/poet.song.249000.json','["雲過催花雨，風收困麥烟。", "一鋤天地裏，三月翠紅邊。", "朝市雖無夢，郊墟似有緣。", "種瓜何代叟，豈識趣熙然。"]'),
('0762abbf-21e4-4ecf-b546-9501c8520fc3','春日田園雜興','俞自得','宋','宋诗','song-poetry','','[]','暄和春景好供詩，日暖風輕土脈肥。',64,'全唐诗/poet.song.249000.json','["暄和春景好供詩，日暖風輕土脈肥。", "白鷺時窺秧刺刺，黄鶑頻說柳依依。", "幾回野水聞姑惡，數樹春英叫姊歸。", "物態滿前看不足，等閑吟詠對斜暉。"]'),
('f75f86f5-8d68-4071-a420-240deb07b2d9','春日田園雜興','東湖散人','宋','宋诗','song-poetry','','[]','物色天成畫不如，東風又到野人廬。',64,'全唐诗/poet.song.249000.json','["物色天成畫不如，東風又到野人廬。", "蜜蜂辛苦供常課，科斗縱橫學古書。", "小雨杏花村問酒，澹煙楊柳巷巾車。", "汀洲水暖蘆芽長，更買扁舟伴老漁。"]'),
('eb43abe0-d4ac-4020-a782-c6c572a8203d','春日田園雜興','感興吟','宋','宋诗','song-poetry','','[]','兒結蓑衣婦浣紗，暖風疏雨趲桑麻。',64,'全唐诗/poet.song.249000.json','["兒結蓑衣婦浣紗，暖風疏雨趲桑麻。", "金桃接種連花蕊，紫竹移根带筍芽。", "椎鼓踏歌朝祭社，賣薪挑菜晚回家。", "前村犬吠無他事，不是搜鹽定榷茶。"]'),
('ef5aed88-c81f-440c-bee0-290d746028e8','春日田園雜興二首  其一','王進之','宋','宋诗','song-poetry','','[]','桑田滄海幾興亡，歲歲東風自扇揚。',64,'全唐诗/poet.song.249000.json','["桑田滄海幾興亡，歲歲東風自扇揚。", "細麥新秧隨意長，閑花幽草爲誰芳。", "午橋蕭散名千古，金谷繁華夢一場。", "滿眼春愁禁不得，數聲啼鳥在斜陽。"]'),
('fe512c2c-2f72-491c-9cc6-5d5812f8106b','春日田園雜興二首  其二','王進之','宋','宋诗','song-poetry','','[]','東君私我此閑身，脫却青衫野服更。',64,'全唐诗/poet.song.249000.json','["東君私我此閑身，脫却青衫野服更。", "桑可以絲麻可績，麥宜續食韭宜羹。", "分甘壟上耕雲隠，夢不湖邊拾翠行。", "物意豈知滄海變，曉風依舊語流鶑。"]'),
('e9d353f9-38ba-4a9f-8d34-8bbed52b2748','春日田園雜興五首  其一','陳希聲','宋','宋诗','song-poetry','','[]','香紅眩眼纈蕤英，竹杖扶吟縱步行。',64,'全唐诗/poet.song.249000.json','["香紅眩眼纈蕤英，竹杖扶吟縱步行。", "桑眼蟆含青蕾小，麥鬚蝦磔翠芒輕。", "黄花菜圃午風軟，綠水秧畦春野平。", "芳樹幾聲鳩雨過，蒼蒼柳色弄烟晴。"]'),
('3aa7f226-062c-42b6-af27-dfbdecb5b050','春日田園雜興五首  其二','陳希聲','宋','宋诗','song-poetry','','[]','犁鉏徧野沸耕農，血吻鵑聲一樹紅。',64,'全唐诗/poet.song.249000.json','["犁鉏徧野沸耕農，血吻鵑聲一樹紅。", "畦矗秧針青剡剡，隴翻麥浪翠芃芃。", "雞鳴晝寂花村雨，蛤吠朝寒草岸風。", "溪外雲過橫笛亂，微煙野色樹蘢葱。"]'),
('735c6957-7f1f-4fad-bd33-d109ecb2708e','春日田園雜興五首  其三','陳希聲','宋','宋诗','song-poetry','','[]','田園興在早春時，眼纈生紅喜上眉。',64,'全唐诗/poet.song.249000.json','["田園興在早春時，眼纈生紅喜上眉。", "門巷日高人掃雪，池塘煙漲水流澌。", "杯柈新歲歡同社，燈火元宵閙古祠。", "野老告余春事及，夜來小雨過前陂。"]'),
('aae2a834-8f21-4c0f-b4f4-b482b46b5d22','春日田園雜興五首  其四','陳希聲','宋','宋诗','song-poetry','','[]','田園興在半春天，春事關心夜不眠。',64,'全唐诗/poet.song.249000.json','["田園興在半春天，春事關心夜不眠。", "護撒秧畦須擁水，闢栽蔬圃更隄川。", "青囊子粒鄉風舊，翠箬靈芽社雨前。", "獨立斜陽無限意，一聲撥穀野橋邊。"]'),
('d7dd95aa-2a40-4264-8f8f-6e66b2483dbd','春日田園雜興五首  其五','陳希聲','宋','宋诗','song-poetry','','[]','田園興在晚春頭，且說田蠶兩事休。',64,'全唐诗/poet.song.249000.json','["田園興在晚春頭，且說田蠶兩事休。", "榆莢雨酣新水滑，楝花風軟薄寒收。", "青楓蛾子催桑月，綠樹鸝鶊報麥秋。", "但願花村無吠犬，時呼薄酒背眠牛。"]'),
('8a3c130c-db1e-4d39-a3b0-acc5454689c6','春日田園雜興三首  其一','戴東老','宋','宋诗','song-poetry','','[]','飲了椒盤收了燈，翁携稚子步新晴。',64,'全唐诗/poet.song.249000.json','["飲了椒盤收了燈，翁携稚子步新晴。", "茅柴初熟勝臘醖，萊菔久虀宜晚羹。", "伏卵雞留上春種，出欄牛試吉辰耕。", "去年官賦今年罷，寂甚門前犬吠聲。"]'),
('c3c8d895-bf2a-47b1-89cf-5b46c2148b68','春日田園雜興三首  其二','戴東老','宋','宋诗','song-poetry','','[]','昨夜西郊雷隠鳴，金穰檢歷兆秋成。',64,'全唐诗/poet.song.249000.json','["昨夜西郊雷隠鳴，金穰檢歷兆秋成。", "槍旗味向茶畦蓄，餠餌香從麥隴生。", "拂去梁塵招燕乳，撥開檐網看蜂營。", "誰家子女群喧笑，競學賣花吟叫聲。"]'),
('3afe6876-f086-4aaa-bc1d-33631e0f59f6','春日田園雜興三首  其三','戴東老','宋','宋诗','song-poetry','','[]','野花村醖賞清明，挑菜踏青魚隊行。',64,'全唐诗/poet.song.249000.json','["野花村醖賞清明，挑菜踏青魚隊行。", "禊水戲浮觴白羽，厨煙不禁飯黄精。", "田功宜早秧勤插，桑價方高繭告成。", "莫道犁鉏忘學問，讀書聲間織機聲。"]'),
('e12f564c-22c8-4dfa-be89-25ab06b46567','春日田園雜興','陳文增','宋','宋诗','song-poetry','','[]','熙熙壠畝扇和風，簇簇人煙野意濃。',64,'全唐诗/poet.song.249000.json','["熙熙壠畝扇和風，簇簇人煙野意濃。", "培溉桑麻沿汲路，經行薺麥省耕農。", "飲牛澗暖山摇影，接果枝青蘚拆封。", "酒熟花香村欲社，芒鞵藤杖儘從容。"]'),
('1a30bab6-9274-4730-9f42-38a3278cc931','春日田園雜興','九山人','宋','宋诗','song-poetry','','[]','軒裳一夢斷塵寰，桑柘陰陰靜掩關。',64,'全唐诗/poet.song.249000.json','["軒裳一夢斷塵寰，桑柘陰陰靜掩關。", "種秫已非彭澤縣，采薇何必首陽山。", "因憐社鼓剛催老，轉覺儒冠不負閑。", "君看浣花堂上燕，芹泥雖好亦知還。"]'),
('568f7351-f768-4d58-9e55-adb294fc59c8','春日田園雜興','桑柘區','宋','宋诗','song-poetry','','[]','粟爵瓜官懶覬覦，生涯雲水與煙腴。',64,'全唐诗/poet.song.249000.json','["粟爵瓜官懶覬覦，生涯雲水與煙腴。", "晚風一笛麥秧隴，春雨半鉏桑柘區。", "可是樊遲宜請學，肯教陶亮歎將蕪。", "斜陽芳草關情處，更把新詩弔石湖。"]'),
('66b1fde1-9358-47f6-a329-326e682dba46','春日田園雜興','柳州','宋','宋诗','song-poetry','','[]','東風生意閙，農圃正宜勤。',48,'全唐诗/poet.song.249000.json','["東風生意閙，農圃正宜勤。", "稻種開包曬，菊苗依譜分。", "疇西曉耕雨，舍北暮鉏雲。", "莫待荒三徑，歸歟陶令君。"]'),
('28896a1f-0d82-4e8c-810e-71ea06d76824','春日田園雜興','草堂後人','宋','宋诗','song-poetry','','[]','桑眼已開芳晝長，西疇東墅足相羊。',64,'全唐诗/poet.song.249000.json','["桑眼已開芳晝長，西疇東墅足相羊。", "麥風初暖燕爭壘，林雨忽晴蛙滿塘。", "野老新衣逢社喜，山妻椎髻爲蠶忙。", "紛紛遊騎踏花去，誰識吾家舊草堂。"]'),
('7bb68c12-cc96-4426-a7fd-4815098013e3','春日田園雜興','君瑞','宋','宋诗','song-poetry','','[]','白粉牆頭紅杏花，竹槍籬下種絲瓜。',64,'全唐诗/poet.song.249000.json','["白粉牆頭紅杏花，竹槍籬下種絲瓜。", "厨煙乍熟抽心菜，篝火新乾捲葉茶。", "草地雨長應易墾，秧田水足不須車。", "白頭翁嫗閑無事，對坐花陰到日斜。"]'),
('f1200f22-aab1-4fda-b658-aa4fa7da143f','春日田園雜興','青山白雲人','宋','宋诗','song-poetry','','[]','昨夜東風雨一犁，曉晴鄰巷共熙熙。',64,'全唐诗/poet.song.249000.json','["昨夜東風雨一犁，曉晴鄰巷共熙熙。", "遮門賸喜有桑柘，輸國不憂無繭絲。", "小婦餉耕因廢織，老夫觀社忽成詩。", "眼前物物是生意，却恨淵明歸計遲。"]'),
('10171ba4-fce8-49e7-9eab-f8f6cdcbc8ec','句','無機老農','宋','宋诗','song-poetry','','[]','名利有危機，老於農圃宜。',12,'全唐诗/poet.song.249000.json','["名利有危機，老於農圃宜。"]'),
('62f531d6-b3f5-4f6b-b57e-8bdadc275ef6','句','子問','宋','宋诗','song-poetry','','[]','驅却餘寒碎土牛，田園生計又從頭。',16,'全唐诗/poet.song.249000.json','["驅却餘寒碎土牛，田園生計又從頭。"]'),
('e23ca31b-27c6-4bf0-bc50-6932380fe9e2','句','田農夫','宋','宋诗','song-poetry','','[]','桃李場中已免參，只將農圃繫頭銜。',16,'全唐诗/poet.song.249000.json','["桃李場中已免參，只將農圃繫頭銜。"]'),
('89363efd-2360-4498-aa5a-9d1a7f727c05','句','唐人機軸','宋','宋诗','song-poetry','','[]','風暖柴荆鳥語幽，麥高麻矮野桑柔。',16,'全唐诗/poet.song.249000.json','["風暖柴荆鳥語幽，麥高麻矮野桑柔。"]'),
('4156832d-93a7-4873-a7bf-ec0c38519222','句','忘懷老人','宋','宋诗','song-poetry','','[]','寸地不可棄，東風何處無。',12,'全唐诗/poet.song.249000.json','["寸地不可棄，東風何處無。"]'),
('6476ae16-a942-4351-9b1a-d3a15263da84','句','五雲山人','宋','宋诗','song-poetry','','[]','種瓜思夏實，分菊待秋花。',12,'全唐诗/poet.song.249000.json','["種瓜思夏實，分菊待秋花。"]'),
('92a1f2ca-adc6-4a8a-8117-2799604f3a1c','句','老農','宋','宋诗','song-poetry','','[]','幸存耕雨地，况值養花時。',12,'全唐诗/poet.song.249000.json','["幸存耕雨地，况值養花時。"]'),
('a9505001-8e0f-4c78-8e77-e336122a24f1','句','劉存行','宋','宋诗','song-poetry','','[]','麥苗花下綠，犢子草邊黄。',12,'全唐诗/poet.song.249000.json','["麥苗花下綠，犢子草邊黄。"]'),
('ed20049d-6eb2-4af7-bad9-3ef62f02b152','句','石姥寄客','宋','宋诗','song-poetry','','[]','水暖眠秧珥，風香豎茗旗。',12,'全唐诗/poet.song.249000.json','["水暖眠秧珥，風香豎茗旗。"]'),
('cf304459-0356-4538-bd2c-bc6766455852','句','雙澗','宋','宋诗','song-poetry','','[]','雨露桑麻清夜話，晴明花柳少年心。',16,'全唐诗/poet.song.249000.json','["雨露桑麻清夜話，晴明花柳少年心。"]'),
('f7b486c3-3359-4895-b488-e112485f9c3a','句','雲水','宋','宋诗','song-poetry','','[]','晴雨花時遊子意，寒暄秧信老農心。',16,'全唐诗/poet.song.249000.json','["晴雨花時遊子意，寒暄秧信老農心。"]'),
('bd9737b7-220d-48e2-b46f-43599129c224','句','白雲人','宋','宋诗','song-poetry','','[]','犢外醉分芳草卧，鶑邊吟踏落花行。',16,'全唐诗/poet.song.249000.json','["犢外醉分芳草卧，鶑邊吟踏落花行。"]'),
('ed724183-1603-49ea-b786-c9188c9c2d7c','句','傅宣山','宋','宋诗','song-poetry','','[]','耕鉏曉雨有餘地，應接東風無暇時。',16,'全唐诗/poet.song.249000.json','["耕鉏曉雨有餘地，應接東風無暇時。"]'),
('08c8e3db-bf72-48dd-815f-dd3edf123073','句','柳耆','宋','宋诗','song-poetry','','[]','野犢正忙犁曉雨，谷鶑才出管東風。',16,'全唐诗/poet.song.249000.json','["野犢正忙犁曉雨，谷鶑才出管東風。"]'),
('26eba525-2093-40e0-a725-689c070730f6','句','俞如山','宋','宋诗','song-poetry','','[]','鳥隨牛後窺秧穀，蝶趁蜂來戀菜花。',16,'全唐诗/poet.song.249000.json','["鳥隨牛後窺秧穀，蝶趁蜂來戀菜花。"]'),
('0f63481d-4a3e-48a7-838d-f9350c32cc93','句','跨犢者','宋','宋诗','song-poetry','','[]','有酒便嘗烹笋蕨，無花聊自賞桑麻。',16,'全唐诗/poet.song.249000.json','["有酒便嘗烹笋蕨，無花聊自賞桑麻。"]'),
('2fe80a0c-e2ef-425b-a6f7-9a7ba2576539','句','佚名','宋','宋诗','song-poetry','','[]','社近記穿黄繭子，雨前趲摘紫槍旗。',16,'全唐诗/poet.song.249000.json','["社近記穿黄繭子，雨前趲摘紫槍旗。"]'),
('1eaf1df7-1c16-429e-a5ef-b5c50a31e121','句','山野人','宋','宋诗','song-poetry','','[]','鶑藏楊柳金歌舞，蝶宿梨花雪夢魂。',16,'全唐诗/poet.song.249000.json','["鶑藏楊柳金歌舞，蝶宿梨花雪夢魂。"]'),
('27e69879-5c8e-4429-80a2-26fca6cff8e2','句','盤隠末子','宋','宋诗','song-poetry','','[]','桃林我憶放牛日，葵圃誰思逸馬時。',16,'全唐诗/poet.song.249000.json','["桃林我憶放牛日，葵圃誰思逸馬時。"]'),
('8274c7b1-a891-4052-ab9a-68a03c01a653','句','扶杖夫','宋','宋诗','song-poetry','','[]','一生甘作扶犁手，萬變寧移抱甕心。',16,'全唐诗/poet.song.249000.json','["一生甘作扶犁手，萬變寧移抱甕心。"]'),
('ffbd7067-b70a-4343-9f17-2610f8a4ddcf','句','廷雲','宋','宋诗','song-poetry','','[]','蛙鳴莫夜官何爲，蝶戀芳菲夢不知。',16,'全唐诗/poet.song.249000.json','["蛙鳴莫夜官何爲，蝶戀芳菲夢不知。"]'),
('d04ad59f-fcda-4289-9c27-c678f454eec2','句','翁自適','宋','宋诗','song-poetry','','[]','鴉趁犁翻爭啄食，蜂粘絮落苦貪香。',16,'全唐诗/poet.song.249000.json','["鴉趁犁翻爭啄食，蜂粘絮落苦貪香。"]'),
('839bbb90-e670-4fb6-ba27-48e518b3eb9b','句','郭建德','宋','宋诗','song-poetry','','[]','烟連草色迷平野，雨趁鳩聲過別村。',16,'全唐诗/poet.song.249000.json','["烟連草色迷平野，雨趁鳩聲過別村。"]'),
('bc613ac5-0123-4ba3-a419-1af776e6f916','句','駱儒賓','宋','宋诗','song-poetry','','[]','烹羆籜龍新上筯，修來秧馬尚依牆。',16,'全唐诗/poet.song.249000.json','["烹羆籜龍新上筯，修來秧馬尚依牆。"]'),
('369e3ade-2c3b-481d-a6ad-4794acba4279','句','陳公舉','宋','宋诗','song-poetry','','[]','清曉蛙聲引啼鴂，夕陽牛背立歸鴉。',16,'全唐诗/poet.song.249000.json','["清曉蛙聲引啼鴂，夕陽牛背立歸鴉。"]'),
('e24f7d75-7993-49d8-a954-e2a627202563','句','晚靜','宋','宋诗','song-poetry','','[]','牛飲芳陂鴉立背，馬過秀野蝶隨蹄。',16,'全唐诗/poet.song.249000.json','["牛飲芳陂鴉立背，馬過秀野蝶隨蹄。"]'),
('aab94373-ba38-4da2-bd47-30677ff2578c','句','竹簑笠翁','宋','宋诗','song-poetry','','[]','蠶一二眠催出伏，秧三四葉尚憂風。',16,'全唐诗/poet.song.249000.json','["蠶一二眠催出伏，秧三四葉尚憂風。"]'),
('26445f5c-3985-49c2-ba42-7b1a4b530e36','句','俞野處','宋','宋诗','song-poetry','','[]','郎罷耕歸呼囝牧，阿翁眠起問姑蠶。',16,'全唐诗/poet.song.249000.json','["郎罷耕歸呼囝牧，阿翁眠起問姑蠶。"]'),
('85acd27d-4683-4e21-9f44-477815888393','句','藍田道人','宋','宋诗','song-poetry','','[]','晴原望新麥，一片綠雲香。',12,'全唐诗/poet.song.249000.json','["晴原望新麥，一片綠雲香。"]'),
('c8c2295c-a694-45dc-a8c0-0034bd5e111e','句','林泉生','宋','宋诗','song-poetry','','[]','桃李公門者，將蕪胡不歸。',12,'全唐诗/poet.song.249000.json','["桃李公門者，將蕪胡不歸。"]'),
('e7375159-e48a-4b2d-a37d-36d262d33114','句','傅九萬','宋','宋诗','song-poetry','','[]','笑他思著蓴鱸者，却感秋風始去官。',16,'全唐诗/poet.song.249000.json','["笑他思著蓴鱸者，却感秋風始去官。"]'),
('91e9fecb-6ea6-4aff-8261-e65c799f121b','句','才人','宋','宋诗','song-poetry','','[]','山翁不識時宜甚，猶學淵明裹葛巾。',16,'全唐诗/poet.song.249000.json','["山翁不識時宜甚，猶學淵明裹葛巾。"]'),
('98f9025e-120b-4d7d-a0d7-f06452d84be0','烏夜啼','宋無','宋','宋诗','song-poetry','','[]','露華洗天天墮水，燭光燒雲半空紫。',144,'全唐诗/poet.song.249000.json','["露華洗天天墮水，燭光燒雲半空紫。", "西施夜醉芙蓉洲，金絲玉簧咽清秋。", "鼙鼓鞭月行春雷，洞房花夢酣不迴。", "宮中夜夜啼栖烏，美人日日歌吳歈。", "吳王國破歌聲絕，鬼火青熒生碧血。", "千年壞塚耕狐兔，烏銜紙錢掛枯樹。", "髑髏無語滿眼泥，曾見吳王歌舞時。", "烏夜啼，啼爲誰。", "身前歡樂身後悲，空留瑟怨傳相思。", "烏夜啼，啼別離。"]'),
('ad69c1bf-75e0-4130-b2c5-1b7f2bbc8eef','自君之出矣二首  其一','宋無','宋','宋诗','song-poetry','','[]','自君之出矣，妾不出閨門。',24,'全唐诗/poet.song.249000.json','["自君之出矣，妾不出閨門。", "懷君不敢恨，惟有感君恩。"]'),
('82b87af2-a451-4b23-ad88-db854920db45','自君之出矣二首  其二','宋無','宋','宋诗','song-poetry','','[]','自君之出矣，妾自奉尊嫜。',24,'全唐诗/poet.song.249000.json','["自君之出矣，妾自奉尊嫜。", "知君不思妾，亦當思故鄉。"]'),
('860def85-f50b-49a2-91fa-9c3639623811','公無渡河','宋無','宋','宋诗','song-poetry','','[]','九龍爭珠戰淵底，洪濤萬丈湧山起。',100,'全唐诗/poet.song.249000.json','["九龍爭珠戰淵底，洪濤萬丈湧山起。", "鱷魚張口奮靈齒，含沙射人毒如矢。", "寧登高山莫涉水，公無渡河，公不可止。", "河伯娶婦蛟龍宅，公無白璧獻河伯，恐公身爲泣珠客。", "公無渡河公不然，憂公老命沉黄泉。", "公沉黄泉，公勿怨天。"]'),
('eedbc227-0793-48ec-8426-1ddd2cfe07a6','戰城南','宋無','宋','宋诗','song-poetry','','[]','漢兵鏖戰城南窟，雪深馬僵漢城沒。',112,'全唐诗/poet.song.249000.json','["漢兵鏖戰城南窟，雪深馬僵漢城沒。", "凍指控弦指斷折，寒膚著鐵膚皸裂。", "軍中七日不火食，手殺降人吞熱血。", "漢懸千金購首級，將士銜枚夜深入。", "天愁地黑聲啾啾，鞍下髑髏相對泣。", "偏裨背負八十創，破旗裹屍橫道旁。", "殘卒忍死哭空城，露布獨有都護名。"]'),
('0aa47b2a-b33e-401f-97eb-fab266b50e0b','公莫舞','宋無','宋','宋诗','song-poetry','','[]','公莫舞，公莫舞，鴻門王氣歸真主。',72,'全唐诗/poet.song.249000.json','["公莫舞，公莫舞，鴻門王氣歸真主。", "何人睚眥赤龍子，手循玉玦目相語。", "令公莫舞公楚舞，劍光射日白虹吐。", "人發殺機天不與，撞斗帳中唉亞父，霸業明朝棄如土。"]'),
('7af52bb0-faf2-4125-a392-9f54a5b49b2d','長門怨','宋無','宋','宋诗','song-poetry','','[]','金壺咽淚蓮花澀，銀箭浮遲渴烏泣。',128,'全唐诗/poet.song.249000.json','["金壺咽淚蓮花澀，銀箭浮遲渴烏泣。", "知更阿監羅襪冰，暝對星河玉階立。", "內官唱漏催曉籌，芙蓉夢破燕支愁。", "起來妝罷窺繡戶，三十六院殘燭幽。", "建章風傳鳳吹遠，翠華晨幸昭儀館。", "箜篌不語心自語，愁長如天恨天短。", "紅裀暖踏楊花雪，絳縷閒封守宮血。", "鸚鵡空猜警蹕聲，春寒緊護流蘇結。"]'),
('57e8f2d2-c223-4a34-af2e-dbc6a4e872ad','寶劍謠','宋無','宋','宋诗','song-poetry','','[]','鐵精蒼玉龍，景潜萬丈虹。',70,'全唐诗/poet.song.249000.json','["鐵精蒼玉龍，景潜萬丈虹。", "孤電走白日，老冰立秋空。", "提出天地愁，八極來清風。", "未逢龍準帝，古匣塵土蒙。", "大蛇當道兮若斷秋蓬，嗚呼寶劍兮亦將遇乎英雄。"]'),
('d9fdfe0f-c8bd-4639-9b14-c7471dcd408c','枯魚過河泣','宋無','宋','宋诗','song-poetry','','[]','北溟有鯤，歕薄崑崙，氣吞積石摧禹門。',113,'全唐诗/poet.song.249000.json','["北溟有鯤，歕薄崑崙，氣吞積石摧禹門。", "過河河水枯，蹤跡困泥塗。", "垂涎向海若，能濟涓滴無。", "中流有魴鯉，不貸斗升水。", "巨口走噞喁，逆游莫若鮪。", "鯤兮鯤兮，爾泣何由。", "龍伯知决雨，津倒天池。", "洚水橫行，隨鯤所之。", "揚鰭爲謝魴與鯉，還有桃花春漲時。"]'),
('a7e769a1-9f8b-4f09-98ff-86e7c1dc4a85','玉津園棄景鐘歌','宋無','宋','宋诗','song-poetry','','[]','炎精不靈火不德，赤熛怒帝喪英魄。',128,'全唐诗/poet.song.249000.json','["炎精不靈火不德，赤熛怒帝喪英魄。", "羿弓射日日無光，黄金大鏞破釜色。", "天崩七廟移神虛，鬼哭長陵一抔土。", "十二盤傾夜月寒，漢銅仙人淚如雨。", "六龍屈曲眠秋草，草根蟪蛄語昏曉。", "紫苔滿地愁古春，東風吹得乾坤老。", "蝸涎鳥篆銀泥剝，烏啄蒲牢戲左角。", "更殘漏斷聲莫聞，凡鷄司晨尊鐵鐸。"]'),
('10d810fa-d541-4738-a1df-3a8400768581','妾薄命','宋無','宋','宋诗','song-poetry','','[]','雲母屏，琢春冰，鮫女織綃蟬翼輕。',96,'全唐诗/poet.song.249000.json','["雲母屏，琢春冰，鮫女織綃蟬翼輕。", "比妾妾薄命，比君君薄情。", "紅綿拭鏡照膽明，還疑妾貌非傾城。", "傾城從來有人妒，况復君心不如故。", "故人心尚峰九疑，新妾那能無故時。", "補天天高，填海海深。", "不食蓮菂，不知妾心。"]'),
('e9f878d2-8a27-42e3-8514-3fec269f1e88','天馬歌','宋無','宋','宋诗','song-poetry','','[]','天馬天上龍，駒生天漢間。',168,'全唐诗/poet.song.249000.json','["天馬天上龍，駒生天漢間。", "兩目夾明月，蹄削崑崙山。", "元氣飲沆瀣，躍步超人寰。", "天上玉帝老不騎，饑食虎豹曉出關。", "滅沒流彗姿，歘忽紫電顔。", "黄道三十六萬里，日馳週天去復還。", "時乎降精渥洼中，龍性變化終難攀。", "天馬來，瑞何朝。", "化爲龍，應童謠。", "騶虞仁獸耻在坰，龍亦絕跡歸赤霄。", "風沙豈無大宛種，雖有八極安能超。", "天馬來，雲霧開。", "天廄騕褭鳴龍媒，龍媒不鳴鳴駑駘。"]'),
('1596759a-d269-4dce-b01e-2ff4a6a866fc','古硯歌','宋無','宋','宋诗','song-poetry','','[]','神媧踏雲補天去，遺下一團蒼黑天。',112,'全唐诗/poet.song.249000.json','["神媧踏雲補天去，遺下一團蒼黑天。", "千年萬年乾不得，長带盤古青紫烟。", "玉工剖天天化石，石內星精有餘魄。", "琱光發炯成禹璧，海王川后輸玄液。", "帝青呵霧坤倪濕，匣月不開太陰泣。", "破天殘缺無人補，一穴絲絲漏春雨。", "空藏老石磨今古，補天何時與天語。"]'),
('21d0b93f-2cb0-42d2-a143-4e54220f23a0','五雜組  其一','宋無','宋','宋诗','song-poetry','','[]','五雜組，角黍絲。',24,'全唐诗/poet.song.249000.json','["五雜組，角黍絲。", "往復還，借書瓻。", "不得已，居九夷。"]'),
('8c29fa86-e5e8-420d-b410-ca646f3831f7','五雜組  其二','宋無','宋','宋诗','song-poetry','','[]','五雜組，冠冕纓。',24,'全唐诗/poet.song.249000.json','["五雜組，冠冕纓。", "往復還，戍卒更。", "不得已，困平城。"]'),
('b965d543-b185-4484-a555-8c6d1a07fdff','湖上意','宋無','宋','宋诗','song-poetry','','[]','晚過鴛鴦浦，無心唱採蓮。',24,'全唐诗/poet.song.249000.json','["晚過鴛鴦浦，無心唱採蓮。", "莫嗔蘭槳急，爲要趁前船。"]'),
('6fe3eeb0-3db7-47d0-aeb2-73640ffa9b71','江上意','宋無','宋','宋诗','song-poetry','','[]','朝來暮還去，寒潮不曾住。',24,'全唐诗/poet.song.249000.json','["朝來暮還去，寒潮不曾住。", "江水亦有情，佳期幾番誤。"]'),
('4bd117c3-2aaa-4a03-b55e-ea53f51a6881','甘露寺放舶至瓜洲風作','宋無','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天造西來險，山迴北固形。',192,'全唐诗/poet.song.249000.json','["天造西來險，山迴北固形。", "斷崖纏赤日，孤柱擘蒼溟。", "此地何能限，長江或有靈。", "然犀夜照浪，飲馬曉吞星。", "鐵鎖沈寥廓，樓船沒杳冥。", "乾坤一衣带，吳楚兩郵亭。", "擊楫人人倦，吹笳處處聽。", "海門沙自白，瓜步草猶青。", "夢墮浮家樂，魂遭捩柁醒。", "計程秋獵地，問舍暮漁汀。", "倏忽波濤變，匆忙網罟停。", "疾飆移蚌室，暗雨卷龍庭。", "贔屭黿鼉壯，谽谺樹石腥。", "危檣連偪仄，高岸失竛竮。", "世事無深測，生涯獨未寧。", "愁煩復消釋，題咏紀曾經。"]'),
('6bf7a445-8389-4c6c-b80c-88765a18986c','送鄧侍郎歸江西','宋無','宋','宋诗','song-poetry','','[]','中國衣冠盡，孤臣蹈海迴。',120,'全唐诗/poet.song.249000.json','["中國衣冠盡，孤臣蹈海迴。", "秦思魯連操，漢憶賈生才。", "天遠文星隠，江平畫鷁摧。", "人尋芳草去，雁到故鄉來。", "山色催行櫂，波聲送客杯。", "身還蘇武節，夢泣李陵臺。", "水落蛟龍縮，城空鼓角哀。", "蒼梧雲浩蕩，黄屋浪崔嵬。", "夜雨江蘺濕，春風杜若開。", "祇令少微動，慎莫應三台。"]'),
('f5751fc8-add5-47d8-9016-bbeab38aac55','李翰林墓  其一','宋無','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','嗜酒傲明時，何因賀監知。',48,'全唐诗/poet.song.249000.json','["嗜酒傲明時，何因賀監知。", "承恩金馬詔，失意玉環詞。", "名與三閭並，身將四皓期。", "匡山有書讀，應亦嘆歸遲。"]'),
('31f355e3-0cb0-4032-823c-12dcfa2491f3','李翰林墓  其二','宋無','宋','宋诗','song-poetry','','[]','一騎紫鯨去，空掩謝山塋。',48,'全唐诗/poet.song.249000.json','["一騎紫鯨去，空掩謝山塋。", "落月今誰弔，長庚夜自明。", "乾坤沈秀氣，江水带哀聲。", "天上多宮府，文章不可輕。"]'),
('f6b315f0-01ab-4500-8b92-955638ad47d4','長相思','宋無','宋','宋诗','song-poetry','','[]','昨夜相逢處，朦朧春夢中。',24,'全唐诗/poet.song.249000.json','["昨夜相逢處，朦朧春夢中。", "遼西書不到，莫是戍遼東。"]'),
('bb89da33-f00c-4771-b81a-43bc0e6bf6f7','月上人還西湖','宋無','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南峰歸度夏，舊業在烟霏。',48,'全唐诗/poet.song.249000.json','["南峰歸度夏，舊業在烟霏。", "半夜聞清磬，一燈明翠微。", "雲蘿尋寺遠，猿狖見人稀。", "想到經行處，天花繞錫飛。"]'),
('d15b9744-d22c-4476-bac0-a1631f33293a','次友人春別','宋無','宋','宋诗','song-poetry','','[]','波流雲散碧天空，魚雁沈沈信不通。',64,'全唐诗/poet.song.249000.json','["波流雲散碧天空，魚雁沈沈信不通。", "楊柳昏黄晚西月，梨花明白夜東風。", "秋千庭院人初下，春半園林酒正中。", "背倚欄桿思往事，畫樓魂夢可曾同。"]'),
('7bbb1de2-a21c-4e92-8175-5e74352bcd87','答王子長','宋無','宋','宋诗','song-poetry','','[]','病後得書頻，情知未立身。',48,'全唐诗/poet.song.249000.json','["病後得書頻，情知未立身。", "孤燈風雨夜，兩處別離人。", "乙鳥歸來社，辛夷開過春。", "如逢元白問，莫說爲詩貧。"]'),
('ff6b4531-fbbc-4aeb-b574-1d267836e111','廢宅','宋無','宋','宋诗','song-poetry','','[]','金谷花開得幾春，東風吹逐路傍塵。',64,'全唐诗/poet.song.249000.json','["金谷花開得幾春，東風吹逐路傍塵。", "蛙鳴私地爲官地，燕認新人是故人。", "珠履賣錢豪客散，玉釵乘傳舞娥顰。", "獸環一鎖歌鐘斷，時有鴞聲恐四鄰。"]'),
('a4881efd-261f-4771-9bdf-fda6d4dc0cd2','春愁','宋無','宋','宋诗','song-poetry','','[]','金雁塵香暗鳳絃，紅繩風緊閣秋千。',32,'全唐诗/poet.song.249000.json','["金雁塵香暗鳳絃，紅繩風緊閣秋千。", "園林寂寞無鶑燕，一段春愁是杜鵑。"]'),
('88b0943b-423f-4e57-b2ae-f2a43661c810','南峰宴坐僧','宋無','宋','宋诗','song-poetry','','[]','空巖槁木形，入定掩松扃。',48,'全唐诗/poet.song.249000.json','["空巖槁木形，入定掩松扃。", "鵲供銜來果，猿看誦罷經。", "雲霞埋衲重，苔蘚上鞋青。", "只有樵人識，曾因採茯苓。"]'),
('82267c27-3faa-4d57-a39c-6983d5b518a4','訪山中隠者','宋無','宋','宋诗','song-poetry','','[]','遥聞擣藥聲，知有幽人家。',24,'全唐诗/poet.song.249000.json','["遥聞擣藥聲，知有幽人家。", "相尋却無路，又隔一谿花。"]'),
('b664b095-1e41-4004-a475-7d2ddfda5c38','別惠上人','宋無','宋','宋诗','song-poetry','','[]','秋歸虎谿月，携錫入雲松。',48,'全唐诗/poet.song.249000.json','["秋歸虎谿月，携錫入雲松。", "又向深山住，還聞古寺鐘。", "出生供野鳥，持呪伏潭龍。", "好去東林下，吟看五老峰。"]'),
('4bb3e776-48dc-43b8-b7ef-73fc6514b16f','銅陵五松山中','宋無','宋','宋诗','song-poetry','','[]','樵聲聞遠林，流水隔雲深。',48,'全唐诗/poet.song.249000.json','["樵聲聞遠林，流水隔雲深。", "茅屋在何處，桃花無路尋。", "身黄松上鼠，頭白竹間禽。", "應有仙家住，避秦來至今。"]'),
('b78a1a85-b006-462c-bf9a-1a256ce7f117','浦口','宋無','宋','宋诗','song-poetry','','[]','浦口晚潮來，佳期那可待。',24,'全唐诗/poet.song.249000.json','["浦口晚潮來，佳期那可待。", "浪急行蘭舟，蘋花更難採。"]'),
('f8d65de8-27f7-451b-99e9-bf3b4fef5a7e','山中書事','宋無','宋','宋诗','song-poetry','','[]','學道志雲霄，自然塵念拋。',48,'全唐诗/poet.song.249000.json','["學道志雲霄，自然塵念拋。", "雨寬琴上線，風響樹間瓢。", "果熟供猿食，松高任鶴巢。", "看他陳處士，終被華山招。"]'),
('10225c91-c43a-4f71-a502-07d40aadc1f3','泰伯廟','宋無','宋','宋诗','song-poetry','','[]','古者吾夫子，曾稱三讓名。',24,'全唐诗/poet.song.249000.json','["古者吾夫子，曾稱三讓名。", "後來秦失鹿，劉項死相爭。"]'),
('0da5cf31-bd02-45df-8fcb-fee84cf0bb96','三高祠','宋無','宋','宋诗','song-poetry','','[]','退能合天道，隠亦是人豪。',24,'全唐诗/poet.song.249000.json','["退能合天道，隠亦是人豪。", "借問祠前水，如今幾個高。"]'),
('0c7b1bd6-c36c-4942-9d27-d41e99f0544f','金陵送倪水西之江陵','宋無','宋','宋诗','song-poetry','','[]','楚江江上暮雲東，萬里春波去意濃。',64,'全唐诗/poet.song.249000.json','["楚江江上暮雲東，萬里春波去意濃。", "桃葉歌殘秣陵酒，梨花夢斷景陽鐘。", "沅湘水落瓊瑶合，巴蜀山來錦繡重。", "回雁峰前見歸雁，相思何處再相逢。"]'),
('2a0aaaab-e802-4ada-9415-308fffeebcdc','戍婦言','宋無','宋','宋诗','song-poetry','','[]','姑嫜有妾奉，征戰盍郎行。',24,'全唐诗/poet.song.249000.json','["姑嫜有妾奉，征戰盍郎行。", "早取封侯去，封侯妾亦榮。"]'),
('df8d5de5-37c1-4398-b75b-718b3e1310aa','送葛鍊師遠遊','宋無','宋','宋诗','song-poetry','','[]','仙翁去醉碧桃春，鶴背風吹萬里身。',64,'全唐诗/poet.song.249000.json','["仙翁去醉碧桃春，鶴背風吹萬里身。", "洞裏棋高饒幾子，瓢中詩好寄何人。", "三峰紫翠浮芒屩，五岳烟霞染葛巾。", "歸日定知能縮地，莫教青竹化龍鱗。"]'),
('a9e62bea-a2f2-4f98-b3fd-9fbed1b82cd1','雲雨','宋無','宋','宋诗','song-poetry','','[]','雲雨朝朝暮暮新，襄王魂斷楚江春。',32,'全唐诗/poet.song.249000.json','["雲雨朝朝暮暮新，襄王魂斷楚江春。", "武丁曾有中宵夢，惟覓巖前版築人。"]'),
('e9217ce1-3223-46b6-8081-1079b3a33526','華蓋峰逸人','宋無','宋','宋诗','song-poetry','','[]','十步九巖壑，結茅無四鄰。',48,'全唐诗/poet.song.249000.json','["十步九巖壑，結茅無四鄰。", "山中春雨過，水上落花新。", "採藥逢毛女，焚香對羽人。", "時携一瓢酒，醉著去朝真。"]'),
('7dc10173-c36d-4cdd-8148-916c45aee9cd','岳陽夜泊圖','宋無','宋','宋诗','song-poetry','','[]','長憶巴陵山水秋，老來看畫却成愁。',32,'全唐诗/poet.song.249000.json','["長憶巴陵山水秋，老來看畫却成愁。", "箇中無聽猿啼處，若聽猿啼更淚流。"]'),
('b14aeaec-f618-49ab-8760-4be938444c57','江南思','宋無','宋','宋诗','song-poetry','','[]','暮雨娥皇廟，春風西子城。',24,'全唐诗/poet.song.249000.json','["暮雨娥皇廟，春風西子城。", "相思行不得，更聽鷓鴣聲。"]'),
('0f3558bf-12c3-4964-8846-4afacebb7c41','寄王子長','宋無','宋','宋诗','song-poetry','','[]','薄宦仍依楚，長聞傍酒壚。',48,'全唐诗/poet.song.249000.json','["薄宦仍依楚，長聞傍酒壚。", "客愁三月盡，春夢五更初。", "吟卷看花掩，行牀並竹鋪。", "江湖有佳句，知我每相於。"]'),
('69db5cad-1d09-47db-89d0-f1ff19a4e347','明皇並轡圖','宋無','宋','宋诗','song-poetry','','[]','三郎沉醉玉環隨，不上金輿索馬騎。',32,'全唐诗/poet.song.249000.json','["三郎沉醉玉環隨，不上金輿索馬騎。", "老大獨歸南內裏，風流無復並鞍時。"]'),
('62f15d43-e4a1-442b-9f2e-81e013a16ba9','贈皖山道士','宋無','宋','宋诗','song-poetry','','[]','世人曾不識，頭带樹皮冠。',48,'全唐诗/poet.song.249000.json','["世人曾不識，頭带樹皮冠。", "閒種藥來賣，醉將琴去彈。", "鶴銜仙果下，猿竊玉書看。", "莫服丹砂好，恐師生羽翰。"]'),
('c56e1210-e0dc-4b54-99b4-7d855ec64151','送謝士良之江東','宋無','宋','宋诗','song-poetry','','[]','謝安遊賞去，別酒惜臨分。',48,'全唐诗/poet.song.249000.json','["謝安遊賞去，別酒惜臨分。", "萬里甘爲客，三春苦送君。", "風帆攲逆水，江樹入空雲。", "若過青山下，須題李白墳。"]'),
('f613810e-d862-44b8-9c16-9eabf5023038','春閨','宋無','宋','宋诗','song-poetry','','[]','閒畫金釵記遠人，杜鵑啼血又殘春。',32,'全唐诗/poet.song.249000.json','["閒畫金釵記遠人，杜鵑啼血又殘春。", "琵琶絃上無多字，近日相思彈不真。"]'),
('fc5bf68b-c0e9-4e0c-8a65-4437ab441ab9','送僧還天目','宋無','宋','宋诗','song-poetry','','[]','瓶錫亂峰西，藤蘿晝掩扉。',48,'全唐诗/poet.song.249000.json','["瓶錫亂峰西，藤蘿晝掩扉。", "山藏翠微寺，僧向白雲歸。", "梵寂風沉磬，禪深雪到衣。", "想曾行道處，猿鳥共忘機。"]'),
('7cd18369-2746-46cf-9b53-d47cbdf3320b','破窗','宋無','宋','宋诗','song-poetry','','[]','蘚畫蟲絲紙半無，雨分錢點入櫺疏。',32,'全唐诗/poet.song.249000.json','["蘚畫蟲絲紙半無，雨分錢點入櫺疏。", "秋風吹得青燈滅，螢火飛來照讀書。"]'),
('d598a0f5-7e4e-4d27-859f-7ff14e73a009','寄郴陽廖有大','宋無','宋','宋诗','song-poetry','','[]','遠宦身安不，題書淚幾行。',48,'全唐诗/poet.song.249000.json','["遠宦身安不，題書淚幾行。", "千山萬水路，一日九迴腸。", "鶗鴂懷春語，蘼蕪入夢香。", "王孫歸未得，歸得早還鄉。"]'),
('385040fb-156b-487d-9ac0-3a07adc99751','沙門島','宋無','宋','宋诗','song-poetry','','[]','孤嶼壓滄海，風濤直下危。',48,'全唐诗/poet.song.249000.json','["孤嶼壓滄海，風濤直下危。", "蛟人依蜃市，魚女祭龍祠。", "月黑犀牛鬬，波紅螮蝀垂。", "登臨有奇觀，感慨但言詩。"]'),
('e1ee0013-ae76-4067-a351-b60217210c75','漢宮','宋無','宋','宋诗','song-poetry','','[]','武帝昇遐玉殿空，金人夜泣月明中。',32,'全唐诗/poet.song.249000.json','["武帝昇遐玉殿空，金人夜泣月明中。", "三千嬪御無行幸，猶費丹砂飼守宮。"]'),
('d171b5ca-0e2e-4077-ab55-a0b7f446dc32','沙上','宋無','宋','宋诗','song-poetry','','[]','四望無邊際，中浮一片沙。',48,'全唐诗/poet.song.249000.json','["四望無邊際，中浮一片沙。", "人家居釣艇，官賦種蘆花。", "渚綠紅蒿短，江清白鳥斜。", "乘流欲東去，萬里寄生涯。"]'),
('7d6fa5b2-a492-4888-bbe4-97ce6e0627f6','牆頭杏花','宋無','宋','宋诗','song-poetry','','[]','紅杏西鄰樹，過牆無數花。',24,'全唐诗/poet.song.249000.json','["紅杏西鄰樹，過牆無數花。", "相煩問春色，端的屬誰家。"]'),
('f569c1fd-7cf9-4850-bb06-5eaa1e9e55ed','金陵懷古','宋無','宋','宋诗','song-poetry','','[]','宮磚賣盡雨崩牆，苜蓿秋紅滿夕陽。',32,'全唐诗/poet.song.249000.json','["宮磚賣盡雨崩牆，苜蓿秋紅滿夕陽。", "玉樹後庭花不見，北人租地種茴香。"]'),
('bd1ee694-a59c-4e26-9067-e1d27e4671b0','墨梅寄因上人  其一','宋無','宋','宋诗','song-poetry','','[]','寒枝香在天外，疏花影流水中。',28,'全唐诗/poet.song.249000.json','["寒枝香在天外，疏花影流水中。", "梨雲夜深清夢，草玄筆底春風。"]'),
('658c0818-73fd-4667-a322-a1e457a8138a','墨梅寄因上人  其二','宋無','宋','宋诗','song-poetry','','[]','夢覺霜林墮月，眼明野水浮枝。',28,'全唐诗/poet.song.249000.json','["夢覺霜林墮月，眼明野水浮枝。", "橫玉不吹春去，斷縑閒寫相思。"]'),
('8bc6b9b7-8999-47ee-98e2-d195065c9c2a','長信秋','宋無','宋','宋诗','song-poetry','','[]','長信秋來月自圓，夜香猶拜玉階前。',32,'全唐诗/poet.song.249000.json','["長信秋來月自圓，夜香猶拜玉階前。", "妾今不願君王寵，惟願君王壽萬年。"]'),
('8281e9c5-0f50-43c2-ade1-4805d22e586f','句曲王尊師','宋無','宋','宋诗','song-poetry','','[]','不與俗人接，草堂雲自封。',48,'全唐诗/poet.song.249000.json','["不與俗人接，草堂雲自封。", "有時鍊丹去，無處覓行蹤。", "樹暖猴捫蝨，花香鹿養茸。", "曾期尸解後，終隠大茅峰。"]'),
('956f9b9a-fbc4-4a71-9c11-ad5a0199e153','萍','宋無','宋','宋诗','song-poetry','','[]','風波長不定，浪跡在天涯。',24,'全唐诗/poet.song.249000.json','["風波長不定，浪跡在天涯。", "莫怨身輕薄，前生是柳花。"]'),
('ce1d5c33-cbf2-4925-ac1b-89dce6f13ddb','山中僧','宋無','宋','宋诗','song-poetry','','[]','雪頂霜眉齒半稀，跏趺苔石看雲歸。',32,'全唐诗/poet.song.249000.json','["雪頂霜眉齒半稀，跏趺苔石看雲歸。", "山童掃葉鶴飛起，狼籍松花滿衲衣。"]'),
('d631408c-6b18-425c-9c95-a0fbdf63b035','唐人四馬卷  其一','宋無','宋','宋诗','song-poetry','','[]','金銜初脫齒新齊，蹄玉無聲赤汗微。',32,'全唐诗/poet.song.249000.json','["金銜初脫齒新齊，蹄玉無聲赤汗微。", "昨日杏園春宴罷，滿身紅雨带花歸。"]'),
('81186805-aba4-43a3-a7ac-807cb3b301a5','唐人四馬卷  其二','宋無','宋','宋诗','song-poetry','','[]','簇仗回來玉勒閒，黄門牽向落花間。',32,'全唐诗/poet.song.249000.json','["簇仗回來玉勒閒，黄門牽向落花間。", "君王不愛長楊獵，嘶入春風十二閑。"]'),
('26a99c1b-1d90-4c30-94b0-a8176e5988ae','唐人四馬卷  其三','宋無','宋','宋诗','song-poetry','','[]','霜蹄踏月早朝回，尾弄紅絲拂紫苔。',32,'全唐诗/poet.song.249000.json','["霜蹄踏月早朝回，尾弄紅絲拂紫苔。", "日暖龍池初洗罷，尚方聞進御鞍來。"]');
